window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q15"]=window.__LIBQ["tien-nghich"]["q15"]||{};window.__LIBQ["tien-nghich"]["q15"]["characters"]={"updatedAt":"2026-07-14","count":80,"chars":[{"id":"vuong-lam","name":"Vương Lâm","canhGioiCaoNhat":"Đạo Hư (bảy đại bổn nguyên)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1579","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp đầu lâu Đạo Cổ, đại chiến con trai Diệp Mịch","text":"Dung hợp thân thể với đầu lâu Đạo Cổ Diệp Mịch, hóa thành mắt trái bị mất khiến đầu lâu đầy đủ. Va chạm lần đầu bị thương nặng, mi tâm lưu vết thương, hai mắt chảy huyết lệ, thị lực mơ hồ nhuộm đỏ. Dùng Thanh Quang Thuẫn kích hoạt Mộng Hồi Viễn Cổ đã hòa Mộng đạo, kéo tinh không về viễn cổ nhưng bị thuật Tê Thiên xuyên phá. Thi triển Nhân Quả Ấn kéo khí tức đối thủ, rồi vỗ Sinh Tử Ấn nhưng không ngăn nổi cơn điên cuồng. Thân thể bị Tê Thiên xé rách từ mi tâm tới bụng, da thịt lộ xương cốt, xương bắt đầu vỡ vụn. Dù bị thương trầm trọng vẫn khát vọng giết đối thủ đoạt thuật Tê Thiên.","anchor":"da thịt đang bị xé ra lộ cả xương cốt"},{"importance":"normal","mucCt":"ky","chuong":"@c1580","tieuDe":"Dung hợp Mộng đạo — giết con trai Diệp Mịch","text":"Trong tình thế xương đầu nứt, lồng ngực rách, dung hợp Mộng đạo thuật với Mộng hồi viễn cổ của Thanh Quang Thuẫn, trở thành chúa tể giấc mộng, biến toàn bộ thiên địa thành đôi mắt khổng lồ nghiền nát con trai Diệp Mịch trong mộng. Mộng tỉnh, dùng huyết kiếm chém đôi đối phương đang mê mang, thu tám giọt máu tím vào mi tâm nhưng chưa dung hợp. Bị thương cực nặng do tổn thương trong mộng phản ánh lên thân thật, phun máu, vào Vô Danh Chuyển Luân trận khoanh chân chữa thương. Nén thương truyền tu vị vào đại trận, kích hoạt bánh xe khổng lồ nghiền nát mấy vạn tu sĩ giới ngoại, hấp thu nguyên thần. Rút cung Lý Quảng kéo căng dây cung uy hiếp Chưởng Tôn buộc rút lui. Chữa thương suốt chín tháng, hết một năm thì Tây Tử Phượng rời đi, bên cạnh chỉ còn nữ tử áo hồng.","anchor":"Mộng đạo thuật dung hợp với Mộng hồi viễn cổ. Mộng này là mộng của ta."},{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Chấn động bổn nguyên — Lam Mộng quy thuận","text":"Hồng Điệp tiết lộ sư tôn từng gặp đại nho họ Vương, người đặt tên cho nàng, khiến Vương Lâm chấn động mãnh liệt vì giấc mộng bổn nguyên tưởng tự tạo ra bằng thuật lừa gạt bản thân lại có dấu vết thật. Hắn rơi vào hoài nghi ranh giới thật–giả của bổn nguyên viên mãn. Kể cho Hồng Điệp về thân thế Thanh Thủy: toàn tộc bị diệt, thê tử chết, chỉ còn nữ nhi đã luân hồi với thai ký màu hồng trên vai trái không bao giờ tiêu tán. Nhập định tới tháng thứ sáu năm thứ ba mới tỉnh, trả lời Lam Mộng Đạo Tôn rằng mình đã có thê tử, gián tiếp từ chối hôn sự với Lý Thiến Mai. Lam Mộng tuyên bố không đánh hắn nữa, sẵn lòng liên thủ. Ba kẻ địch Diệu Âm, Cửu Thiên, Đại Hoang được Chưởng Tôn cứu khỏi cổ mộ lao tới tấn công, nhưng Lam Mộng chủ động chặn hộ.","anchor":"Tất cả mọi chuyện rõ ràng là giấc mộng do mình tạo ra, dùng thuật lừa gạt bản thân để tạo thành"},{"chuong":"@c1583","importance":"normal","tieuDe":"Hủy tranh tiếp nhận Lý Thiến Mai","text":"Vương Lâm ngồi trong Vô Danh Chuyển Luân trận dưỡng thương hai năm, hồi phục hơn phân nửa, tiếp tục dung hợp tám giọt máu cổ đạo và nghiên cứu thuật Tê Thiên. Chứng kiến Lam Mộng Đạo Tôn một mình đánh bại ba đại năng trong ba ngày. Tuyên bố cả đời chỉ có một thê tử, ban đầu từ chối đề nghị của Lam Mộng Đạo Tôn. Lý Thiến Mai xin lại bức tranh Tương Vong Vu Giang Hồ để đoạn tuyệt, nói rõ ân không phải tình. Vương Lâm nắm chặt bức tranh không buông, cuối cùng hủy bức tranh, tuyên bố từ nay Lý Thiến Mai là nữ nhân của hắn, đồng thời khẳng định Lý Mộ Uyển vẫn là thê tử, đợi nàng tỉnh dậy sẽ cùng thành thân.","anchor":"Từ nay về sau nàng là nữ nhân của Vương Lâm ta!"},{"importance":"major","mucCt":"ky","chuong":"@c1584","tieuDe":"Phân thân vào giới nội ngưng tụ tứ đại tiên giới","text":"Sau khi Lý Thiến Mai và Mộc Băng Mi lần lượt rời đi, Vương Lâm điểm vào mi tâm tách phân thân tu sĩ (Không Linh trung kỳ, không lực lượng thân thể cường hãn) ra khỏi bổn tôn (Cổ Thần/Cổ Yêu/Cổ Ma, truyền thừa đạo cổ). Bổn tôn ở lại giữ Vô Danh Chuyển Luân trận trong tháng cuối trước khi tứ đại chiến tướng ra khỏi viễn cổ tiên vực. Phân thân bước vào tinh không giới nội thực hiện kế hoạch ngưng tụ tứ đại tiên giới dung hợp thành một tân tiên giới, để tu sĩ giới nội có thể ngưng tụ hương hỏa lực và tu sĩ mới sinh có thể tu tiên rồi phi thăng. Phân thân đầu tiên tới Phong Tiên giới ở Vân Hải tinh vực, cảm ứng được Văn thú thất lạc trăm năm đang ở đó. Con Văn thú khổng lồ màu vàng thân trăm vạn trượng khi cảm nhận khí tức chủ nhân liền điên cuồng lao tới, Vương Lâm quay đầu lộ nụ cười vui vẻ. Đối với Mộc Băng Mi, hắn không còn hận nhưng cũng không có tình.","anchor":"bất ngờ từ trong cơ thể hắn huyễn hóa ra một Vương Lâm khác"},{"importance":"normal","mucCt":"ky","chuong":"@c1585","tieuDe":"Khám phá bí mật Phong Tiên giới","text":"Phân thân trong Phong Tiên giới hội ngộ Văn vương trăm trượng dẫn đàn trên vạn Văn thú, nhận ra Văn vương đã tiến hóa gần bước thứ ba chỉ còn kém một bước lột xác. Được Văn vương dẫn vào vùng sâu sương mù, phát hiện pho tượng hình người từng thấy năm xưa đã biến mất. Tìm thấy thi thể Văn thú ngàn trượng bước thứ ba bị giết bằng ba ngón tay xuyên thấu vào cổ, khí tức trên tam chỉ khiến hắn cảm thấy mơ hồ quen thuộc. Dùng ngọc giản bẻ gãy rồi gắn lại để thí nghiệm so sánh, kết luận cái khe khổng lồ đã bị xé mở một lần rồi sửa lại, sau đó bị xé mở lần thứ hai. Theo Văn vương vào bên trong khe, phát hiện không gian tràn ngập huỳnh quang chứa hàng trăm vạn trứng Văn thú các kích cỡ. Tản thần thức bao phủ toàn bộ không gian, phát hiện điều gì đó chấn động khiến hắn kinh ngạc lùi lại mấy bước ngẩng phắt đầu.","anchor":"hai mắt hắn lộ vẻ rung động, thân thể theo tiềm thức lui lại phía sau vài bước, ngẩng phắt đầu"},{"chuong":"@c1586","importance":"major","mucCt":"ky","tieuDe":"Kiếm xuyên phong ấn, phát hiện Tiên Cương","text":"Khám phá thông đạo bí ẩn trong động phủ, cuối thông đạo là cửa đá khổng lồ có lá phù phong ấn hai chiều. Lần đầu xuất nguyên thần dung hợp huyết kiếm tiếp cận nhưng bị lực bài xích đẩy lui. Lần hai bạo phát toàn bộ tu vi, triệu lục đại bổn nguyên — lôi, hỏa, sinh, tử, nhân quả, tam đại hư bổn nguyên, sát lục — ngưng tụ trong huyết kiếm, nguyên thần hóa kiếm xuyên qua phong ấn đâm sâu ba thước vào cửa đá. Cảm nhận được khí tức Tiên Cương đại lục bên kia — mũi kiếm lộ ra ba tấc trên Đông Đan chung của Quy Nhất tông, tỏa huyết quang kinh thiên. Sau đó bị đẩy lui, rút về an toàn, xác nhận bên ngoài cửa đá chính là Tiên Cương đại lục.","anchor":"Tiên Cương đại lục! Bên ngoài cánh cửa đá này không ngờ lại là Tiên Cương đại lục!"},{"importance":"normal","mucCt":"ky","chuong":"@c1587","tieuDe":"Ngưng tụ Phong Tiên giới, tiến về Thiểm Giới","text":"Nhận ra cánh cửa đá trong thông đạo không phải đại môn động phủ Thất Thải Tiên Tôn mà là thông đạo do tu sĩ từ Tiên Cương đại lục mở ra từ bên ngoài để xâm nhập. Liên kết manh mối từ Thiểm Lôi tộc, Côn Cực Tiên, thủ lĩnh giống Nạp Đa, suy ra nhóm tu sĩ thần bí chính là người từ tông phái khác trên Tiên Cương đại lục, có thể vẫn đang ở Ngũ Hành tinh. Thu toàn bộ hàng trăm vạn trứng Văn thú vào không gian trữ vật, phong ấn khe nứt thông đạo bằng cấm chế và cổ Tức Diệp. Dùng tu vi Không Linh trung kỳ bao trùm toàn bộ Phong Tiên giới, ép các mảnh đại lục vỡ vụn ngưng tụ thành một đại lục hoàn chỉnh, gió lốc sụp đổ. Dùng nguyên thần dung hợp mặt đất, điều khiển cả đại lục Phong Tiên giới bay ra tinh không Vân Hải tinh vực, hướng về Triệu Hà để tới Thiểm Giới — tiên giới duy nhất chưa từng đi qua.","anchor":"Phong Tiên giới này giống như một tấm gương đã bị nghiền nát đang từ từ hợp lại"},{"importance":"normal","mucCt":"ky","chuong":"@c1588","tieuDe":"Ngưng tụ Tân tiên giới và tuyên bố nghịch tiên","text":"Điều khiển Phong Tiên giới rời Vân Hải tinh vực tới Triệu Hà, vào Thiểm Giới khảo sát ba ngày rồi nhận định đã bị hủy diệt không thể cứu vãn, vung tay thu cả dải ngân hà Thiểm Giới vờn quanh đại lục Phong Tiên giới làm tầng bảo vệ. Đưa Phong Tiên giới tới La Thiên Tinh Vực khảo sát Lôi Tiên Giới, nhận định đã phế hoàn toàn không thể dùng. Khi rời đi, hạt châu Thiên Nghịch tự lóe sáng phát ra lực lượng kỳ dị giúp nhận biết Chiến lão quỷ đang ẩn thế nhìn mình, nhưng dấu diếm rời đi không vọng động. Tới Côn Hư Vũ giới, hoàn tất khảo sát tứ đại tiên giới. Tại giao điểm tứ đại tiên giới, ngưng tụ Tân tiên giới: lấy đại lục Phong Tiên giới làm căn cơ, dùng bụi bặm Vũ Giới bành trướng đại lục, triển khai Dịch Linh Ấn ngưng tụ, biến ngân hà Thiểm Giới thành tầng bảo vệ phân chia tiên phàm (dưới Hóa Thần không vào được), kích hoạt Vô Danh Chuyển Luân trận hấp thu khí tức Thái cổ Tinh Thần. Phân nguyên thần chỉ đạo mấy vạn tu sĩ do Thanh Lâm dẫn đầu tản ra tứ đại tinh vực rút tinh hồn từ các tu chân tinh, dung hợp vào tân tiên giới, thiết lập cơ chế phi thăng cho tu sĩ đột phá Hóa Thần. Tuyên bố từ bỏ danh xưng Phong Tôn, sắp đi nghịch tiên — thành thì tiên phá, bại thì tử vong. Gửi gắm Tư Đồ Nam nếu mình chết thì bố cáo thiên hạ, viết thành ngọc giản lưu khắp nơi. Bóng lưng cô độc bước đi, mấy vạn tu sĩ vái tiễn.","anchor":"Vương mỗ lần này ra đi sinh tử không rõ, danh xưng Phong Tôn này từ nay về sau ta không giữ nữa"},{"importance":"normal","mucCt":"ky","chuong":"@c1589","tieuDe":"Dung hợp phân thân, tiến vào Thái Cổ Tinh Thần","text":"Vào ba ngày cuối cùng của năm thứ ba, bổn tôn mở mắt bên ngoài Vô Danh Chuyển Luân trận, phân thân bạch y từ giới nội trở về dung hợp vào bổn tôn, phát ra tiếng ầm và ánh sáng nhu hòa. Vương Lâm cảm ngộ sâu sắc rằng cường giả chân chính là người hiểu được sự gánh vác, liên hệ hình ảnh phụ thân phàm nhân che chở gió mưa với con đường tu đạo hơn hai ngàn năm của mình. Quyết định hủy diệt viễn cổ tiên vực giới ngoại và tạo hỗn loạn trước đại chiến, hắn không ẩn giấu khí tức trực tiếp tiến vào Thái Cổ Tinh Thần, thần thức khuếch tán khiến mọi cường giả bừng tỉnh. Dừng lại gần trung tâm Thái Cổ Tinh Thần khoanh chân thổ nạp, vận chuyển giọt máu tiên nhân bất diệt thể trên mi tâm đưa khí tức lên đỉnh phong. Khi còn ba-bốn canh giờ, phát hiện mấy trăm tới hơn ngàn tu sĩ mặt vẽ xanh đỏ gào thét khẩu hiệu Tiên Long Hiển Đạo lao tới.","anchor":"chỉ có cường giả hiểu được chuyện cần gánh vác mới là cường giả chân chính"},{"importance":"normal","mucCt":"ky","chuong":"@c1590","tieuDe":"Chặn đường viêm long","text":"Phát hiện viêm long quen thuộc từ trăm năm trước trong thế giới động phủ, chủ động hiện thân chặn đường nó. Viêm long ngốc nghếch phun hỏa cầu tấn công nhưng Vương Lâm phá tan dễ dàng, thu toàn bộ ngọn lửa vào tay trái, thể hiện thực lực áp đảo hoàn toàn.","anchor":"Vương Lâm từ bên trong ngọn lửa đi ra, bước từng bước một"},{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Thu phục Tiểu Hồng, lộ bí mật Liên Đạo Phi","text":"Dùng ấn quyết Chu Tước đời thứ hai kích hoạt ấn ký trên mi tâm viêm long, khiến nó đau đớn khuất phục. Phát hiện trong thân viêm long ẩn chứa huyết mạch tiên nhân nhờ giọt máu tiên nhân bất diệt thể trên mi tâm. Phối hợp viêm long diễn kịch trước hơn ngàn môn đồ Tiên Long Tông, nhận danh nghĩa phó tông chủ. Viêm long khai nhận tên Tiểu Hồng, xác nhận chủ nhân cũ chính là Liên Đạo Phi — người điên năm xưa — tâm thần chấn động mạnh khi nhớ lại lời người điên nhiều lần gọi Tiểu Hồng. Thu viêm long vào khe trữ vật, bình ổn tâm cảnh trong ba canh giờ cuối trước khi thời hạn ba năm trong Thái Cổ Tinh Thần kết thúc.","anchor":"Tiểu Hồng! Đôi mắt Vương Lâm bừng sáng. Hắn nhìn chằm chằm vào viêm long, trong đầu ầm vang."},{"chuong":"@c1592","importance":"major","tieuDe":"Viễn cổ tiên vực mở ra đúng ước định","text":"Đúng một trăm năm kể từ khi giới nội và giới ngoại khai chiến, cũng là thời hạn ba năm Vương Lâm chờ đợi. Tứ đại chiến tướng viễn cổ tiên vực giới nội đã ước định với hắn triển khai chiến đấu vào ngày này. Thần thức ngưng tụ bên người không ai phát hiện, kịch biến sắp phát sinh. Tứ đại tinh vực tinh không vỡ vụn, khe nứt khổng lồ ngưng tụ thành hình chữ thập tại tân tiên giới. Hơn mười sáu tiên nhân viễn cổ tỏa kim quang bước ra, khí tức bước thứ ba nhưng bất đồng với tu sĩ trong động phủ, lao thẳng tới tân tiên giới thôn phệ hương hỏa.","anchor":"Hắn đã đợi ngày này ba năm rồi","mucCt":"ky"},{"importance":"normal","mucCt":"ky","chuong":"@c1593","tieuDe":"Thân ảnh đuổi tiên nhân, kim quang huyết mạch trấn áp","text":"Bản thể ngồi ở giới ngoại Thái Cổ Tinh Thần, cảm nhận tiên nhân xâm nhập tiên giới. Qua ngọc giản giao Tư Đồ Nam ba năm trước, một tia thần thức huyễn hóa thành thân ảnh, quát hỏi Chu Tước, Huyền Vũ, Thanh Long, Bạch Hổ về ước định, phát sát lục kinh thiên đuổi hơn mười tiên nhân khỏi tiên giới. Nhận ra viễn cổ tiên vực giới ngoại cũng mở, lập tức vọt tới lỗ hổng tinh không, ý đồ lấy lực lượng hai cung hủy diệt viễn cổ tiên vực giới ngoại. Đối mặt đệ tử Thất Đạo Tông bay ra, một tiên nhân lao tới định hút thành hương hỏa. Mở bừng mắt phát kim quang từ giọt máu tiên nhân bất diệt thể, huyết mạch tinh thuần cực điểm, trấn áp tiên nhân khiến hắn hãi hùng lui lại hỏi “Ngươi là ai!”","anchor":"Kim quang này là giọt máu do tiên nhân bất diệt thể hóa thành được hắn ngưng tụ ra"},{"importance":"normal","mucCt":"ky","chuong":"@c1594","tieuDe":"Liên bắn hai mũi tên cung Lý Quảng, phong ấn viễn cổ tiên vực","text":"Lần đầu tiên liên tục bắn hai mũi tên kể từ khi có cung Lý Quảng. Mũi thứ nhất bành trướng mấy ngàn trượng, xuyên qua hình thần câu diệt, giết sạch hơn mười tiên nhân Thất Đạo Tông vừa ra khỏi viễn cổ tiên vực. Mũi thứ hai mang lực hút khổng lồ khiến lỗ hổng thông đạo co rút sụp đổ hoàn toàn, phong ấn viễn cổ tiên vực giới ngoại, ngăn chặn hai luồng khí tức mạnh ngang Chưởng Tôn từ bên trong lao ra. Kim quang huyết mạch tiên nhân trong hai mắt (đặc biệt mắt trái) tiêu tán hoàn toàn sau khi bắn, trán toát mồ hôi, tiêu hao cực lớn. Chưởng Tôn phong ấn toàn bộ Thái Cổ Tinh Thần nhốt Vương Lâm, cùng Thất phi, Diệu Âm đạo tôn, Cửu Thiên ma tôn đồng loạt lao tới giết.","anchor":"Đây là lần đầu tiên sau khi hắn có được cây cung của Lý Quảng liên tục bắn hai mũi tên"},{"chuong":"@c1595","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Tộc Bất Diệt Chỉ nghênh chiến Chưởng Tôn","text":"Bị Chưởng Tôn tấn công ngay sau khi khai cung. Bình tĩnh nghênh chiến: kích hoạt Cổ Thần tinh điểm trên mi tâm và tinh điểm Cổ Yêu trong mắt trái, ngưng tụ toàn bộ lực lượng Đạo cổ lên ngón trỏ, lần đầu thi triển thần thông tự nghĩ ra — Tộc Bất Diệt Chỉ (lấy cảm hứng từ tiên nhân bất diệt thể). Đồng thời triển khai Thanh Quang Thuẫn, Quang Ảnh Thuẫn và Ngũ Thải hồ điệp. Nói câu «Còn chưa tới thời cơ» cho thấy đã có kế hoạch. Ngón trỏ đối đầu chưởng ấn trăm trượng huyền kiếp, bị hủy diệt và tái tạo hơn ngàn lần, thân thể nứt vỡ khắp nơi, phun máu. Quang Ảnh Thuẫn sụp đổ, Thanh Quang Thuẫn bị cuốn về thân, Ngũ Thải hồ điệp tiêu tan — ba lớp phòng ngự đều vỡ, chịu tổn thương nghiêm trọng trước khoảng cách tu vi quá lớn.","anchor":"tay phải Vương Lâm bỗng nhiên giơ lên, Cổ Thần tinh điểm trên mi tâm hắn tinh điểm cổ Yêu trong mắt trái hắn đều lóe sáng"},{"importance":"normal","mucCt":"ky","chuong":"@c1596","tieuDe":"Bắn tên thứ ba, đại phá bốn cường giả","text":"Bị Chưởng Tôn tung chưởng ấn huyền kiếp đánh trọng thương liên tiếp, lần lượt dùng Dịch Linh Ấn, trường thương bảy màu, sáu thanh kiếm bổn nguyên đối kháng đều không đủ sức. Lần đầu tiên thi triển thuật Tê Thiên (đoạt từ con trai Diệp Mịch), kết hợp hư ảnh thân thể Đạo Cổ (do tám giọt huyết quang chưa luyện hóa tự hiện ra — lần đầu hiện cả thân thể mơ hồ chứ không chỉ đầu lâu) xé tan chưởng ấn, bản thân bị trọng thương nặng. Hé lộ kế hoạch: hủy viễn cổ tiên vực giới ngoại, làm loạn động phủ, khiến các thế lực mất cân bằng — tất cả chỉ là bước đầu tiên, đã tính trước việc bị vây trong Thái Cổ Tinh Thần. Cố ý chờ bốn cường giả (Chưởng Tôn, Thất Phi, Diệu Âm Đạo Tôn, Cửu Thiên Ma Tôn) tụ tập rồi rút cung Lý Quảng bắn mũi tên thứ ba, hoàn toàn vượt ngoài dự liệu Chưởng Tôn. Nhắm mắt giấu ánh sáng vàng khi bắn. Mũi tên xuyên phá mọi thần thông Chưởng Tôn, xuyên thân khiến hắn tan xác bỏ trốn, đánh nổ tung Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn rồi bắt gọn nguyên thần cả hai, trọng thương Thất Phi.","anchor":"Hàn mang trong ánh mắt loé lên, trực tiếp nhắm hai mắt lại, không cho người khác nhìn thấy ánh sáng màu vàng trong mắt mình"},{"chuong":"@c1597","importance":"major","mucCt":"ky","tieuDe":"Thoát tinh không, gặp Phàn San Lộ nhận đề nghị","text":"Đạo nhân bảy màu hiện thân, Vương Lâm không chút do dự bóp nát ngọc giản do Phàn San Lộ đưa từ trước tạo hắc động, được ngọc thủ đệ nhất phi thi triển Thái Ngọc Thất Thủ Ấn chặn chỉ phong bảy màu, rồi bị hắc động hút vào thoát khỏi tinh không Thái Cổ Tinh Thần. Toàn bộ kế hoạch đường lui đã chuẩn bị từ một năm trước khi thôn nạp trong Vô Danh Chuyển Luân trận, lợi dụng ngọc giản liên lạc nữ tử đạt thành hiệp ước. Qua hắc động tới khe sâu Yêu Tông cũ (Vân Hải tinh vực), gặp Phàn San Lộ — đệ nhất phi, muội muội đạo lữ Thất Thải Thiên Tôn, đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Nghe nàng đề nghị: giết Thất Thải Thiên Tôn đoạt sơn môn Thất Đạo Tông, rồi nhập Đại Hồn Môn qua Tiên Cương đại lục. Cuối cùng hỏi về số phận tu sĩ khác trong động phủ thì cả hai cùng biến sắc cảm ứng điều bất thường phía sau.","anchor":"Cho nên một năm trước khi hắn thôn nạp trong Vô Danh Chuyển Luân trận đã lợi dụng ngọc giản do nữ tử này đưa từ trước mà truyền thần niệm"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Phản kích đạo nhân bảy màu, trốn vào thuyền tím","text":"Bị đạo nhân bảy màu truy đuổi trong tinh không Vân Hải tinh vực, tiếng nói của hắn đánh vào tâm thần khiến Vương Lâm phun máu. Nhân lúc Phàn San Lộ ngăn chín hỏa điểu, lấy cung Lý Quảng bắn một mũi tên phản kích nhờ còn một giọt huyết mạch tiên nhân mà Chưởng Tôn không biết. Sau khi Phàn San Lộ kiệt sức phá vây tinh thể, ôm nàng na di gần hai ngàn dặm vào thuyền lớn màu tím (động phủ của nàng). Cuối cùng đặt câu hỏi về danh tính thật của đạo nhân bảy màu.","anchor":"Chuyện này đã tồn tại trong đáy lòng hắn rất lâu rồi!"},{"importance":"normal","mucCt":"ky","chuong":"@c1599","tieuDe":"Khảo sát chiến thuyền, phát hiện cơ hội cấm chế bổn nguyên","text":"Tản thần thức bao phủ toàn bộ chiến thuyền, nhận ra cả thuyền do cấm chế tạo thành như một trận pháp khổng lồ, nhận diện tứ đại cấm chế (Tuế Nguyệt, Sinh Tử, Phá Diệt) cùng nhiều cấm chế chưa từng thấy, nhận thấy nếu nắm giữ toàn bộ có khả năng đạt thành tựu cấm chế bổn nguyên. Bị mặt quỷ trên buồm phát tiếng gào thét xuyên tâm thần phải lùi lại. Nhận định cấm chế chỉ mở chưa tới hai phần, không đủ chặn đạo nhân bảy màu, quyết không giao cung Lý Quảng vì cần nó để đấu bậc toàn năng Không Huyền. Nhận ra nữ tử trên thuyền không phải Phàn San Lộ mà là Phàn San Mộng. Nghe Phàn San Mộng kể quá khứ nhưng chỉ tin một phần, phát hiện lời nàng có dấu vết.","anchor":"Lời nói của nữ tử này nhìn qua thì đều là những lời tâm huyết nhưng trên thực tế lại có chút dấu vết"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Bí mật ba hồn bảy phách — suy luận chấn động","text":"Nghe nữ tử áo trắng tiết lộ bí mật ba hồn bảy phách của Thất Thải Thiên Tôn: hồn thứ nhất nắm thần thông chính là đạo nhân bảy màu, hồn thứ hai chứa ý cảnh và bổn nguyên lực, hồn thứ ba nắm toàn bộ trí nhớ và bí mật triệu hoán thiên đạo. Chấn động suy luận ra Chiến lão quỷ rất có thể chính là hồn thứ hai, giải thích vì sao Chưởng Tôn e sợ khi gặp lại Chiến lão quỷ. Nhận ra Thanh Thủy sư huynh chính là một trong thất phách, giải thích cuộc đời thê thảm và thực lực dị thường khi vừa vào bước thứ ba. Tự hỏi bản thân có phải là một trong thất phách hay không. Nghe nữ tử đề xuất hai phương pháp giết Thất Thải Thiên Tôn, trong đó phương pháp hai là dạy Vương Lâm thần thông thôn phệ hồn thứ ba rồi nuốt nốt hai hồn và thất phách để trở thành Thất Thải Thiên Tôn mới. Liên tưởng tới chuyện thánh tổ phù văn tộc bị Thanh Lâm trấn áp ở vùng đất Yêu Linh, cảnh giác trước lời nữ tử. Khi nữ tử đề nghị thệ huyết, nhận ra tất cả lời nàng chỉ là đánh lạc hướng có thâm ý riêng, thầm cười lạnh, chuyển hướng hỏi về tế đàn năm xưa.","anchor":"Tất cả những lời đối phương nói ra đều chỉ là đánh lạc hướng, hiển nhiên chỗ này có thâm ý riêng"},{"chuong":"@c1601","importance":"normal","mucCt":"ky","tieuDe":"Phản khách vi chủ — nghiên cứu cấm chế thuyền","text":"Nhìn thấu bố cục của hai tỷ muội Phàn San Mộng: cố tình trì hoãn để đạo nhân bảy màu đuổi tới, dụ hắn lên thuyền tạo thế cấp bách ép trao huyết thệ. Từ chối đề xuất phá tế đàn trong ba ngày, chọn nghiên cứu cấm chế chiếc thuyền nhằm phản khách vi chủ. Kích hoạt lực lượng Đạo cổ, dung hợp tinh điểm Cổ Thần mi tâm và sáu tinh điểm Cổ Yêu mắt trái thành hư ảnh Đạo cổ mấy chục trượng bảo vệ toàn thân. Phóng ra gần trăm vạn cấm chế hợp nhất thành một chưởng phá vỡ tầng phòng hộ cấm chế bên ngoài boong tàu. Phát hiện boong thuyền thực chất do cấm chế ngưng tụ mà thành, bắt đầu phân tích ký hiệu cấm chế, nhận định thời gian ba ngày hơi gấp. Nhìn thấu mưu kế của hai chị em Phàn San Mộng cố ý dùng áp lực đạo nhân bảy màu bên ngoài để ép hắn trao huyết thệ. Từ chối đề nghị đến tế đàn tầng cuối thuyền, quyết định nghiên cứu cấm chế trên thuyền để phản khách vi chủ. Dung hợp lực lượng tam tộc cổ (tinh điểm Cổ Thần mi tâm và sáu tinh điểm Cổ Yêu mắt trái) hóa hư ảnh Đạo cổ bảo vệ toàn thân. Triển khai gần trăm vạn cấm chế trong chớp mắt, ấn một chưởng phá vỡ tầng phòng hộ cấm chế bên ngoài boong thuyền, lộ ra bản chất boong tàu là cấm chế ngưng tụ mà thành. Bắt đầu phân tích từng ký hiệu cấm chế nhưng nhận thấy ba ngày khá gấp.","anchor":"Nếu hắn thật sự có thể nghiên cứu được chiếc thuyền này, nắm được cách điều khiển như vậy chẳng những có thể giải được nguy cơ bên ngoài từ đạo nhân bảy màu mà hoàn toàn có thể phản khách vi chủ"},{"importance":"major","mucCt":"ky","chuong":"@c1602","tieuDe":"Lĩnh ngộ Cổ Hồn cấm, đoạt quyền thuyền","text":"Đối mắt với mặt quỷ trên cánh buồm nửa ngày mới trấn tĩnh. Dành năm canh giờ nghiên cứu thấu đáo một Cổ Hồn cấm trên boong thuyền, từ đó hoàn toàn lĩnh ngộ loại cấm chế thứ tư trong tứ đại cấm. Phá giải đồng loạt hàng vạn cấm chế trên boong tàu (tầng một) bằng bốn loại tứ đại cấm, biến tất cả thành cấm chế do mình điều khiển. Tiến xuống tầng thứ hai, dùng bảy canh giờ phá xong, đoạt thêm quyền kiểm soát thuyền. Tiết lộ thuyền có chín tầng cấm chế, boong tàu chỉ là tầng thứ nhất. Phàn San Mộng mất phần lớn quyền kiểm soát, giờ chỉ còn hơn Vương Lâm một chút. Tĩnh tâm nghiên cứu cấm chế trên boong thuyền cổ của Phàn San Mộng, đối mặt với mặt quỷ yêu dị trên cánh buồm nửa ngày mới bình tĩnh lại. Dành năm canh giờ nghiên cứu hoàn toàn một Cổ Hồn cấm đầy đủ trên boong thuyền, từ đó lĩnh ngộ toàn bộ nguyên lý loại cấm chế thứ tư trong tứ đại cấm — trước đó chỉ biết phiên bản có khuyết điểm. Sau khi lĩnh ngộ, phá hủy và thay thế toàn bộ mấy ngàn vạn cấm chế trên boong tàu (tầng một) trong thời gian cực ngắn, đoạt quyền điều khiển tầng thứ nhất. Ghi nhớ một số cấm chế kỳ dị chưa từng thấy ngoài tứ đại cấm để nghiên cứu sau. Tiến xuống tầng thứ hai, dùng bảy canh giờ phá xong, đoạt thêm quyền kiểm soát thuyền. Tiết lộ thuyền có tổng cộng chín tầng cấm chế. Lúc này quyền kiểm soát của Phàn San Mộng chỉ còn nhiều hơn hắn một chút.","anchor":"với khả năng minh ngộ của hắn, dùng năm canh giờ là đủ để hiểu hết cấm chế này"},{"chuong":"@c1603","importance":"major","mucCt":"ky","tieuDe":"Vạch trần Phàn San Lộ giả dạng, tứ đại cấm chế viên mãn","text":"Khi Phàn San Mộng mở phòng hộ cho đạo nhân bảy màu lên thuyền gây sức ép, Vương Lâm chủ động hủy cấm chế tầng một cho đối phương tiến vào tầng hai, dùng ngược lại làm đòn bẩy uy hiếp. Ép Phàn San Mộng trì hoãn đạo nhân bảy màu, tranh thủ ba canh giờ nghiên cứu cấm chế tầng ba — hơn phân nửa chưa từng gặp, khiến trình độ tăng vọt. Tứ đại cấm chế đạt viên mãn, chỉ thiếu dung hợp làm một sinh bổn nguyên. Sau hai canh giờ tầng hai sụp đổ, hắn kịp biến cấm chế tầng ba thành lưới chắn, cùng Phàn San Mộng tiến vào tầng bốn. Tại đây vạch trần nữ tử đồng hành thực ra là Phàn San Lộ giả dạng từ đầu bằng cách phun máu biến hóa thần sắc khí tức. Tuyên bố toàn bộ tầng hai đến tầng bốn và đạo nhân bảy màu trên thuyền đều là huyễn giới do Phàn San Lộ tạo ra. Chủ động đánh sập tầng ba để kiểm chứng.","anchor":"tứ đại cấm chế của Vương Lâm đã đạt tới viên mãn chỉ thiếu việc dung hợp làm một, sinh ra bổn nguyên"},{"chuong":"@c1604","importance":"normal","mucCt":"ky","tieuDe":"Phá Đại Hồn chân ảo thuật, chiếm buồm mặt quỷ","text":"Bị cuốn vào ảo thuật huyễn cảnh song trọng của Phàn San Mộng thi triển từ xa mà không hay biết, toàn bộ cảnh trên thuyền đều là huyễn giới. Trong ảo cảnh bình tĩnh đối mặt vầng mặt trời của đạo nhân bảy màu giả, nhận ra tất cả đều là giả rồi vung tay tiêu tán mọi huyễn tượng, thức tỉnh trên boong tàu tầng nhất. Phân tích mưu kế tầng tầng lớp lớp của hai chị em Phàn San cho Phàn San Lộ nghe. Suy luận Phàn San Mộng chưa từng bị Thất Thải Tiên Tôn giết chết, rất có thể dùng ảo thuật lừa gạt hắn, thậm chí mối quan hệ đạo lữ năm đó cũng chưa chắc thật. Đánh giá Phàn San Mộng là người thứ hai cả đời khiến hắn kiêng kỵ trong lòng. Hung hăng giật cánh buồm có khuôn mặt quỷ trên thuyền, tuyên bố chiếm bảo vật này, khiến Phàn San Mộng ở Tiên Cương đại lục phun máu kinh hãi.","anchor":"cả đời gặp vô số người, chỉ có một người là ta cảm thấy thần bí khó lường, trong lòng kiêng kỵ. Lúc này lại có thêm một người đó là tỷ tỷ của ngươi"},{"chuong":"@c1605","importance":"major","mucCt":"ky","tieuDe":"Thu buồm mặt quỷ, hứa đưa Phàn San Lộ về nhà, thử xâm nhập ảo giác đạo nhân bảy màu","text":"Thu tấm buồm mặt quỷ (pháp bảo Đại Hồn Môn, chủ hồn trên thuyền) cùng chiếc thuyền làm bồi thường cho việc bị lừa, bắt đầu luyện hóa trong không gian trữ vật để nắm cấm chế điều khiển thuyền. Nhận ngọc giản chứa bản đồ dẫn tới tế đàn và thuật thôn hồn người thứ ba từ Phàn San Lộ. Nhận thệ huyết của nàng (máu đỏ chuyển vàng) dung nhập vào cơ thể, hứa mang nàng về Tiên Cương đại lục — lời hứa đầu tiên sau khi đạt tu vi bước thứ ba. Tự đánh giá tu vi không bằng bậc toàn năng Không Huyền, cần tới tế đàn tìm cơ duyên và lợi dụng đại chiến viễn cổ tiên vực sắp tới. Phát hiện đạo nhân bảy màu đang chìm đắm trong ảo giác trên thi hài mãnh thú, xung quanh có cấm chế hủy diệt vô thanh trong phạm vi trăm trượng. Quyết định liều lĩnh tiến vào, thi triển Mộng Đạo thuật cố xâm nhập ảo giác đạo nhân bảy màu nhưng thất bại, khóe miệng tràn máu, không cam lòng.","anchor":"Vương Lâm nhíu mày, thần sắc lộ vẻ không cam lòng"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Thâm nhập ký ức Thất Thải Tiên Tôn","text":"Cắn lưỡi phun 99 giọt máu tươi chứa tu vi toàn thân, dung hợp Đạo Cổ bất diệt vào một giọt kèm tia nguyên thần để thâm nhập vùng uy áp kinh khiếp của đạo nhân bảy màu. 98 giọt hình thành quầng sáng bảo vệ bị tiêu tán, giọt Đạo Cổ bị hủy diệt–khôi phục vô số lần, cuối cùng chỉ còn tia máu kịp rơi vào mi tâm đạo nhân rồi tan biến, nhưng nguyên thần kịp chạm thân thể đối phương. Thi triển Mộng Đạo, tâm thần sụp đổ, bị cuốn vào huyễn cảnh bảy màu, phát hiện đạo nhân ngồi thẫn thờ trên núi nhắc tên Phàn San Mộng, suy đoán đây là huyễn trong huyễn. Lấy buồm mặt quỷ tung phủ thân, nguyên thần phá hư vô bay tới đạo nhân, mặt quỷ hóa khuôn mặt Vương Lâm rơi vào mắt đạo nhân như hố đen, bị hút vào tầng ký ức sâu. Chứng kiến toàn bộ đại chiến năm xưa giữa Thất Thải Tiên Tôn và liên minh Liên Đạo Phi, Phàn San Mộng, Phàn San Lộ. Thấy Tiên Tôn bị phản bội, triệu Thiên Đạo đồng quy vu tận, thân thể vỡ thành ba phần: đạo nhân bảy màu, ý cảnh, trí nhớ hóa cầu vồng. Hiểu ra nguyên nhân đạo nhân bảy màu cam tâm chìm trong ảo giác — hắn đang cố lấy lại phần hồn thứ ba chứa toàn bộ trí nhớ.","anchor":"Hắn đã hiểu rồi, đã hiểu tại sao đạo nhân bảy màu lại cam tâm chìm đắm trong ảo giác này mà không muốn thức tỉnh!"},{"importance":"normal","mucCt":"ky","chuong":"@c1607","tieuDe":"Rống Đạo cổ đánh thức đạo nhân bảy màu","text":"Nhận ra đạo nhân bảy màu lợi dụng ảo giác Phàn San Mộng sửa thành cảnh quay ngược thời gian để truy tìm hồn thứ ba — nếu tìm được thì Vương Lâm chắc chắn chết. Ba lần phun nguyên thần khí (quý hơn tinh huyết) tăng tốc gấp trăm lần đuổi kịp đạo nhân bảy màu trong huyễn cảnh tầng hai, nguyên thần đau đớn như bị thiêu đốt xé rách. Tận mắt thấy hồn thứ ba bay vào giới nội rồi xuyên Vân Hải tinh vực hướng Triệu Hà. Nhận định tu vi không đủ ngăn đối phương trong tầng hai, dùng tấm buồm mặt quỷ thoát về huyễn cảnh tầng một. Bị quang nhiệt chín hỏa điểu chặn không tiếp cận được thân thể thật đạo nhân bảy màu, tóc bốc cháy tiêu tán. Nghĩ ra kế dùng lục đại bổn nguyên ngưng tụ thành chiếc loa phóng đại âm thanh, kết hợp Đạo cổ lực (dung hợp tam tộc cổ) rống một tiếng kinh thiên — thần thông học từ trận đẩy lui Chưởng Tôn ở cổ mộ — khiến thiên không sụp đổ, đại địa nứt vỡ, phong vân biến sắc.","anchor":"Một tiếng rống này là tiếng rống của Cổ Thần, là tiếng rống của Đạo cổ, cũng là thần thông khi ở vùng đất cổ mộ Vương Lâm đẩy lui Chưởng Tôn mà học được"},{"importance":"normal","mucCt":"ky","chuong":"@c1608","tieuDe":"Phá huyễn cảnh đạo nhân bảy màu, bỏ trốn hướng tế đàn","text":"Dùng lục đại bổn nguyên biến thành loa khuếch đại tiếng rống, xuyên qua chín mặt trời bảo vệ, phá tan huyễn cảnh tầng hai của đạo nhân bảy màu, cắt đứt việc truy tìm hồn thứ ba. Bị phản kích từ tiếng gào phẫn nộ của đạo nhân bảy màu, lục đại bổn nguyên sụp đổ, phun máu nhiều lần, gần xương tan thịt nát. Nhờ Đạo cổ bất diệt nhanh chóng khôi phục, vung tấm buồm mặt quỷ che thân rồi dùng huyết độn điên cuồng bỏ trốn. Xác định tế đàn là sinh cơ duy nhất sau khi dung nhập hồn phách Thiên Vận Tử bói toán.","anchor":"Phá hoại kế hoạch của đối phương là việc hắn phải làm!"},{"importance":"normal","mucCt":"ky","chuong":"@c1609","tieuDe":"Dung hợp cánh tay Đạo Cổ Diệp Mịch trên tế đàn","text":"Bị đạo nhân bảy màu cùng chín hỏa điểu hóa chín mặt trời truy kích, toàn thân như bị thiêu đốt, nhiều lần phun máu dùng huyết độn chạy trốn trong tinh không. Dù nắm hỏa bổn nguyên nhưng không chống nổi sức nóng thần thông đạo nhân bảy màu. Lao tới tế đàn trong khe Vân Hải tinh vực, nhận ra cánh tay trên tế đàn thuộc Đạo Cổ Diệp Mịch nhờ khí tức Đạo Cổ, coi đó là sinh cơ. Nhờ truyền thừa chính tông Đạo Cổ, đặt tay lên dung hợp, cánh tay lập tức phát ra ánh sáng vạn trượng bao phủ toàn thân.","anchor":"Hắn có truyền thừa chính tông của Đạo cổ, lúc này trong tích tắc khi đặt tay lên cánh tay, cánh tay này lập tức phát ra ánh sáng vạn trượng"},{"chuong":"@c1610","importance":"normal","mucCt":"ky","tieuDe":"Đột phá Bát Tinh Đạo Cổ tam tộc cổ","text":"Chứng kiến Tham Lang phóng khí tức đại thiên tôn bức lui đạo nhân bảy màu, nhìn thấy hai tiểu cô nương (đại thiên tôn chuyển thế Tử Dương tông) trong tự thú giới phong bế cái khe và giấu Tham Lang. Nhận ra hai cô bé chính là đại thiên tôn truyền thuyết của Tiên Cương đại lục, lập chí trở thành đại thiên tôn. Sau đó chính thức hấp thu dung hợp tám giọt máu Đạo cổ của Diệp Mịch trên tế đàn: bóp nát từng giọt thành huyết vụ hút vào thất khiếu và lỗ chân lông, giọt đầu mất bảy ngày, rồi bóp hai giọt cùng lúc, cuối cùng bóp nát cả năm giọt còn lại. Trải qua đau đớn bành trướng thân thể hơn mười ngày, thành công đột phá tam tộc cổ lên Bát Tinh đồng thời: yêu tinh thứ tám xuất hiện ở mắt trái, ma tinh thứ tám hiện ra ở mắt phải, tinh điểm Cổ Thần thứ tám ngưng thật ở mi tâm. Hư ảnh Đạo Cổ hiện ra sau lưng. Cảm nhận Tam tổn thất kiếp sắp tới.","anchor":"tinh điểm Cổ Thần thứ tám tỏa ra ánh sáng vô tận, từ trong mơ hồ trở nên ngưng thật"},{"chuong":"@c1611","importance":"major","mucCt":"ky","tieuDe":"Vượt nhị tổn tứ kiếp Cổ Yêu và Cổ Ma, tam tộc bát tinh cân bằng, bắt đầu Cổ Mạch Thương Khung Huyết","text":"Tam tổn thất kiếp của Cổ Thần, Cổ Yêu, Cổ Ma đồng loạt giáng xuống sau khi đạt bát tinh. Vượt nhị tổn tứ kiếp Cổ Yêu: tám yêu tinh mắt trái dung hòa, yêu khí tràn ngập, ngưng tụ yêu giáp tím đỏ, phía sau hiện hư ảnh Cổ Yêu một sừng, mất một năm mười ngày vượt qua. Vượt nhị tổn tứ kiếp Cổ Ma: tám ma tinh mắt phải hiện, ma khí thay thế yêu khí, xuất hiện ma giáp đen, bảy ngày vượt đệ nhất tổn và mười ba ngày trấn áp đệ nhị tổn, thân thể Cổ Ma gần đạt đại thành. Tam tộc cổ đều đạt bát tinh cân bằng, 24 tinh điểm đồng chuyển, Đạo cổ hoàn chỉnh. Tự đánh giá đủ sức thắng Không Huyền sơ kỳ, nếu thêm đạo bổn nguyên thứ bảy thì không sợ Không Huyền trung kỳ. Bắt đầu đệ tam tổn, kiếp thứ nhất Cổ Mạch Thương Khung Huyết — hòa tan tinh khí thần tam tộc cổ thành giọt máu tươi. Phân thân tu sĩ tách khỏi bổn tôn, bổn tôn hoàn toàn trở thành cổ tộc.","anchor":"Phân thân rời đi khiến cho bổn tôn Vương Lâm đang ngồi khoanh chân lúc này hoàn toàn là cổ tộc!"},{"chuong":"@c1612","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp ba bản nguyên thành cổ Mạch Thương Khung Huyết","text":"Vương Lâm lần lượt hòa tan thân thể Cổ Yêu (mắt trái tan, tạo giọt máu chứa Cổ Yêu thu nhỏ), thân thể Cổ Ma (mắt phải tan, toàn thân héo rũ như thây khô, tạo giọt máu đen mang ma khí), rồi toàn bộ thân thể Cổ Thần (từ chân tay đến toàn thân hóa sương mù máu, nửa nén hương ngưng tụ thành giọt máu). Ba giọt máu xếp hình chữ phẩm, đồng thời mở mắt rồi dung hợp thành một giọt máu duy nhất màu đen lấp lánh chứa tất cả Cổ Thần, Cổ Ma, Cổ Yêu. Quá trình cực kỳ thống khổ vượt cực hạn chịu đựng. Giọt máu phát ra khí tức thê lương xông thẳng chín tầng trời, chấn động toàn bộ cổ tộc trong giới nội lẫn giới ngoại. Phân thân hắn trên tế đàn chứng kiến bổn tôn hoàn toàn biến mất. Quá trình kéo dài mười ba ngày (Huyền La năm xưa chỉ mất chín ngày). Trên mi tâm pho tượng cổ tổ ở Tiên Cương hiện bốn giọt máu, gây kinh ngạc toàn thể cổ quốc.","anchor":"Ba giọt máu tươi hoàn toàn dung hợp, hóa thành một giọt! Một giọt máu tươi này là tất cả Cổ Thần, Cổ Ma, Cổ Yêu, tất cả của Vương Lâm!"},{"chuong":"@c1613","importance":"normal","mucCt":"ky","tieuDe":"Huyết mạch cổ tộc hình thành — tám giọt máu cổ tổ ngang kỷ lục Huyền La","text":"Phân thân ngồi trên tế đàn giới nội, bốn giọt máu cổ tổ từ dòng xoáy lần lượt dung hợp vào giọt máu bổn tôn, mỗi giọt đau đớn gấp bội. Giọt thứ ba khiến thân thể tóc bạc ngưng tụ từ hư ảnh, toàn thân phủ ấn ký phức tạp. Giọt thứ tư điểm lên mi tâm, huyết mạch cổ tộc hình thành, chính thức trở thành hậu nhân cổ tổ và dân cư cổ quốc. Bất phục chỉ dừng bốn giọt, chủ động lao vào dòng xoáy sắp tiêu tán — trở thành người đầu tiên trong lịch sử Đạo cổ nhất mạch xông ngược vào đòi thêm máu tươi. Lần lượt đoạt giọt năm, sáu, bảy, tám, ngang bằng kỷ lục Huyền La Đại Thiên Tôn, chấn động gần trăm vạn tộc nhân. Hành động thể hiện ý chí không tôn kính cổ tổ, không khuất phục thiên địa, chỉ tin vào lực lượng bản thân.","anchor":"Hắn là người đầu tiên trong Đạo cổ nhất mạch, trong cổ Mạch Thương Khung Huyết sau khi đạt được máu tươi lại thấy chưa đủ, nhắm tới dòng xoáy này!"},{"importance":"normal","mucCt":"ky","chuong":"@c1614","tieuDe":"Thách thức cổ tổ, đoạt mười giọt máu và hồn huyết","text":"Không chấp nhận chỉ bốn giọt máu cổ tổ, lao thẳng vào dòng xoáy trên bầu trời thách thức cổ tổ, tuyên bố nếu không cho thêm máu và cơ duyên thì sẽ bức bốn giọt máu ra, bỏ huyết mạch cổ tộc nhập tiên tộc. Dùng ánh sáng trắng sữa ở mi tâm huyễn hóa hình ảnh quá khứ: cảnh đạt truyền thừa ký ức Đồ Ti trên Chu Tước Tinh khi còn Kết Đan, cảnh ở cổ mộ Thái Cổ Tinh Thần — chứng minh sớm có truyền thừa Cổ Thần. Thần thức cổ tổ kiểm chứng xong rút đi, dòng xoáy ngưng tụ trở lại đáp ứng: giọt máu tăng từ năm lên chín, rồi xuất hiện giọt thứ mười màu tím — hồn huyết cổ tổ, chưa từng có tiền lệ từ cổ chí kim.","anchor":"Nếu muốn ta tán thành huyết mạch này thì ngươi phải cho ta nhiều máu và cơ duyên hơn"},{"importance":"major","mucCt":"vua","chuong":"@c1615","tieuDe":"Hồn huyết thứ mười xuất hiện","text":"Kết quả tam tổn đệ nhất kiếp Cổ Mạch Thương Khung Huyết: năm giọt máu tươi và một giọt hồn huyết màu tím bay từ mi tâm pho tượng cổ tổ vào dòng xoáy. Giọt hồn huyết là giọt thứ mười của cổ quốc, vạn đời chỉ có chín giọt, nếu đạt hai giọt có thể tạo mạch cổ tộc thứ tư. Trên tế đàn trong cái khe Vân Hải tinh vực, huyết quang chiếu lên hắn khiến trông như huyết nhân, vài giọt máu tươi từ dòng xoáy gào thét lao ra. Bị hoàng tôn Đạo cổ coi thường là kẻ được truyền thừa của Diệp Mịch.","anchor":"Vạn đời cổ quốc ta cũng chỉ có chín giọt mà thôi!"},{"chuong":"@c1616","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp truyền thừa Cổ Tổ và cánh tay Diệp Mịch","text":"Tiếp nhận giọt máu tươi thứ 5 đến thứ 9 của Cổ Tổ qua mi tâm, cốt tủy thay đổi hoàn toàn, huyết mạch đạt nồng đậm ngang hoàng tôn Đạo cổ, trở thành đệ nhất huyết mạch trong Đạo cổ nhất mạch. Nhận giọt hồn huyết màu tím (giọt thứ 10) dung nhập mi tâm, hồn phách biến đổi, tương đương con trai thứ tư Cổ Tổ — cao quý hơn hoàng tôn. Hôn mê trên tế đàn, mộng thấy Cổ Tổ tuyên bố ý chí nghịch thiên và truyền khẩu quyết. Tỉnh dậy, tám tinh điểm Cổ Thần trên mi tâm chuyển tím, khí tức ngạo nghễ bá đạo. Dung hợp hoàn toàn cánh tay Diệp Mịch vào tay phải bằng 24 tinh điểm phát ánh sáng tím, tay phải biến đổi thô ráp với ký hiệu phức tạp và vẻ xanh mét. Lần đầu thi triển thuật Tê Thiên bằng tay phải mới, xé mở khe khổng lồ trong tinh không, uy lực đủ giết tu sĩ Không Huyền sơ kỳ. Phát hiện tế đàn có điều cổ quái.","anchor":"Tám tinh điểm cổ Thần lộ ra màu tím, chậm rãi chuyển động"},{"importance":"major","mucCt":"ky","chuong":"@c1617","tieuDe":"Gom đủ tế đàn Phong Diệt Tộc, tu luyện Tam Mệnh Thuật","text":"Dung hợp phân thân trở lại bổn tôn sau khi thu nạp cánh tay Diệp Mịch và hồn huyết Cổ Tổ. Dùng gần trăm vạn cấm chế phá vỡ tế đàn đá, phát hiện bên trong ẩn giấu vật bát giác tỏa hồng quang — phần tế đàn thứ ba và cuối cùng của Phong Diệt Tộc. Kết hợp lực lượng Tê Thiên toàn lực (cánh tay Diệp Mịch + Cổ Thần, Cổ Yêu, Cổ Ma bát tinh) xé nát hồng vân và phá hủy hoàn toàn tế đàn. Ba phần tế đàn Phong Diệt Tộc (huyết các Huyết Tổ từ Côn Hư, tế đàn từ chỗ Cổ Yêu ở La Thiên, vật bát giác vừa phát hiện) đồng thời xuất hiện, huyết quang giao hòa xác nhận cùng nguồn gốc. Ấn tộc ấn Phong Diệt Tộc vào mi tâm, phun máu tươi niệm chú gọi tổ linh, máu hóa trường đao ba thanh chồng nhau. Thực hiện bước Trảm Tam Hồn — trường đao chém xuyên thân thể, trảm được tam hồn, trên thiên linh hiện ra hai phần hồn phách. Tuy nhiên linh hồn quá cường đại (đã dung hợp hồn huyết Cổ Tổ) khiến đao chịu không nổi lực phản chấn, từ ba thanh còn hai rồi tan nát tiêu tán.","anchor":"Linh hồn Vương Lâm sau khi dung hợp với hồn huyết của Cổ Tổ làm sao thanh đao này có thể chém nổi"},{"importance":"normal","mucCt":"ky","chuong":"@c1618","tieuDe":"Trảm Tam Thân, đạt Tam Mệnh Thuật","text":"Dùng đôi trường đao cùng lực lượng kỳ dị của Phong Diệt Tộc chia thân thể, hồn phách, nguyên thần làm ba phần, nhập vào ba tế đàn hình dáng bất đồng. Huyết quang trên ba tế đàn xoay tròn suốt bảy ngày rồi suy yếu, hai ngày sau biến mất hoàn toàn. Ba Vương Lâm xuất hiện từ ba tế đàn sụp đổ, lần lượt nói Tam Mệnh Thuật, Mạnh mẽ tạo thân, Tam thể quy nhất rồi dung hợp thành một. Từ nay có ba mạng sống, mỗi phần sinh cơ tương đương toàn bộ trước đó. Tế đàn sụp đổ do hồn phách và thân thể quá cường đại, không thể dùng lại Tam Mệnh Thuật. Giải phóng hồn phách nữ tử cố nhân trong huyết các, tuyên bố ân oán xóa bỏ, tiễn nàng vào luân hồi. Xác nhận thân thể đạt huyết mạch Đạo cổ, yêu, ma, thần đạt bát tinh. Suy luận Thiên Vận Tử có thể là hồn thứ ba của Thất Thải Tiên Tôn hoặc thuộc bảy phách, dựa vào việc Thiên Vận Tử đạt máu thiên đạo, không chết, ẩn thế, có hơn ba nghìn phân thân từng thôn phệ đệ tử. Bắt đầu luyện hóa buồm mặt quỷ, dùng thần thức thăm dò suốt mười sáu ngày, phát hiện cấm chế bên trong tự động diễn biến, là tổ hợp cấm chế hoàn mỹ. Dùng huyết kiếm chém xuyên buồm mặt quỷ mở lỗ hổng, đưa thần thức vào bên trong, cấm chế tràn ra bao phủ toàn bộ khe Vân Hải tinh vực.","anchor":"Tam Mệnh Thuật đích thực là kỳ dị. Có thuật này trong người ta liền có ba mạng"},{"importance":"normal","mucCt":"ky","chuong":"@c1619","tieuDe":"Minh ngộ bổn nguyên cấm chế, chín lần dung hợp","text":"Ngồi trong khe nứt Vân Hải tinh vực, dùng thần thức Không Linh trung kỳ tính toán dung hợp cấm chế bổn nguyên suốt hơn hai mươi ngày. Minh ngộ bản chất cấm chế là đại đạo, là quy tắc thiên địa, bổn nguyên cấm chế là lực lượng tính toán bao trùm La Thiên, có thể tính toán tương lai và thay đổi vận mệnh. Thực hiện chín lần dung hợp: ba lần đầu bằng thần thức thuần túy, lần bốn triệu bổn tôn tách khỏi phân thân hóa tam thể Cổ Yêu, Cổ Ma, Cổ Thần tạo thế tam giác đè nén cấm chế. Lần năm đến tám dùng lục đạo bổn nguyên hóa sáu thanh trường kiếm áp chế. Lần chín phun máu tươi chia 3172 phần thi triển Huyết cấm. Từ vô số cấm chế dung hợp còn chín cái lớn ngàn trượng, nhưng hai cái lập tức vỡ tung phân chia. Điểm chỉ vào mắt phải, phun sương mù máu biến ảo thành hư ảnh đồng tử khổng lồ tràn ngập tơ máu. Nhận định Thiên Vận Tử đã ẩn giấu trình độ cấm chế kinh thiên.","anchor":"Cấm chế bổn nguyên chính là một lực lượng tính toán. Loại lực lượng này bao trùm cả La Thiên, thậm chí có thể tính toán cả tương lai, thay đổi được vận mệnh bản thân"},{"chuong":"@c1620","importance":"normal","mucCt":"ky","tieuDe":"Ngộ cấm chế bổn nguyên, đột phá Không Linh hậu kỳ","text":"Lĩnh ngộ bản chất quy tắc và pháp tắc: giống vô số sợi tơ vô hình cuốn quanh vạn vật, cấm chế là sinh linh thượng cổ bắt chước quy tắc mà tạo ra. Chọn phương pháp dùng tơ máu đồng tử hai mắt làm sợi tơ quy tắc, dung hợp toàn bộ cấm chế xung quanh — phương pháp từ cổ chí kim chưa ai nghĩ tới. Hai đồng tử hư ảo khổng lồ xuất hiện, hấp thu mọi cấm chế rồi thu về mắt. Tam thể bổn tôn và phân thân dung hợp thành một thể. Đạo bổn nguyên thứ bảy — cấm chế bổn nguyên — thành hình, trường kiếm lục đạo bổn nguyên phát tiếng hoan hô. Tơ máu trong mỗi mắt ngưng tụ thành một sợi chỉ hồng nằm ngang chia đôi đồng tử, hồng quang trên đầu ngón tay hóa u quang cấm chế, điểm chỉ tạo thanh trường kiếm hư ảo chứa vô số cấm chế. Tu vi trực tiếp từ Không Linh trung kỳ tăng tới Không Linh hậu kỳ, nắm tay khiến tinh không bốn phía run rẩy. Thử nghiệm sức mạnh mới: gảy sợi dây quy tắc vô hình lần một tạo vùng băng hàn khổng lồ, lần hai tạo hố đen nuốt mọi vật. Thu tấm buồm mặt quỷ — lỗ hổng tự khép lại nguyên vẹn, hoàn toàn trở thành bảo vật của hắn. Nhận định ảo thuật Đại Hồn Môn cũng là một loại cấm chế, cấm chế bổn nguyên chưa đại thành — muốn đại thành phải khiến quy tắc bản thân trở thành quy tắc thiên địa. Tổng kết chuyến Vân Hải tinh vực: đạt Đạo Cổ bát tinh Không Linh hậu kỳ, được tấm buồm mặt quỷ và thuyền, kết liên minh với Phàn San Lộ, mơ hồ thấy phương pháp tìm hồn thứ ba từ đạo nhân bảy màu.","anchor":"Tu vi gia tăng khiến cho chỉ một động tác nắm tay này của hắn cũng khiến cho tinh không bốn phía run rẩy"},{"chuong":"@c1621","importance":"normal","mucCt":"ky","tieuDe":"Trở về tiên giới, chuẩn bị truy sát Thiên Vận Tử","text":"Rời khe núi Vân Hải tinh vực, tới ranh giới tiên giới dùng tơ máu trong đồng tử dung nhập ngân hà và túm quy tắc tinh không ngưng tụ bao phủ, tăng cường cấm chế bảo vệ tiên giới. Bước vào tiên giới, gặp lại Hồng Sam Tử, Thanh Lâm, Thanh Thủy, Tư Đồ Nam, Nam Vân Tử và nhiều người quen. Thấy Hồng Điệp đã nhận cha Thanh Thủy, Chu Dật u buồn nhìn Thanh Sương từ xa, Chu Như đã trưởng thành. Trả hồn huyết cho Đầu to, giải phong ấn cho hắn được tự do hoàn toàn. Ở đỉnh núi phía bắc hơn một tháng, giao toàn bộ tiên phẩm và tiên thuật từ Lôi Tiên Giới cho Thanh Lâm truyền thụ. Dành phần lớn thời gian nghiên cứu tấm buồm mặt quỷ Cấm Phiên, nắm giữ ảo thuật trong đó nhưng tiến triển chậm. Nhớ tới Lý Mộ Uyển, cảm thấy có lỗi với nàng. Ghé thăm khu Lam Ti tộc, biết Lý Thiến Mai đang bế quan, thở phào vì chưa hiểu rõ đối với nàng là ân hay tình. Coi Thiên Vận Tử là cái gai phải rút, tiến vào hồn Thiên Vận Tử mà hắn nắm giữ để truy tìm bổn tôn và giết.","anchor":"Thiên Vận Tử không trừ, Vương Lâm khó có thể an tâm"},{"importance":"normal","mucCt":"ky","chuong":"@c1622","tieuDe":"Phát hiện phân thân Thiên Vận Tử là bẫy","text":"Vương Lâm ngồi trong nhà tranh trên đỉnh núi tân tiên giới, dung hợp với hồn phách phân thân Thiên Vận Tử nhằm truy tìm vị trí bổn tôn. Sau năm ngày dung hợp, đột ngột cảm thấy bổn nguyên dường như bị mất đi dù kiểm tra bảy đạo bổn nguyên không giảm. Thử dung hợp lần hai, cảm giác bất ổn mạnh hơn, dứt khoát tách ra. Suy đoán toàn bộ việc năm xưa giết phân thân Thiên Vận Tử ở vùng đất yêu linh bằng thuật Tàn Dạ và đoạt hồn phách đều có thể nằm trong âm mưu của Thiên Vận Tử. Rút hồn phách phân thân ra khỏi mi tâm, dịch chuyển tới tuyết sơn phía nam tiên giới tìm Thanh Lâm nhờ hộ pháp và tính toán.","anchor":"Kỳ quái, tại sao ta cảm thấy khi dung hợp với phân thân của Thiên Vận Tử, bổn nguyên hình như mất đi"},{"importance":"normal","mucCt":"ky","chuong":"@c1623","tieuDe":"Lộ bảy bổn nguyên, mắc Luân Hồi nhất thể thuật","text":"Đề nghị Thanh Lâm dung nhập thần thức vào cơ thể mình để quan sát bổn nguyên khi dung hợp phân hồn Thiên Vận Tử, thể hiện tin tưởng tuyệt đối. Thanh Lâm phát hiện Vương Lâm có bảy đạo bổn nguyên (trước chỉ biết sáu) và huyết mạch cổ xưa bá đạo không phải Cổ Thần thông thường. Khi dung hợp sâu, cấm chế bổn nguyên tự phân tia vận chuyển mà hắn không hay biết, bị lực lượng kỳ dị điều khiển hướng về Triệu Hà tinh vực, được Thanh Lâm dùng Định Thần Thuật ngăn kịp. Lam Mộng Đạo Tôn cảnh báo nắm chắc bốn phần đã mắc Luân Hồi nhất thể thuật của Thiên Vận Tử, nhưng nếu giết được đối phương thì ngược lại sẽ thôn phệ tăng tu vi. Được Lam Mộng Đạo Tôn dùng lam quang định vị, nhìn thấy bổn tôn Thiên Vận Tử trên thiên thạch sâu trong Triệu Hà tinh vực, ánh mắt hai người chồng lên nhau.","anchor":"Ánh mắt của Vương Lâm và ánh mắt Thiên Vận Tử trong tích tắc chồng lên nhau!"},{"chuong":"@c1624","importance":"major","mucCt":"ky","tieuDe":"Truy sát Thiên Vận Tử — bẫy hiến hồn đoạt cấm chế","text":"Nhận ra âm mưu Thiên Vận Tử, vọt khỏi tiên giới ra tinh không, dung nhập thiên địa tới Triệu Hà truy sát. Phá nát thiên thạch tìm thấy Thiên Vận Tử, đại chiến bằng hỏa bổn nguyên (hỏa Chu Tước đối kháng, đồng thời sụp đổ) và lôi bổn nguyên (lôi điện khai thiên xuyên qua chín Lôi Long). Cận chiến nắm quyền bị thương phun máu nhưng không lui. Lần đầu thi triển Sát cấm — vuốt hai mắt triệu hai đồng tử hư ảo đầy tơ máu ẩn chứa cấm chế, quấn và chia lìa thân thể Thiên Vận Tử. Tuy nhiên mỗi lần giết phân thân Thiên Vận Tử, hồn phách đối phương tự động dung nhập vào cơ thể Vương Lâm khiến phân hồn Thiên Vận Tử bên trong lớn mạnh thêm. Đuổi tới tu chân tinh, Thiên Vận Tử lại chủ động tự sát lần hai, phân hồn tiếp tục nhập vào. Nhận ra mình đang bị dẫn dắt vào bẫy, trái tim lạnh như băng.","anchor":"Vương Lâm đột nhiên cảm thấy trái tim lạnh như băng"},{"importance":"normal","mucCt":"ky","chuong":"@c1625","tieuDe":"Phát hiện sơ hở Luân Hồi toàn thể thuật, lật ngược cục diện với Thiên Vận Tử","text":"Bình tĩnh phân tích âm mưu đoạt xá của Thiên Vận Tử, suy luận rằng hắn không phải nạn nhân đầu tiên bị Luân Hồi toàn thể thuật cướp bổn nguyên. Chủ động tìm đến đám đá vụn trong Triệu Hà tinh vực đối mặt phân thân Thiên Vận Tử, bình thản ngồi xuống khoanh chân đối thoại. Nhận thủy bổn nguyên (một tia) và thổ bổn nguyên (đám bùn đất) từ Thiên Vận Tử. Khi Thiên Vận Tử định diễn cảnh tử vong quỷ dị bằng cách tự điểm xuyên mi tâm lần hai, dùng cuồng phong ẩn chứa lực lượng huyết mạch Đạo cổ phá tan đá vụn bốn phía cản lại. Phát hiện sơ hở trí mạng: Thiên Vận Tử không có khí tức Đạo cổ, Luân Hồi toàn thể thuật không trộm nổi huyết mạch Đạo cổ. Vạch trần Thiên Vận Tử hiện tại chỉ là phân thân, bổn tôn ở nơi khác. Tuyên bố tự đặt quy tắc trò chơi: bổn tôn hắn sẽ đi tìm bổn tôn Thiên Vận Tử mà giết, còn phân thân tu sĩ này chỉ là con cờ. Cuối cùng phóng lực lượng Đạo cổ tấn công phân thân Thiên Vận Tử.","anchor":"Ta có thể tạo lại tiên giới, được vô số tu sĩ ghi tạc, ngươi có thể sao!"},{"importance":"major","mucCt":"ky","chuong":"@c1626","tieuDe":"Phế phân thân, mộng nhập truy bổn tôn Thiên Vận Tử","text":"Bổn tôn tách khỏi phân thân, chủ động phế bỏ phân thân để Tam Mệnh Thuật tử vong một lần, hủy khả năng Thiên Vận Tử trộm thần thông. Triệu Hồn Phiên bao phủ tinh không, rồi hóa sương mù — hơn phân nửa nhập mi tâm bổn tôn, phần còn lại bao phủ thân bổn tôn. Thu hồi hai bổn nguyên (giọt nước và bùn đất). Biến hồn phách phân thân thành dạng thôn hồn năm xưa, nguyên thần liên kết chặt chẽ với hồn phách, có thể cắn nuốt tất cả kể cả bản thân. Giao bổn tôn cho Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử hộ pháp. Khi Thiên Vận Tử triệu gần ba nghìn phân thân trong tứ đại tinh vực, hồn phách Thiên Vận Tử trong cơ thể hắn sôi trào liên lạc toàn bộ — Vương Lâm cảm ứng vị trí từng phân thân, trúng kế. Dùng Mộng Đạo làm đường, mượn cấm chế Hồn Phiên làm huyễn, mộng nhập ba nghìn phân thân truy hồi luân hồi đạo tìm bổn tôn Thiên Vận Tử. Bổn tôn mở bừng mắt, mở con đường mộng về ngàn năm trước, nhập huyễn cảnh thấy Thiên Vận Tử ngồi trên thiên thạch Triệu Hà xưa, tay dính máu thiên đạo, rồi cắn nuốt Lăng Thiên Hầu đang hôn mê.","anchor":"Ta không tiếc hết thảy phế bỏ phân thân của mình cũng chỉ là dùng Tam Mệnh Thuật này tử vong một lần"},{"chuong":"@c1627","importance":"normal","mucCt":"ky","tieuDe":"Nhận ra thân phận thật Thiên Vận Tử — phân thân bị đoạt xác","text":"Bổn tôn đắm chìm trong luân hồi của Thiên Vận Tử, chứng kiến toàn bộ hơn chín mươi bảy lần thức tỉnh ngược về thái cổ và tinh vực tử vong. Ban đầu suy đoán Thiên Vận Tử là hồn thứ ba của Thất Thải Tiên Tôn nhưng phát hiện sai hoàn toàn — Thiên Vận Tử là thực thể nguyên thủy đã nuốt phách Thất Thải Tiên Tôn, tồn tại từ trước khi có sự sống. Hồi tưởng được cảnh Thiên Vận Tử phát hiện hắn trên tu chân tinh bỏ đi khi còn tu vi Nguyên Anh, chủ động kết thiện duyên giả nhận đệ tử ký danh, mục đích thật là bồi dưỡng rồi cắn nuốt phân thân. Cuối chương tuyên bố đã biết đối phương là ai nhưng chưa nói ra. Phân thân ở Triệu Hà bình tĩnh khoanh chân ngồi giữa cơn tấn công của gần ba nghìn hồn phách Thiên Vận Tử đang chiếm cơ thể, không phản kháng.","anchor":"Hắn nuốt thất phách của Thất Thải Tiên Tôn! Hắn vốn không phải là tam hồn thất phách của Thất Thải Tiên Tôn"},{"importance":"normal","mucCt":"ky","chuong":"@c1628","tieuDe":"Phát hiện Thiên Vận Tử là Thiên Đạo, tìm ra bổn tôn","text":"Bổn tôn đắm chìm trong luân hồi Thiên Vận Tử, phát hiện sự thật kinh thiên: Thiên Đạo chính là Thiên Vận Tử, bổn tôn là nửa nghịch la bàn mang ấn ký cổ xưa nằm sâu trong một tu chân tinh không sinh mạng. Chứng kiến cảnh tượng cánh cửa khổng lồ (khác cánh cửa Thiên Nghịch) bị lực lượng cường đại oanh kích vỡ tung, đám sương mù bạc chứa nửa nghịch la bàn rơi vào tu chân tinh. Ngộ ra thiên đạo vốn không có linh trí, sau khi cắn nuốt Liên Đạo Phi và hấp thu phần tham lam cùng tính xấu từ thần thức tự bạo của tiên nhân mà sinh ra suy nghĩ, hóa hình thanh niên. Ngộ ra chân tướng Liên Đạo Phi: vốn là kẻ ngỗ ngược kiêu ngạo trên Tiên Cương đại lục, có ca ca thân phận cực cao, bị thiên đạo hấp thu phần tính xấu nên còn lại thành người điên hiện tại. Ghi nhớ khí tức tu chân tinh nơi cất giấu nửa la bàn, chín mươi chín lần luân hồi Thiên Vận Tử hoàn toàn chấm dứt. Thoát luân hồi, cảm nhận phân thân sắp bị hồn phách Thiên Vận Tử chiếm cứ hoàn toàn, nhờ Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử khống chế phân thân tranh thủ thời gian, rồi ôm quyền cất bước vào tinh không lên đường tìm bổn tôn Thiên Vận Tử.","anchor":"Thiên Vận Tử, trò chơi kết thúc rồi!"},{"importance":"normal","mucCt":"ky","chuong":"@c1629","tieuDe":"Đoạt bổn tôn Thiên Vận Tử","text":"Bổn tôn Đạo cổ xé khe tinh không di chuyển từ Triệu Hà tới Côn Hư tinh vực chỉ trong gần một nhịp thở, phương pháp chỉ thân thể Đạo cổ có huyết mạch mạnh hơn Cổ Thần mới chịu nổi. Tại Côn Hư, phát hiện tu chân tinh hoang dã mang khí tức tinh hồn quen thuộc đang sắp tử vong, phá cương phong quét sạch sương mù độc, rẽ hải dương đen xuyên xuống đáy biển, vào động cổ vạn cổ đoạt lấy nửa cái la bàn chôn vùi dưới bụi đất — chính là bổn tôn của Thiên Vận Tử. Từ cuối tinh không tuyên bố đã đem bổn tôn Thiên Vận Tử về, xác nhận đã nhanh hơn trong cuộc đua tốc độ.","anchor":"Thiên Vận Tử, Vương mỗ đem bổn tôn của ngươi về rồi đây!"},{"chuong":"@c1630","importance":"normal","mucCt":"ky","tieuDe":"Tiêu diệt Thiên Vận Tử, triệu U Minh Thú","text":"Cầm nửa la bàn (bổn tôn Thiên Vận Tử) bước tới từ phía sau nhóm Lam Mộng Đạo Tôn, đối mặt Thiên Vận Tử. Dùng ấn ký trên ngực phân thân lần lượt tiêu hủy bảy đạo bổn nguyên, nguyên thần, hồn phách của phân thân — phá vỡ sự dung hợp ba nghìn phân thân của Thiên Vận Tử, khiến thân thể hắn tan nát và 2999 hồn phách nổ tung. Tự xưng là chủ nhân của thiên đạo, điểm mi tâm khiến tinh điểm Cổ Thần tiêu tán, dòng xoáy bên trong phóng ra U Minh Thú khổng lồ. Cho nửa la bàn bay vào miệng U Minh Thú, ra lệnh nuốt sạch toàn bộ 2999 hồn phách Thiên Vận Tử. Ngồi lên lưng U Minh Thú bay đi, nhờ Lam Mộng Đạo Tôn nhắn Thanh Thủy sư huynh mấy ngày đừng ra ngoài và chờ hắn trở về. Chính thức có tư cách trục lộc trong thế giới động phủ.","anchor":"Hắn cho tới giờ phút này mới thực sự có tư cách trục lộc!"},{"importance":"normal","mucCt":"ky","chuong":"@c1631","tieuDe":"Ngưng tụ phân thân mới, thu hồi bốn bổn nguyên","text":"Cưỡi u Minh thú trong tinh không, hồi tưởng về thiên đạo, xác nhận u Minh thú và Thiên Vận Tử đều là bộ phận thiên đạo, tuyên bố mình là chủ nhân thiên đạo. Phun máu Đạo cổ huyết mạch làm vật dẫn ngưng tụ phân thân mới: dùng tinh điểm tam tộc rút lực Đạo cổ khỏi huyết nhân, tách hồn phách vào phân thân, bổn tôn ngủ say, phân thân tiếp quản. Phân thân lần lượt thu hồi Hỏa bổn nguyên vào mắt trái, Lôi bổn nguyên vào mắt phải, Sinh Tử bổn nguyên dung hợp thành vòng âm dương ở mi tâm khiến khí tức bạo tăng, Chân Giả bổn nguyên khiến thân hóa hư ảo, nhắm mắt là giả mở mắt là thật. Tới Triệu Hà tinh vực, gặp nhóm tứ đại chiến tướng viễn cổ tiên vực và Chiến lão quỷ.","anchor":"Phân thân này lấy huyết mạch của ta làm vật dẫn thành tựu đại đạo vạn cổ"},{"chuong":"@c1632","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp phân thân, xác lập chiến lược trục lộc","text":"Bổn tôn ngủ say khôi phục trên lưng U Minh thú trong khi phân thân ngưng tụ bảy đại bổn nguyên (nhân quả, sát lục, cấm chế và các bổn nguyên khác), nguyên thần biến ảo trở lại như cũ, chỉ khác không còn hồn phách phân thân Thiên Vận Tử. Nửa ngày sau phân thân chồng lên bổn tôn dung hợp thành một thể, cơ thể hoàn toàn khỏe mạnh. Xác định mục tiêu tiếp theo: tới Ngũ Hành tinh bức lực lượng ẩn thế cuối cùng lộ diện, rồi triển khai trận tranh đoạt hồn thứ ba. Coi Thiên Vận Tử là cây đinh đã rút, cây đinh thứ hai là đám người Quy Nguyên Tông từ Tiên Cương đại lục. Khi bị tứ đại chiến tướng cùng Chiến lão quỷ và hơn trăm tiên nhân vây chặn đòi nguồn gốc U Minh thú, bình thản không nao núng, tuyên bố cho bọn họ nếm đau đớn tới tận xương cốt rồi triệu hoán Khai Thiên Phủ khổng lồ đối đầu.","anchor":"Lập tức Khai Thiên Phủ khổng lồ ầm ầm hiện ra!"}],"tuiDo":{"phapBao":[{"ten":"Thanh Quang Thuẫn","trangThai":"dang-co","moTa":"Đã chữa trị đầy đủ, truyền lực lượng Đạo Cổ vào kích hoạt Mộng Hồi Viễn Cổ bên trong.","nguon":"@c1579"}]},"nhanMach":[{"ten":"Hồng Điệp","tag":"ban-be","quanHe":"Nữ tử kính nể Vương Lâm, có tình cảm không rõ ràng; từng giao chiến ở Vũ Tiên Giới, được Vương Lâm giải thoát khỏi luân hồi ở Chu Tước mạc","ghiChu":"Xác nhận danh tính @c1581"},{"ten":"Diệu Âm đạo tôn","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra tấn công hắn"},{"ten":"Cửu Thiên ma tôn","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, cùng Diệu Âm và Đại Hoang tấn công hắn"},{"ten":"Đại Hoang Thượng Nhân","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, cùng hai người kia tấn công hắn"},{"ten":"Chưởng môn phân tông Quy Nhất tông","tag":"khac","quanHe":"Chưởng môn phân tông nhận ra huyết kiếm là kiếm của Diệp Mịch","ghiChu":"@c1586"},{"ten":"Viêm long","tag":"khac","quanHe":"Linh thú thu phục, trước đây là thú cưỡi của Liên Đạo Phi","ghiChu":"Dùng ấn quyết Chu Tước trấn áp, thu vào khe trữ vật @c1591"},{"ten":"Phàn San Lộ","tag":"dong-minh","quanHe":"Đồng minh hợp tác","ghiChu":"Đệ nhất phi Thất Đạo Tông, đề nghị Vương Lâm giết Thất Thải Thiên Tôn đổi sơn môn, hứa giúp nhập Đại Hồn Môn và qua kiếp nạn Tiên Cương"},{"ten":"Phàn San Mộng","tag":"doi-thu","quanHe":"Đối thủ tiềm tàng","ghiChu":"Người thứ hai cả đời khiến Vương Lâm kiêng kỵ trong lòng, thi triển ảo thuật suýt ép hắn giao thệ huyết"},{"ten":"Nữ tử trong băng sơn","tag":"khac","quanHe":"Tỷ tỷ của Phàn San Lộ, gián tiếp trợ lực phá vây cho Vương Lâm","ghiChu":"Truyền lực xuyên không gian từ Tiên Cương đại lục @c1598"},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Người duy nhất Vương Lâm không thể nắm được tâm tư","ghiChu":"Vương Lâm tự nhận cả đời gặp nhiều người nhưng chỉ Thiên Vận Tử là ngoại lệ"},{"ten":"Nữ tử trong núi băng","tag":"khac","quanHe":"Tỷ tỷ của Phàn San Lộ, gián tiếp trợ giúp Vương Lâm thoát vây","ghiChu":"Tướng mạo giống hệt Phàn San Lộ, truyền lực xuyên không gian phá tinh thể vây khốn"},{"ten":"Huyền La Đại Thiên Tôn","tag":"su-mon","quanHe":"Huyền La tuyên bố sẽ nhận Vương Lâm làm đệ tử duy nhất nếu tới được Tiên Cương","gap":"@c1612"},{"ten":"Cổ Hoàng","tag":"doi-thu","quanHe":"Hoàng tôn Đạo cổ, coi thường Vương Lâm, tuyên bố dù có hồn huyết cũng phải quỳ trước hắn","nguon":"@c1615"}],"tuViMoc":[{"chuong":"@c1603","canhGioi":"Tứ đại cấm chế viên mãn","text":"Liên tục phá cấm chế trên thuyền, tứ đại cấm chế đạt viên mãn, chỉ thiếu dung hợp làm một sinh ra bổn nguyên.","importance":"major"},{"chuong":"@c1610","canhGioi":"Bát Tinh Đạo Cổ","text":"Hấp thu toàn bộ tám giọt máu Đạo cổ Diệp Mịch, tam tộc cổ (Cổ Thần, Cổ Yêu, Cổ Ma) đồng thời đột phá lên Bát Tinh. Yêu tinh thứ tám (mắt trái), ma tinh thứ tám (mắt phải), tinh điểm Cổ Thần thứ tám (mi tâm) đều ngưng thật. Hư ảnh Đạo Cổ hiện ra sau lưng.","importance":"major"},{"chuong":"@c1611","canhGioi":"Bát tinh Cổ Yêu","text":"Tám yêu tinh mắt trái dung hòa, yêu khí tràn ngập, ngưng tụ yêu giáp tím đỏ. Vượt nhị tổn tứ kiếp Cổ Yêu, đạt bát tinh Cổ Yêu.","importance":"major"},{"chuong":"@c1611","canhGioi":"Bát tinh Cổ Ma","text":"Tám ma tinh mắt phải hiện, ma khí bao phủ, xuất hiện ma giáp đen. Vượt nhị tổn tứ kiếp Cổ Ma, thân thể Cổ Ma gần đạt đại thành.","importance":"major"},{"chuong":"@c1611","canhGioi":"Tam tộc cổ bát tinh cân bằng (Đạo cổ hoàn chỉnh)","text":"Cổ Thần, Cổ Yêu, Cổ Ma đều đạt bát tinh, 24 tinh điểm đồng chuyển, khí tức Đạo cổ tràn ngập tinh không, Đạo cổ đạt cân bằng hoàn chỉnh.","importance":"major"},{"chuong":"@c1618","canhGioi":"Huyết mạch Đạo cổ + Yêu/Ma/Thần bát tinh","text":"Sau khi hoàn thành Trảm Tam Thân qua ba tế đàn Phong Diệt Tộc, xác nhận thân thể đạt huyết mạch Đạo cổ, yêu, ma, thần đạt bát tinh. Đây là mốc hệ thân thể/yêu/ma/thần, không phải tu vi chính Không Linh.","importance":"major"},{"chuong":"@c1620","canhGioi":"Không Linh hậu kỳ","text":"Khi thanh kiếm cấm chế bổn nguyên hư ảo xuất hiện, khí tức toàn thân từ Không Linh trung kỳ trực tiếp tăng tới Không Linh hậu kỳ, đồng thời đạt Đạo Cổ bát tinh.","importance":"minor"}],"diem":[{"text":"Từ phàm nhân tư chất kém, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, quyết chí tu tiên bước vào con đường khổ tu","chuong":"@c0001"},{"text":"Đoạt xá thân Mã Lương tái sinh, ngộ Thần Thức Cực Cảnh, nhận truyền thừa Cổ Thần Đồ Ti rồi trọng tổ thân thể Cổ Thần","chuong":"@c0176"},{"text":"Dung hợp bổn tôn với phân thân thành tam tinh Cổ Thần, ý cảnh đạt cấp Anh Biến dù tu vi chỉ Hóa Thần hậu kỳ","chuong":"@c0365"},{"text":"Cảm ngộ sáu đạo bổn nguyên đại thành, phá Không Môn thành tựu bước thứ ba Không Linh trung kỳ","chuong":"@c1522"},{"text":"Dung hợp huyết mạch Đạo Cổ tam tộc đạt bát tinh cân bằng, hoàn thành Trảm Tam Thân tu luyện Tam Mệnh Thuật","chuong":"@c1618"},{"text":"Lĩnh ngộ cấm chế bổn nguyên đột phá Không Linh hậu kỳ, truy sát tiêu diệt Thiên Vận Tử và minh ngộ chân tướng Thiên Đạo","chuong":"@c1630"}]},"nguon":["@c1579","@c1580","@c1581","@c1582","@c1583","@c1584","@c1585","@c1586","@c1587","@c1588","@c1589","@c1590","@c1591","@c1592","@c1593","@c1594","@c1595","@c1596","@c1597","@c1598","@c1599","@c1600","@c1601","@c1602","@c1603","@c1604","@c1605","@c1606","@c1607","@c1608","@c1609","@c1610","@c1611","@c1612","@c1613","@c1614","@c1615","@c1616","@c1617","@c1618","@c1619","@c1620","@c1621","@c1622","@c1623","@c1624","@c1625","@c1626","@c1627","@c1628","@c1629","@c1630","@c1631","@c1632"],"cn":"王林","gioiTinh":"nam","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh vươn lên nhờ ý chí khổ tu và quyết tâm sinh tử; Thâm trầm mưu trí, giỏi bố trí hậu thủ, nhìn thấu cạm bẫy và tính toán trước nước cờ của đối thủ; Quyết đoán tàn nhẫn với kẻ thù, không ngại đại khai sát giới khi cần thiết; Trọng ân oán nhân quả, gánh vác t","vaiTro":"Nhân vật chính — Đạo Cổ bát tinh tam tộc, tu sĩ bước thứ ba Không Linh hậu kỳ","blurb":"Vương Lâm là thiếu niên tư chất kém từ Thạch Thôn, nhờ Nghịch Thiên Châu, ý chí khổ tu và vô số lần sinh tử mà bước vào con đường tu tiên nhuốm ma đạo — trải qua diệt tộc, đoạt xá thân Mã Lương, ngộ Thần Thức Cực Cảnh, nhận truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, rồi liên tiếp đột phá qua Anh Biến, Vấn Đỉnh, Âm Hư, Dương Thực, Khuy Niết, Tịnh Niết và Toái Niết, thức tỉnh Cổ Thần thất tinh vương tộc, vượt Nhất Tổn Nhị Kiếp trở thành Cổ Thần chân chính, cảm ngộ bảy đạo bổn nguyên đại thành, đạt bước thứ ba Không Linh hậu kỳ. Hắn dung hợp huyết mạch Đạo Cổ tam tộc Cổ Thần, Cổ Y"},{"id":"con-trai-diep-mich","name":"Con trai Diệp Mịch","cn":"","aliases":["nam tử trung niên"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Con trai của Đạo Cổ Diệp Mịch, được phụ tổ truyền thừa thuật Tê Thiên cực mạnh. Có thể triệu hồi hư ảnh tam tộc cổ và hư ảnh Đạo Cổ chiến đấu, rơi vào điên cuồng bất chấp sinh tử khi giao chiến với Vương Lâm.","vaiTro":"Đối thủ sinh tử của Vương Lâm, con trai Đạo Cổ Diệp Mịch","tinhCach":"Hung hãn quyết liệt; điên cuồng bất chấp sinh tử khi chiến đấu; kiêu ngạo tự phụ về truyền thừa của phụ tổ","tabs":{"diem":[{"text":"Được Đạo Cổ Diệp Mịch truyền thừa thuật Tê Thiên, thần thông lấy vạn vật làm trời, hai tay cổ tộc xé trời.","chuong":"@c1579"},{"text":"Khi chiến đấu rơi vào trạng thái điên cuồng bất chấp sinh tử, chỉ có ý niệm duy nhất muốn xé tan đối thủ.","chuong":"@c1579"}],"kinhLich":[{"mucCt":"ky","text":"Triệu hồi hư ảnh tam tộc cổ và hư ảnh Đạo Cổ Diệp Mịch tấn công Vương Lâm. Va chạm lần đầu bị vỡ hư ảnh tam tộc cổ, phun máu bị đẩy lùi. Thi triển thuật Tinh không là thiên vặn vẹo tinh không, rồi triển khai Tê Thiên xé đôi bàn chân khổng lồ, xuyên phá Mộng Hồi Viễn Cổ, xé rách thân thể Vương Lâm từ mi tâm tới bụng lộ xương. Rơi vào trạng thái điên cuồng bất chấp sinh tử, chỉ có ý niệm duy nhất muốn xé tan Vương Lâm.","anchor":"giờ phút này chỉ có một ý niệm duy nhất trong đầu là muốn xé tan thân thể Vương Lâm","bridge":true,"khoang":"@c1579"},{"importance":"normal","mucCt":"ky","chuong":"@c1580","tieuDe":"Bị Vương Lâm giết trong Mộng đạo","text":"Trong mộng, phát hiện nơi giao chiến chỉ là mắt trái của khuôn mặt khổng lồ Vương Lâm, kinh hoàng gào thét chống cự nhưng song chưởng vỡ tung, bị thiên địa nghiền nát. Mộng tỉnh vẫn đang mê mang giữa không trung, bị Vương Lâm dùng huyết kiếm chém đôi. Thân thể hóa thành tám giọt máu tím chui vào mi tâm Vương Lâm. Tử vong.","anchor":"Cho tới khi tử vong hai mắt hắn vẫn lộ vẻ mờ mịt vô tận"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Mịch","tag":"su-mon","quanHe":"Phụ tổ (cha/tổ tiên)","ghiChu":"Được Diệp Mịch truyền thừa thuật Tê Thiên"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Giao chiến dữ dội tại tinh không bên ngoài Vô Danh Chuyển Luân trận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tê Thiên","moTa":"Thần thông cực mạnh do phụ tổ Diệp Mịch truyền thừa, lấy vạn vật làm trời, hai tay cổ tộc xé trời.","nguon":"@c1579"},{"ten":"Tinh không là thiên","moTa":"Thuật pháp vặn vẹo tinh không, dùng trước khi triển khai Tê Thiên.","nguon":"@c1579"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1579","@c1580"]},{"id":"diep-mich","name":"Diệp Mịch","tabs":{"kinhLich":[{"chuong":"@c1579","importance":"bridge","mucCt":"gon","text":"Đầu lâu Đạo Cổ Diệp Mịch được Vương Lâm dung hợp làm phương tiện chiến đấu; thuật Tê Thiên do hắn truyền thừa cho con trai được thi triển trong trận.","anchor":"Phụ tổ truyền thừa cho ta một thuật cực mạnh"},{"chuong":"@c1586","importance":"normal","mucCt":"vua","tieuDe":"Huyết kiếm xuyên tới Tiên Cương","text":"Huyết kiếm mang danh tính Diệp Mịch xuyên qua Đông Đan chung của Quy Nhất tông trên Tiên Cương. Tu sĩ Quy Nhất tông xác nhận lời đồn Diệp Mịch bị Thất Đạo Tông dẫn vào động phủ là thật.","anchor":"xem ra lời đồn Diệp Mịch đã bị Thất Đạo Tông dẫn vào động phủ là thật rồi"},{"chuong":"@c1612","importance":"bridge","mucCt":"gon","text":"Được nhắc tới: Huyền La dùng thuật bói toán phát hiện nguồn gốc cổ Mạch Thương Khung Huyết đến từ người thừa kế của Diệp Mịch, cổ hoàng kinh ngạc.","anchor":"Người thừa kế của Diệp Mịch là một việc ngoài ý muốn"},{"chuong":"@c1613","importance":"bridge","mucCt":"gon","text":"Được nhắc làm mốc so sánh: năm đó chỉ đạt ba giọt máu cổ tổ, Vương Lâm là người thừa kế đã vượt qua hắn.","anchor":"Phải biết rằng dù là Diệp Mịch năm đó cũng chỉ đạt được ba giọt"},{"importance":"bridge","mucCt":"gon","chuong":"@c1615","tieuDe":"Được nhắc qua lời hoàng tôn","text":"Bị hoàng tôn Đạo cổ gọi khinh thường, coi Vương Lâm là kẻ được truyền thừa của Diệp Mịch.","anchor":"Chỉ một kẻ được truyền thừa của Diệp Mịch, hắn có tư cách gì mà khiến Huyền La Đại Thiên Tôn coi trọng như vậy!"},{"chuong":"@c1616","importance":"bridge","mucCt":"vua","text":"Cánh tay khổng lồ nằm trên tế đàn bị Vương Lâm dung hợp hoàn toàn vào tay phải; ban đầu phản kháng dãy dụa nhưng bị trấn áp bởi huyết mạch chín giọt máu Cổ Tổ và khí tức hồn phách mới của Vương Lâm.","anchor":"Diệp Mịch, đưa cánh tay này cho ta!"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, bị Lý Quảng bắn rơi mắt trái khiến khí tức truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu bùng lên từ chín quan tài trên tấm bia đá khổng lồ","chuong":"@c1576"},{"text":"Đầu lâu được Vương Lâm dung hợp làm phương tiện chiến đấu; thuật Tê Thiên do hắn truyền thừa","chuong":"@c1579"},{"text":"Huyết kiếm mang danh tính Diệp Mịch xuyên qua Đông Đan chung của Quy Nhất tông trên Tiên Cương","chuong":"@c1586"},{"text":"Năm đó chỉ đạt ba giọt máu cổ tổ, Vương Lâm là người thừa kế đã vượt qua thành tựu này","chuong":"@c1613"},{"text":"Cánh tay khổng lồ nằm trên tế đàn được Vương Lâm dung hợp hoàn toàn vào tay phải","chuong":"@c1616"}]},"nguon":["@c1579","@c1586","@c1612","@c1613","@c1615","@c1616"],"trangThai":"khong-ro","cn":"叶覔","gioiTinh":"nam","vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, người để lại di sản tu luyện cho Vương Lâm","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân cổ mộ truyền thừa mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong vùng đất cổ mộ, nhưng bị Lý Quảng bắn rơi mắt trái khiến khí tức truyền thừa không hoàn chỉnh. Di vật của ông bao gồm lầu các địa phủ chứa ba thần hồn, đầu lâu được Vương Lâm dung hợp làm phương tiện chiến đấu, cánh tay khổng lồ trên tế đàn, cùng khí tức Đạo Cổ mang đặc tính biến đổi giữa Cổ Thần, Cổ Ma, Cổ Yêu; năm đó chỉ đạt ba giọt máu cổ tổ, và Vương Lâm với tư cách người thừa kế đã vượt qua thành tựu này."},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","cn":"西子凤","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ở bên cạnh Vương Lâm trong Vô Danh Chuyển Luân trận, lo lắng khi trận pháp bị tấn công. Ấm rượu đợi Vương Lâm suốt chín tháng nhưng hắn không uống. Hết một năm, thần sắc phức tạp nhìn Vương Lâm, than nhẹ rồi rời đi.","anchor":"Cho tới hết một năm, Tây Tử Phượng với thần sắc phức tạp nhìn Vương Lâm một lần, than nhẹ rồi từ từ rời đi","bridge":true,"khoang":"@c1580"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Gặp Vương Lâm giữa Lôi Tiên Giới sụp đổ, cung kính cảm tạ hai lần được cứu mạng","chuong":"@c0750"},{"text":"Đau lòng rơi lệ khi nhận ra Vương Lâm tranh phong tiên vì Lý Mộ Uyển","chuong":"@c0826"},{"text":"Tái xuất bi thương sau tám trăm năm, gia tộc diệt vong, tự hủy dung nhan giữ khí tiết","chuong":"@c1395"},{"text":"Được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công bạo tăng tới Tinh Tịnh Niết và chính thức bái sư tôn","chuong":"@c1398"},{"text":"Nhận huyết kiếm bản mệnh từ Vương Lâm, dung nhập cơ thể thành pháp bảo để rửa nhục tám trăm năm","chuong":"@c1399"},{"text":"Xin Vương Lâm cho một năm ở bên cạnh, đồng hành cùng hắn nơi tiền tuyến đại chiến giới ngoại","chuong":"@c1573"}]},"nguon":["@c1580","@c1581"],"vaiTro":"Nữ tu sĩ trọng tình, từng được Vương Lâm nhiều lần cứu giúp và sau bái hắn làm sư tôn","tinhCach":"biết cảm ân, cung kính tạ ơn và trung thành với ân nhân; trọng tình cảm, nhiều lần rung động trước Vương Lâm nhưng âm thầm chịu đựng; kiên cường chịu nhục, tự hủy dung nhan để giữ khí tiết; dễ tự ti trước khoảng cách thân phận","blurb":"Tây Tử Phượng là nữ tu sĩ lần đầu gặp Vương Lâm trong biến cố Lôi Tiên Giới sụp đổ, được hắn cứu giúp rồi mang theo tình cảm thầm kín qua cuộc tranh phong tiên tại Lôi Tiên Điện, nơi nàng chứng kiến hắn tranh đoạt vì Lý Mộ Uyển mà đau lòng rơi lệ. Tám trăm năm sau, nàng tái xuất với gia tộc diệt vong và dung nhan tự hủy, được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công cho tu vi bạo tăng tới Tinh Tịnh Niết, rồi chính thức bái hắn làm sư tôn và nhận huyết kiếm bản mệnh để rửa nhục. Trong đại chiến giới ngoại, nàng xin được ở bên cạnh Vương Lâm một năm và lặng lẽ đồng hành cù"},{"id":"chuong-ton","name":"Chưởng Tôn","cn":"掌尊","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Xuất hiện ngoài trận pháp hơn trăm trượng, bị Vương Lâm kéo cung Lý Quảng uy hiếp, trầm mặc hồi lâu rồi xoay người rời đi.","anchor":"Lúc này thân ảnh Chưởng Tôn xuất hiện, nhìn chằm chằm vào Vương Lâm, trầm mặc hồi lâu rồi xoay người rời đi"},{"mucCt":"gon","text":"Hai năm trước tìm Lam Mộng Đạo Tôn hứa giúp tách hồn ngũ phi nhưng Lam Mộng biết bất khả. Cứu Diệu Âm đạo tôn, Cửu Thiên ma tôn và Đại Hoang Thượng Nhân ra khỏi cổ mộ nơi Vương Lâm nhốt, ba người mang sát khí lao tới tấn công Vương Lâm.","anchor":"Chưởng Tôn hai năm trước đi tìm ta, từng nói có thể giúp ta bức hồn phách ngũ phi trong thân thể thê tử ta ra","bridge":true,"khoang":"@c1582"},{"mucCt":"vua","text":"Ngồi trong cung điện cảm nhận Vương Lâm xuất hiện trong Thái Cổ Tinh Thần, nắm chặt bàn tay khô héo trầm mặc rất lâu. Dù tu vi thông thiên nhưng không dám hạ quyết tâm giết Vương Lâm vì kiêng kỵ cung Lý Quảng còn chưa dùng hết sức bắn hai cung, nghi ngờ Vương Lâm đang khiêu khích dụ hắn ra ngoài.","anchor":"Tu vi của hắn thông thiên, nếu không phải sợ cây cung của Lý Quảng thì sẽ lập tức ra tay giết người","bridge":true,"khoang":"@c1589"},{"mucCt":"vua","text":"Nhận ra Vương Lâm muốn lấy lực lượng hai cung hủy diệt viễn cổ tiên vực giới ngoại, gọi Vương Lâm là “điên cuồng”. Sắc mặt đại biến, bay vào tinh không.","anchor":"Hắn không ngờ muốn lấy lực lượng hai cung kia hủy diệt viễn cổ tiên vực của giới ngoại ta","bridge":true,"khoang":"@c1593"},{"mucCt":"vua","text":"Ở cách ngàn vạn dặm cảm nhận Vương Lâm bắn tên, vui mừng vì đánh giá Vương Lâm chỉ còn lực lượng hai cung và đã lãng phí hết. Lập tức phong ấn toàn bộ Thái Cổ Tinh Thần chỉ ngăn ra không ngăn vào, rồi lao đến chỗ Vương Lâm với sát khí nồng đậm.","anchor":"Ta tính hắn chỉ còn lực lượng bắn hai cung, giờ đã lãng phí một lần, còn một lần nữa thì hôm nay hắn hẳn phải chết","bridge":true,"khoang":"@c1594"},{"chuong":"@c1595","importance":"normal","mucCt":"ky","tieuDe":"Xuất thủ lần thứ sáu — chưởng ấn huyền kiếp","text":"Chờ đúng thời cơ Vương Lâm bắn xong hai mũi tên hết lực lượng huyết mạch tiên nhân, tu vi huyền kiếp bạo phát xuất hiện trong tinh vực. Hồi tưởng toàn bộ quá khứ: ba lần chật vật (bị đạo nhân bảy màu bắt bái sư, thua Chiến Không Liệt tại Thái Cổ Tinh Thần, bị trọng thương khi tìm mũi tên Lý Quảng) và năm lần đối đầu Vương Lâm đều thất bại hoặc ngoài ý muốn. Tự nhắc lại thân phận nô tài người điên, ngoài nhìn vào là môn hạ vương hầu, ở giới ngoại có Trường Tôn hội được vô số tộc lạc kính sợ. Xác định Vương Lâm chỉ còn lực lượng bắn hai mũi tên và cả hai đã bắn. Không nói một câu, trực tiếp đánh chưởng ấn trăm trượng về phía Vương Lâm. Nội tâm mơ hồ lo lắng dù miệng tự trấn an, chính thức coi Vương Lâm là khắc tinh sau năm lần thất bại.","anchor":"Vương Lâm giống như một cái dầm đâm thật sâu vào trong lòng Chưởng Tôn"},{"importance":"normal","mucCt":"ky","chuong":"@c1596","tieuDe":"Bị xuyên thân, đạo tâm sụp đổ bỏ trốn","text":"Tung chưởng ấn huyền kiếp liên tục đánh Vương Lâm, xác định đối phương chỉ bắn được hai tên cung Lý Quảng nên tự tin tiến tới cùng Thất Phi, Diệu Âm Đạo Tôn, Cửu Thiên Ma Tôn vây sát. Khi thấy Vương Lâm giương cung lần ba, đạo tâm bị rung chuyển dữ dội, kế hoạch hoàn toàn sụp đổ. Phát điên tung chưởng ấn, biến hóa giếng khổng lồ dung nạp tinh không, mặt trời đỏ đậm chứa quy tắc thái sơ, bức ra cốt châu tỏa bạch cốt khí tức tăng tu vi mấy lần quyết cược. Bị mũi tên xuyên thân, tan xác nhưng ngưng tụ sống lại, hoảng sợ chưa từng thấy, điên cuồng bỏ trốn không quay đầu.","anchor":"Không chút do dự, giống như ba năm trước, Chưởng Tôn điên cuồng bỏ trốn, không quay đầu một lần"},{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra đệ nhất phi qua ấn quyết","text":"Đang định bỏ chạy khi ánh sáng bảy màu hiện ra, lộ vẻ khổ sở. Nhận ra ấn quyết Thái Ngọc Thất Thủ Ấn từ ngọc thủ trong hắc động, kinh hãi xác nhận biết thân phận chủ nhân bàn tay.","anchor":"Hoá ra là nàng!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1600","tieuDe":"","text":"Được nhắc: bị đạo nhân bảy màu thu phục làm sai vặt, chiếm cứ giới ngoại.","anchor":"cũng thu phục gã sai vặt Chưởng Tôn, chiếm cứ giới ngoại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Phong ấn giết Chiến Tinh Dã lấy chiến hồn bằng thần thông Thiên Địa Thái Sơ, tiết lộ Thiên Đạo Kế","chuong":"@c1134"},{"text":"Luyện 108 cây Thất Thải Thần Không Đinh từ thiên thạch thần bí, liên thủ với người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới","chuong":"@c1206"},{"text":"Phát lệnh tàn sát Phong Giới tuân ý chỉ Viễn Cổ Tiên Vực, triển khai trận chiến quy mô tinh vực","chuong":"@c1413"},{"text":"Hiện thân tách huyết mạch tiên nhân Vương Lâm, tiết lộ toàn bộ nơi sát kiếp là Tĩnh Trung Lao Nguyệt do mình bày bố","chuong":"@c1491"},{"text":"Bái kiến sư tôn đạo nhân bảy màu, lộ ra giao kèo với chủ nhân bí ẩn và thân phận bị thu phục làm sai vặt chiếm cứ giới ngoại","chuong":"@c1573"},{"text":"Bị Vương Lâm xuyên thân bằng mũi tên thứ ba ngoài dự liệu, đạo tâm sụp đổ bỏ trốn, nhận ra ấn quyết đệ nhất phi mà lâm vào tuyệt cảnh","chuong":"@c1596"}]},"nguon":["@c1580","@c1582","@c1589","@c1593","@c1594","@c1595","@c1596","@c1597","@c1598","@c1600"],"canhGioiCaoNhat":"Huyền Kiếp","vaiTro":"Lão tổ tông Nguyệt Tộc bước thứ ba — Chưởng Tôn Thái Cổ Tinh Thần, kẻ thù chính của Vương Lâm","tinhCach":"Mưu tính thâm sâu, bày bố Thiên Đạo Kế và mai phục Thất Thải Giới xuyên suốt vạn năm; tàn nhẫn quyết đoán, phong ấn giết Chiến Tinh Dã đoạt chiến hồn không chút do dự; giỏi dùng lợi ích mua chuộc người khác ra tay; ngoài mạnh trong yếu, hoảng loạn sợ hãi trước tồn tại bậc cao hơn như U Minh Thú và c","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, cha của Thu Dao và lão tổ Phù Văn tộc, bị đạo nhân bảy màu — sư tôn — thu phục làm sai vặt chiếm cứ giới ngoại, sở hữu hai luồng bản nguyên đại thành nhập đạo và chỉ vượt qua ba lần huyền kiếp. Từng luyện 108 cây Thất Thải Thần Không Đinh chuyên giết tu sĩ bước thứ ba, liên thủ với người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới gần tử vong, bày mưu Thiên Đạo Kế xuyên suốt nhiều đời, phát lệnh tàn sát Phong Giới tuân ý chỉ Viễn Cổ Tiên Vực. Trong nhiều lần đối đầu Vương Lâm, liên tiếp bị đánh l"},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰眉","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Ở trong giới nội cùng nữ tử áo hồng, thấp thỏm lo lắng cho Vương Lâm.","anchor":"bên trong giới nội, Mộc Băng Mi và nữ tử áo hồng kia đang thấp thỏm"},{"importance":"bridge","mucCt":"vua","chuong":"@c1582","text":"Ngày cuối năm thứ hai tới bên cạnh Vương Lâm, bình thản ngồi xuống không nói gì, gật đầu chào Lý Thiến Mai rồi nhắm mắt.","anchor":"Mộc Băng Mi đi tới bên cạnh Vương Lâm. Nàng không có nói bất cứ điều gì mà chỉ bình thản ngồi bên cạnh hắn"},{"chuong":"@c1583","importance":"bridge","tieuDe":"Chứng kiến Vương Lâm tiếp nhận Lý Thiến Mai","text":"Chứng kiến Vương Lâm và Lý Thiến Mai đoạn tuyệt rồi tiếp nhận, mi tâm mơ hồ đau đớn dù cho rằng mình không có tư cách khuyên can.","anchor":"Nhìn phụ thân của con trai mình và một người phụ nữ khác đoạn tuyệt, chuyện này không ngờ lại khiến mi tâm của Mộc Băng Mi mơ hồ đau đớn"},{"mucCt":"ky","text":"Ở lại trong Vô Danh Chuyển Luân trận cùng Vương Lâm suốt gần một năm, muốn mở miệng nói chuyện nhưng Vương Lâm nhắm mắt tham ngộ thuật Tê Thiên nên đành nuốt lời. Khi chỉ còn một tháng cuối, nàng nói câu duy nhất trong cả năm — Bảo trọng — rồi xoay người về Côn Hư. Tâm trạng cô độc, hâm mộ Lý Thiến Mai có phụ thân, Lý Mộ Uyển có Vương Lâm, còn nàng không gia đình, không sư tôn, người quen đều đã chết, chỉ còn Vương Bình nhưng Bình nhi hận nàng.","anchor":"Đây là câu nói đầu tiên trong một năm qua của nàng, cũng là câu nói cuối cùng.","bridge":true,"khoang":"@c1584"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cứu Vương Lâm cận tử trước Thiên Vận Tử, tuyên bố mọi thần thông và nguyên lực Côn Hư Tinh vực đều nằm trong tay nàng","chuong":"@c1010"},{"text":"Bị Thác Sâm đánh tan thân thể, nguyên thần trọng thương, Côn Hư cảnh bị hủy diệt hoàn toàn, lưu lạc ẩn tu dưới danh tính Liễu Mi tại Vân Hải tinh vực","chuong":"@c1147"},{"text":"Tái ngộ Vương Lâm dưới ánh trăng, xác nhận danh tính Liễu Mi, đạo tâm viên mãn rồi tự nguyện từ biệt","chuong":"@c1196"},{"text":"Được Vương Lâm dùng thần niệm phủ khắp thiên địa phong làm tông chủ Thần Tông, chỉ huy bày binh bố trận tạo phòng tuyến trong đại chiến giới nội — giới ngoại","chuong":"@c1422"},{"text":"Lặng lẽ đứng dưới pho tượng Vương Lâm ngày đêm, hai giọt nước mắt rơi rồi yên lặng rời đi","chuong":"@c1494"},{"text":"Trong đại chiến giới ngoại, tin Vương Lâm còn sống, được hắn bảo vệ, sau đó ở lại bên hắn trong Vô Danh Chuyển Luân trận","chuong":"@c1561"}]},"nguon":["@c1580","@c1581","@c1582","@c1583","@c1584"],"vaiTro":"Côn Hư Thánh Nữ — chủ nhân Côn Hư Tinh vực, mẹ Vương Bình, tông chủ Thần Tông","tinhCach":"Lạnh lùng quyền uy nhưng ẩn chứa tình cảm sâu nặng với Vương Lâm và con; giằng xé giữa tình thân và đạo tâm, chịu đựng cô độc; bất khuất trước cường địch, không khuất phục uy hiếp; kiên định chấp niệm, lặng lẽ hy sinh không đòi hỏi đáp trả","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, từng nắm trọn thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực, đồng thời là mẹ của Vương Bình — người con chung với Vương Lâm. Sau khi cứu Vương Lâm khỏi cận tử rồi bị hắn lạnh lùng cự tuyệt, nàng lặng lẽ từ biệt; về sau bị Thác Sâm đánh tan thân thể, Côn Hư cảnh bị hủy diệt hoàn toàn, nàng lưu lạc đến Vân Hải tinh vực ẩn tu dưới danh tính Liễu Mi, tái ngộ Vương Lâm rồi lại từ biệt, bị Thần Tông giam cầm nhiều năm. Cuối cùng được Vương Lâm phong làm tông chủ Thần Tông, nàng chỉ huy phòng tuyến trong cuộc chiến giới nội — giới ngoại, lặng lẽ đứng bên hắn"},{"id":"hong-diep","name":"Hồng Điệp","cn":"红蝶","aliases":["Phấn y nữ tử","nữ tử áo hồng"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Ở trong giới nội thấp thỏm cùng Mộc Băng Mi; sau khi Tây Tử Phượng rời đi, nàng ở bên cạnh Vương Lâm trên mặt đất.","anchor":"Trên mặt đất, lúc này bên cạnh Vương Lâm là nữ tử áo hồng"},{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Phát hiện mối liên hệ Thanh Thủy — đại nho đặt tên","text":"Ngày cuối năm thứ hai từ biệt Vương Lâm để trở về chỗ Mộc Băng Mi. Trước khi đi, tiết lộ sư tôn năm xưa từng gặp một đại nho họ Vương, người chỉ điểm trận pháp cho sư tôn và đặt tên cho nàng là Hồng Điệp. Hỏi Vương Lâm về Thanh Thủy có thân nhân không. Nghe Vương Lâm kể nữ nhi duy nhất của Thanh Thủy đã luân hồi, trên vai trái có thai ký màu hồng không bao giờ tiêu tán, nàng thân thể lảo đảo, sắc mặt tái nhợt, nói cảm tạ rồi hóa cầu vồng lao về La Thiên với tốc độ nhanh nhất muốn gặp Thanh Thủy.","anchor":"Sư tôn từng nói năm đó bà gặp một đại nho họ Vương, khi đó ta vốn không thể sống sót"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Đứng bên cạnh Thanh Thủy, phụ tử đã nhận nhau.","anchor":"đứng bên cạnh Thanh Thủy chính là Hồng Điệp. Phụ tử hai người hiển nhiên đã nhận nhau"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Kính nể, có tình cảm không rõ ràng; từng giao chiến ở Vũ Tiên Giới, được Vương Lâm giải thoát ở Chu Tước mạc","ghiChu":"Xác nhận danh tính, hàn huyên @c1581"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Sở hữu Thiên Tiên Ngũ Linh thể, tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn","chuong":"@c0246"},{"text":"Bị Vương Lâm chém đứt cánh tay phải, sau đó từ chối dùng Đông Hải Chi Linh phục hồi để giữ ý chí","chuong":"@c0317"},{"text":"Lĩnh ngộ Tuyệt Tình ý cảnh trong đại chiến nhưng bại trước Sinh Tử Luân Hồi của Vương Lâm","chuong":"@c0339"},{"text":"Bị Kiền Phong đoạt tuyệt tình ý cảnh cùng tứ linh, biến thành con rối trống rỗng đổi tên Tuyệt Tình","chuong":"@c0340"},{"text":"Chết dưới chiến phủ Vương Lâm — không chống cự, không né tránh, mỉm cười kiêu hãnh, thân thể nứt vỡ","chuong":"@c0428"},{"text":"Hồn phách được bảo tồn nhờ Hồn Truyền Tống Trận, tái sinh thành trẻ sơ sinh tại Tuyết Vực, được Vương Lâm đặt lại tên Hồng Điệp","chuong":"@c1512"}]},"nguon":["@c1580","@c1581","@c1582","@c1621"],"vaiTro":"Thiên chi kiêu nữ Tuyết Vực — đối thủ định mệnh của Vương Lâm","tinhCach":"Kiêu hãnh bất khuất, giữ khí tiết và tôn nghiêm đến tận lúc chết; hiếu chiến cố chấp, nhiều lần chủ động khiêu chiến Vương Lâm dù biết bất lợi; tàn nhẫn quyết đoán, sẵn sàng hy sinh pháp bảo và Anh Hài để phát động tuyệt chiêu; cương liệt trọng tôn nghiêm, từ chối phục hồi cánh tay cụt để giữ ý chí","blurb":"Hồng Điệp là nữ tu thiên tài của Tuyết Vực quốc, sở hữu Thiên Tiên Ngũ Linh thể với tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn nghiêm trọng. Xuyên suốt nhiều lần giao tranh với Vương Lâm — từ đánh lén trên sa mạc, đấu pháp tại tế đàn đến đại chiến quyết tử tại Chu Tước quốc — nàng lĩnh ngộ Tuyệt Tình ý cảnh nhưng vẫn bại trước Sinh Tử Luân Hồi của đối thủ, rồi bị Kiền Phong đoạt ý cảnh cùng tứ linh, biến thành con rối trống rỗng mang tên Tuyệt Tình. Cuối cùng nàng chết dưới chiến phủ của Vương Lâm trong tư thế không chống cự, mỉm cười kiêu hãnh, nhưn"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1582","text":"Ngồi gần Vương Lâm, khi nghe hắn nói đã có thê tử thì cúi đầu che giấu thần sắc ảm đạm.","anchor":"vị trí hơi xảo diệu, khá gần Vương Lâm mơ hồ giống như là một người vợ cạnh chồng"},{"chuong":"@c1583","importance":"normal","tieuDe":"Được Vương Lâm tiếp nhận","text":"Lo lắng theo dõi phụ thân chiến đấu ba ngày, rơi nước mắt khi hiểu được hy sinh của cha. Muốn cùng cha về nhà không đi đâu nữa. Xin Vương Lâm tặng lại bức tranh sơn thủy năm xưa, nói lời đoạn tuyệt phân biệt ân không phải tình. Cuối cùng được Vương Lâm hủy tranh tiếp nhận, vùi đầu khóc ròng trong lòng hắn.","anchor":"Vương Lâm, ân, không phải là tình"},{"importance":"normal","mucCt":"vua","chuong":"@c1584","tieuDe":"Cùng phụ thân trở về Lam Ti tộc","text":"Cùng phụ thân Lam Mộng Đạo Tôn mang ngũ phi trở về Lam Ti tộc, dự định lần sau mang cả tộc vào giới nội lập tân tộc. Ra đi vui vẻ, thỉnh thoảng quay đầu nhìn Vương Lâm với ánh mắt ôn nhu, khẳng định dù có chết cũng không hối hận về lựa chọn của mình.","anchor":"Nam tử này chính là người nàng lựa chọn, trước kia nàng không hối hận"},{"chuong":"@c1621","importance":"normal","mucCt":"gon","tieuDe":"Bế quan lĩnh ngộ bổn nguyên phụ thân","text":"Đang bế quan trong khu Lam Ti tộc phía tây tiên giới, lĩnh ngộ bổn nguyên của Lam Mộng Đạo Tôn. Vương Lâm ghé qua nhưng thở phào vì không phải gặp mặt.","anchor":"Bản thân hắn cũng chưa hiểu được đối với Lý Thiến Mai hắn là ân hay tình"}],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"cha-me","quanHe":"Phụ thân","ghiChu":"Đang bế quan lĩnh ngộ bổn nguyên của hắn"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Ân nhân / mối quan hệ mơ hồ","ghiChu":"Nàng nói ân không phải là tình, Vương Lâm chưa rõ đối với nàng là ân hay tình"}],"tuViMoc":[],"diem":[{"text":"Thiên tài tu luyện: 5 tuổi nhập đạo, 7 tuổi Trúc Cơ, hơn 1200 năm đạt Toái Niết hậu kỳ, được tôn là thiên chi kiêu nữ Vân Hải tinh vực","chuong":"@c1090"},{"text":"Hỏi đạo Vương Lâm tại Bồng Lai, từ luận thiên đạo dần phát sinh tình cảm, chấn động trước tâm trí và thực lực của hắn","chuong":"@c1096"},{"text":"Bất chấp quân lệnh đào ngũ khỏi chiến trường Yêu Tông sau trăm năm chém giết mãnh thú, phi tinh trảm nguyệt xuyên tinh vực tới đại hội Vô Cực Tông tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ, cô độc rời tông môn phóng vào tinh không không hối tiếc","chuong":"@c1200"},{"text":"Ẩn thân mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, hy sinh máu tươi và tinh huyết chăm sóc tượng đá đến kiệt quệ sinh cơ","chuong":"@c1214"},{"text":"Dần khôi phục ký ức và được Vương Lâm tiếp nhận, cùng phụ thân Lam Mộng Đạo Tôn trở về Lam Ti tộc bế quan lĩnh ngộ bổn nguyên","chuong":"@c1621"}]},"nguon":["@c1581","@c1582","@c1583","@c1584","@c1621"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","cn":"李芊梅","gioiTinh":"nu","vaiTro":"Nữ tu sĩ truyền kỳ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ tình cảm của Vương Lâm","tinhCach":"Thiên phú tu luyện phi phàm, tốc độ đột phá cảnh giới hiếm có; ham hỏi đạo, trọng bản tâm, chủ động tìm người luận đạo; nặng tình kiên định, dám bất chấp sư mệnh và quân lệnh vì lời hứa; kiên nghị cô độc, một mình gánh chịu hậu quả không hối tiếc","blurb":"Lý Thiến Mai (bí danh Lý Oánh Chi) là nữ tu sĩ tóc xanh lam truyền kỳ của Phá Thiên Tông thuộc Vân Hải tinh vực cấp chín, khởi tu từ năm tuổi và sau hơn 1200 năm đạt Toái Niết hậu kỳ. Trên hành trình hỏi đạo, nàng kết giao và dần sinh tình với Vương Lâm, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp quân lệnh đào ngũ, phi tinh trảm nguyệt xuyên tinh vực đến đại hội Vô Cực Tông tìm hắn, vì đó mà bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ. Nàng ẩn thân suốt mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, hy sinh máu tươi và tinh huyết chăm sóc tượng đá đến kiệt qu"},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam Ti Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền đỉnh phong (@c1582)","trangThai":"song","blurb":"Lam Mộng Đạo Tôn là một trong ngũ đại tôn giả của Thái Cổ Tinh Thần, tu vi từ Không Huyền đỉnh phong hai đạo bổn nguyên dung hợp tiến tới Không Huyền đại viên mãn — đứng đầu Thái Cổ Ngũ Tôn — rồi đạt Không Huyền hậu kỳ viên mãn đỉnh phong; vốn là người sinh ra trong giới nội. Ông chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thụ ba thức thần thông — Đạo thuật Dung, Quang Ảnh Thuẫn và Phiên Thiên — rồi nhiều lần dõi theo, can thiệp giúp đỡ Vương Lâm giữa các biến cố lớn trên Đại Đế tinh, cho đến khi vì ước định với Chưởng Tôn mà buộc phải xuất thủ chặn Vương Lâm, ân đoạn ngh","vaiTro":"Ngũ đại tôn giả Thái Cổ Tinh Thần — lãnh đạo Lam Ti Tộc, cư ngụ tại Lam Sơn","tinhCach":"U buồn thâm trầm, thường độc tọa gảy cổ cầm; trọng tình nghĩa với thê tử và nữ nhi, sẵn sàng che chở người thân; điềm tĩnh cân nhắc trước mỗi biến cố, hành sự thận trọng; nội tâm phức tạp, có thể vì ước định mà ân đoạn nghĩa tuyệt dù bất đắc dĩ","tabs":{"diem":[{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống không thành, truyền ba thức thần thông: Đạo thuật Dung, Quang Ảnh Thuẫn và Phiên Thiên","chuong":"@c1243"},{"text":"Vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, ân đoạn nghĩa tuyệt","chuong":"@c1492"},{"text":"Tuyên bố đứng về phía Vương Lâm, tiết lộ bản thân là người sinh ra trong giới nội, kể bí mật ngũ phi","chuong":"@c1582"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày, tự xưng Thái Cổ Ngũ Tôn","chuong":"@c1583"},{"text":"Tu vi đạt Không Huyền đại viên mãn, đứng đầu Thái Cổ Ngũ Tôn","chuong":"@c1435"},{"text":"Lộ sát khí hộ vệ Vương Lâm, coi hắn là người thân, truy sát kẻ thù","chuong":"@c1624"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Tuyên bố đứng về phía Vương Lâm — kể bí mật ngũ phi","text":"Đề nghị Lý Thiến Mai làm thê tử thứ hai của Vương Lâm, không ép. Tiết lộ bản thân là người sinh ra trong giới nội thứ hai sau Chiến lão quỷ, tu vi Không Huyền đỉnh phong, sớm có thể bước vào huyền kiếp. Kể rằng thê tử bị ngũ phi (một trong bát phi Tiên Tôn, đang bị phong ấn trong Thiên Hoàng Lô của Vương Lâm) đoạt xá, hồn phách dung hợp hoàn toàn không thể tách, một chết cả hai chết. Chưởng Tôn từng tới hứa giúp tách hồn phách nhưng Lam Mộng biết điều đó bất khả. Tuyên bố không đánh Vương Lâm nữa, sẵn lòng liên thủ chống Đạo nhân Bảy Màu và Chiến lão quỷ. Chủ động bước ra chặn ba kẻ địch Diệu Âm, Cửu Thiên, Đại Hoang, tung khí tức Không Huyền đỉnh phong khiến tinh không run rẩy.","anchor":"Hồn phách của thê tử ta sớm đã hoàn toàn dung hợp với ngũ phi. Các nàng căn bản là không thể chia lìa nữa"},{"chuong":"@c1583","importance":"major","tieuDe":"Một đánh ba và tự xưng thái cổ ngũ tôn","text":"Lam Mộng Đạo Tôn một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày. Diệu Âm trọng thương rớt xuống Không Linh, Cửu Thiên mất hương hỏa giới tâm thần tổn thương, Đại Hoang bỏ chạy sống không quá mười năm. Tự xưng là một trong thái cổ ngũ tôn, sinh ra từ thái cổ, khẳng định mọi việc đều vì con gái, không tham gia cuộc chiến giới nội giới ngoại. Đặt điều kiện cuối cho Vương Lâm: nếu Lý Mộ Uyển sống lại thì kết huynh muội với Thiến Mai, nếu không thì phải thành đạo lữ. Thấy con gái hết hy vọng, từ tức giận hóa bi ai.","anchor":"Ta chỉ muốn bảo vệ cho Lam Ti tộc, dù ai là kẻ thắng cuối cùng thì cũng chẳng liên quan tới ta"},{"mucCt":"vua","text":"Mang Lý Thiến Mai và ngũ phi trở về Lam Ti tộc, dự định lần sau mang cả tộc vào giới nội lập tân tộc. Dù bị thương nhưng tu vi Không Huyền đỉnh phong vẫn đủ bảo đảm an toàn trên đường, hắn có thể dẫn động huyền kiếp khiến Chưởng Tôn cũng phải tránh.","anchor":"tu vi Không Huyền đỉnh phong của Lam Mộng Đạo Tôn cũng sẽ không bị bức quá mức","bridge":true,"khoang":"@c1584"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Ngồi trong nhà tranh phía tây tiên giới khu Lam Ti tộc, cho Lý Thiến Mai bế quan lĩnh ngộ bổn nguyên của hắn vì tu vi nàng chưa đủ.","anchor":"Bộ lạc này là Lam Ti tộc"},{"mucCt":"ky","text":"Xuất hiện trên tuyết sơn trong vùng lam quang. Giải thích Luân Hồi nhất thể thuật là thần thông của Thất Thải Tiên Tôn (chưa tu thành), qua vô số luân hồi tạo phân thân cắn nuốt nhau, kẻ dung hợp phân thân sẽ bị trộm bổn nguyên và tu vi. Đánh giá Vương Lâm nắm chắc bốn phần đã mắc thuật, nhưng chỉ ra nếu giết được đối phương thì ngược lại sẽ thôn phệ tăng tu vi, đây cũng là cơ duyên. Dùng lam quang đặt lên mi tâm Vương Lâm, giúp hắn nhìn thấy bổn tôn Thiên Vận Tử trên thiên thạch sâu trong Triệu Hà tinh vực.","anchor":"Thuật này ta nghe được từ chưởng tôn","bridge":true,"khoang":"@c1623"},{"chuong":"@c1624","importance":"normal","mucCt":"vua","tieuDe":"Lộ sát khí hộ Vương Lâm, rời đỉnh tuyết sơn truy sát","text":"Trấn an Thanh Lâm, nói Thiên Vận Tử sống không bao lâu. Lộ sát khí vì bao che Vương Lâm, coi hắn là người thân, vung tay áo hóa lam quang rời đỉnh tuyết sơn đi truy sát.","anchor":"có dũng khí thế mới đáng là con rể Lam Mộng Đạo Tôn ta"},{"mucCt":"vua","text":"Cùng Thanh Lâm, Hồng Sam Tử đã có mặt sẵn chứng kiến giao chiến trước đó. Khoanh chân ngồi trước bổn tôn Vương Lâm hộ pháp, khẳng định nếu tìm được bổn tôn Thiên Vận Tử thì dù tu vi cao đến đâu cũng trốn không thoát.","anchor":"Có lão phu ở đây, ngươi có thể yên tâm được rồi","bridge":true,"khoang":"@c1626"},{"importance":"bridge","mucCt":"gon","chuong":"@c1628","tieuDe":"Khống chế phân thân Vương Lâm","text":"Được Vương Lâm nhờ cùng Thanh Lâm và Hồng Sam Tử khống chế phân thân Vương Lâm tranh thủ thời gian.","anchor":"Ba vị tiền bối không cần đi cùng ta"},{"mucCt":"vua","text":"Bình tĩnh đứng bên cạnh phân thân Vương Lâm trong lam quang chờ đợi kết quả. Khi Thiên Vận Tử hoàn thành thức tỉnh toan rời đi, chặn trước mặt hắn tuyên bố đã đồng ý với Vương Lâm không cho Thiên Vận Tử rời khỏi.","anchor":"Ta đã đồng ý với hắn không cho ngươi rời khỏi nơi này.","bridge":true,"khoang":"@c1629"},{"mucCt":"vua","text":"Ra tay cản Thiên Vận Tử nhưng bị đánh lui mấy bước. Muốn đuổi theo 2999 hồn phách tản ra nhưng bị Vương Lâm ngăn. Được Vương Lâm nhờ chuyển lời cho Thanh Thủy sư huynh.","anchor":"Lam Mộng Đạo Tôn biến sắc, thân thể bịch bịch bịch lui lại phía sau liền mấy bước","bridge":true,"khoang":"@c1630"}],"tuViMoc":[{"chuong":"@c1582","canhGioi":"Không Huyền đỉnh phong","text":"Tự tiết lộ tu vi Không Huyền đỉnh phong, sớm có thể bước vào huyền kiếp độ kiếp, nếu vượt chín lần thì đạt Không Kiếp. Nếu không vì đạo tâm bất viên mãn thì thậm chí Chưởng Tôn cũng không địch nổi.","importance":"major"}],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"cha-me","quanHe":"Con gái","ghiChu":"Dẫn tới trước Vương Lâm @c1581"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đề nghị làm con rể, sẵn sàng liên minh","ghiChu":"@c1581"},{"ten":"Diệu Âm đạo tôn","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại khi lao tới tấn công Vương Lâm"},{"ten":"Cửu Thiên ma tôn","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại cùng Diệu Âm và Đại Hoang"},{"ten":"Đại Hoang Thượng Nhân","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại cùng hai người kia"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Con rể (Lý Thiến Mai chọn Vương Lâm)","ghiChu":""},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Mối đe dọa duy nhất trên đường","ghiChu":"Có thể dẫn động huyền kiếp buộc Chưởng Tôn phải tránh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1581","@c1582","@c1583","@c1584","@c1621","@c1623","@c1624","@c1626","@c1628","@c1629","@c1630"]},{"id":"chu-vu-thai","name":"Chu Vũ Thái","tabs":{"kinhLich":[]},"nguon":["@c1581"]},{"id":"kien-phong","name":"Kiền Phong","tabs":{"kinhLich":[]},"nguon":["@c1581"]},{"id":"thanh-thuy","name":"Thanh Thủy","tabs":{"kinhLich":[{"mucCt":"vua","text":"Được Vương Lâm kể cho Hồng Điệp nghe: khổ mệnh, toàn tộc bị diệt, thê tử chết, chỉ còn nữ nhi duy nhất đã luân hồi, trên vai trái có thai ký màu hồng không bao giờ tiêu tán. Hồng Điệp nghe xong lảo đảo tái nhợt, lao về La Thiên muốn gặp Thanh Thủy.","anchor":"Sư huynh chỉ là một người khổ mệnh.hắn thủa nhỏ toàn tộc bị diệt vong","bridge":true,"khoang":"@c1582"},{"mucCt":"vua","text":"Phẫn nộ vì tiên giới bị xâm nhập, ngưng tụ sát lục bổn nguyên ngoài thân. Không bị lực lượng huyết mạch tiên nhân ảnh hưởng, lao xuyên lốc vàng tiến vào tiên giới phản kích.","anchor":"Chỉ có Thanh Thủy là không chịu chút ảnh hưởng bởi lực lượng huyết mạch này","bridge":true,"khoang":"@c1593"},{"importance":"major","mucCt":"vua","chuong":"@c1600","tieuDe":"Bị nhận ra là thất phách Thất Thải Thiên Tôn","text":"Bị Vương Lâm nhận ra chính là một trong thất phách của Thất Thải Thiên Tôn, giải thích cuộc đời thê thảm, đạt sát lục bổn nguyên, vừa vào bước thứ ba đã cực mạnh. Đây là suy luận của Vương Lâm dựa trên bí mật ba hồn bảy phách vừa được tiết lộ.","anchor":"Thanh Thuỷ sư huynh chính là một trong thất phách của Thất Thải Thiên Tôn"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Nghênh đón Vương Lâm, đứng cùng Hồng Điệp — phụ tử hai người đã nhận nhau.","anchor":"đứng bên cạnh Thanh Thủy chính là Hồng Điệp. Phụ tử hai người hiển nhiên đã nhận nhau"},{"chuong":"@c1630","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm nhắn đợi","text":"Được Vương Lâm nhờ Lam Mộng Đạo Tôn nhắn mấy ngày tới đừng ra ngoài, chờ Vương Lâm trở về vì cần hắn giúp đỡ.","anchor":"Thay mặt ta chuyển lời cho Thanh Thủy sư huynh, mấy ngày này tốt nhất là không nên ra ngoài, chờ ta trở về còn cần hắn giúp đỡ"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lai lịch được tiết lộ: vốn là thái tử Thanh Thủy Quốc, sau khi cố quốc bị diệt vong đã bảy ngày đẫm máu báo thù rồi phi thăng Tiên giới, trở thành sát tinh khét tiếng Lôi Giới","chuong":"@c0746"},{"text":"Tái xuất chiến trường với Cực Cảnh lâm thế, vây đánh Huyền Bảo thượng nhân và giao chiến trong thông đạo thân Vọng Nguyệt","chuong":"@c0874"},{"text":"Được Vương Lâm giải trừ toàn bộ mười cây cọc phong ấn, khôi phục tu vi và dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá không môn, đột phá Không Niết Sơ Kỳ","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm, thay mặt bế quan trấn giữ đài chiến Vân Hải tại Chu Tước Tinh, sau bị Hư Thần Thiên Tôn trọng thương gần chết","chuong":"@c1494"},{"text":"Bị Vương Lâm nhận ra chính là thất phách của Thất Thải Thiên Tôn, giải thích toàn bộ cuộc đời thê thảm và nguồn gốc Cực Cảnh","chuong":"@c1600"},{"text":"Trọng thương cận tử nhưng bùng phát sát lục bảo vệ nữ nhi lưu lạc, sau đó được Vương Lâm cứu chữa khỏi tử vong","chuong":"@c1562"}]},"nguon":["@c1582","@c1592","@c1593","@c1600","@c1621","@c1630"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Tiên quân Cực Cảnh — sư huynh đồng môn Bạch Phàm, bảo hộ và truyền thừa cho Vương Lâm","tinhCach":"trọng tình nghĩa đồng môn, nguyện xả thân bảo hộ truyền nhân; sát phạt quyết liệt, không nương tay với kẻ địch; thận trọng đa nghi, không dễ tin người; biết tự tỉnh sau sát nghiệp, từng tự phong ấn vì hối hận","blurb":"Thanh Thủy Tiên Quân vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, sau khi cố quốc bị diệt vong đã bảy ngày đẫm máu báo thù rồi phi thăng lên Tiên giới, trở thành sát tinh khét tiếng tại Lôi Giới; về sau tỉnh ngộ trước sát nghiệp mà tự phong ấn tu vi, sau đó được Vương Lâm giải trừ toàn bộ phong ấn và đột phá Không Niết Sơ Kỳ. Với tư cách sư huynh cùng sư môn Bạch Phàm, ông nhiều lần hiện thân bảo hộ Vương Lâm, truyền thừa các tiên thuật Hoán Vũ, Tát Đậu Thành Binh, giao chiến Huyết Thần Tử và Huyền Bảo thượng nhân, từng hóa thân thay Vương Lâm bế quan trấn giữ đài chiến. Thân p"},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Diệu Âm Đạo Tôn là một trong Thái Cổ Ngũ Tôn, bản thể là lão già tóc bạc ẩn tu dưới đáy hải dương ở tu chân tinh trung tâm, từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa. Y lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết lên bước thứ ba, phái phân thân thiếu niên tham gia tranh đoạt tại cổ mộ và giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc để cướp tứ phẩm đạo linh. Sau đại chiến dung hợp âm–thủy, y bị trọng thương rồi bị Đại Hoang Thượng Nhân đoạt xá; mấy vạn năm sau ẩn dưới đáy tử hải ôm mối oán hận, mở mắt trở lại khi khe cổ mộ tái xuất, nhưng cuối c","vaiTro":"Cường giả cổ tu — một trong Thái Cổ Ngũ Tôn, bản thể ẩn tu dưới đáy hải dương","tinhCach":"Nhàn nhã phóng túng, thường nằm mây ăn đào quan sát thế cục; tham lam dã tâm, lộ rõ tham niệm khi thấy bảo vật; âm trầm khó lường, bề ngoài thiếu niên xinh xắn nhưng bản thể là lão già tóc bạc tu luyện dưới đáy hải dương","tabs":{"diem":[{"text":"Từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa","chuong":"@c1193"},{"text":"Bản thể là lão già tóc bạc tu luyện dưới đáy hải dương ở tu chân tinh trung tâm, phái phân thân thiếu niên đi tranh đoạt","chuong":"@c1325"},{"text":"Lấy âm bổn nguyên đại thành phá cửa ải Không Niết thành bước thứ ba, dung hợp âm–thủy đại chiến với Đại Hoang Lão Độc rồi bị trọng thương gần chết","chuong":"@c1365"},{"text":"Bị Đại Hoang Thượng Nhân đoạt xá sau khi trọng thương, bắt vào biển sương mù","chuong":"@c1366"},{"text":"Mấy vạn năm ẩn dưới đáy tử hải, mở mắt trở lại khi khe cổ mộ tái xuất, ôm oán hận Đại Hoang và Vương Lâm","chuong":"@c1378"},{"text":"Bị Vương Lâm bắt gọn nguyên thần sau khi mũi tên cung Lý Quảng đánh nổ tung thân thể","chuong":"@c1596"}],"kinhLich":[{"mucCt":"vua","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Cửu Thiên ma tôn và Đại Hoang Thượng Nhân mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chủ động chặn lại.","anchor":"Diệu Âm, Cửu Thiên, Đại Hoang, ba ngươi biến cho lão phu","bridge":true,"khoang":"@c1582"},{"text":"Cùng Cửu Thiên và Đại Hoang Thượng Nhân hợp lực đánh Lam Mộng Đạo Tôn ba ngày, bại trận. Trọng thương, trăm năm không thể khôi phục đỉnh phong, tu vi rớt xuống Không Linh.","anchor":"Diệu âm đ*o tôn trọng thương trăm năm không thể khôi phục tu vi đỉnh phong, rớt xuống không linh","bridge":true,"khoang":"@c1583"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Gào thét lao tới giết Vương Lâm","text":"Thương thế chưa hồi phục nhưng vẫn gào thét lao tới chỗ Vương Lâm cùng Cửu Thiên ma tôn, cười nanh ác tự tin hắn không thể sống sót.","anchor":"Có những người này muốn giết ngươi thì ta không tin ngươi có thể sống nổi"},{"importance":"normal","mucCt":"vua","chuong":"@c1596","tieuDe":"Bị bắt gọn nguyên thần","text":"Xuất hiện cùng Cửu Thiên Ma Tôn và Thất Phi vây Vương Lâm. Bị mũi tên cung Lý Quảng đánh nổ tung thân thể, nguyên thần bị Vương Lâm vung tay áo bắt gọn.","anchor":"Diệu âm đ*o Tôn và Cửu Thiên Ma Tôn cũng phun máu tươi, thân thể nổ tung, huyết nhục mơ hồ, nguyên thần đang muốn lui lại thì bị tay áo Vương Lâm vung lên, trực tiếp bắt gọn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Cửu Thiên ma tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Đại Hoang Thượng Nhân","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại khi tấn công Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583","@c1594","@c1596"],"canhGioiCaoNhat":"Không Linh"},{"id":"cuu-thien-ma-ton","name":"Cửu Thiên ma tôn","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Cửu Thiên Ma Tôn là đại năng ma đạo từng nổi tiếng vì dám lẻn vào Điên Lạc Địa, song trọng thương rút lui và lập thề không quay lại. Trong cổ mộ nhiều tầng bản đồ, hắn ngồi trên đài mộ cấp bảy thi triển đạo thuật truy sát đối thủ nhưng liên tục bị Vương Lâm áp chế — phân thân tử vong, bổn tôn hoảng sợ, cuối cùng bị nhốt lại trong cổ mộ. Sau khi được Chưởng Tôn giải cứu, hắn tiếp tục bại trận trước Lam Mộng Đạo Tôn mất hương hỏa giới, rồi lại vây đánh Vương Lâm và bị bắt gọn nguyên thần.","vaiTro":"Đại năng ma đạo — đối thủ dai dẳng của Vương Lâm trong cổ mộ và ngoại giới","tinhCach":"tự phụ thực lực, dám đơn độc xâm nhập hiểm địa; biết tiến biết lui, thề không tái phạm khi trọng thương; mưu mô toan tính, sẵn sàng kết thỏa thuận vì lợi ích; thù dai, thương thế chưa hồi phục vẫn quyết trả thù","tabs":{"diem":[{"text":"Từng âm thầm lẻn vào Điên Lạc Địa, trọng thương rút lui và thề không quay lại","chuong":"@c1284"},{"text":"Ngồi trên đài mộ cấp bảy trong bản đồ thứ tám, tự tin thi đua khi cảm nhận đối thủ cùng cấp","chuong":"@c1374"},{"text":"Toàn bộ phân thân tử vong sau khi cùng nữ tử áo hồng tấn công Vương Lâm trong vòng xoáy Cổ Yêu","chuong":"@c1377"},{"text":"Bị nhốt lại trong cổ mộ sau khi Địa Phù bị Vương Lâm thu mất","chuong":"@c1386"},{"text":"Được Chưởng Tôn giải cứu khỏi cổ mộ, nhưng bại trận trước Lam Mộng Đạo Tôn, mất hương hỏa giới và tâm thần tổn thương","chuong":"@c1583"},{"text":"Bị mũi tên cung Lý Quảng đánh nổ tung thân thể, nguyên thần bị bắt gọn","chuong":"@c1596"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1582","tieuDe":"Được giải cứu — bị Lam Mộng chặn","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Diệu Âm đạo tôn và Đại Hoang Thượng Nhân mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chặn lại, kiêng kỵ tu vi Không Huyền đỉnh phong của Lam Mộng.","anchor":"Cửu Thiên ma tôn và Đại Hoang Thượng Nhân cũng đưa mắt nhìn nhau, trong mắt đều hiện lên vẻ kiêng kỵ"},{"chuong":"@c1583","importance":"normal","tieuDe":"Bại trận mất hương hỏa giới tâm thần tổn thương","text":"Bại trận trước Lam Mộng Đạo Tôn, bị thương nhẹ hơn Diệu Âm Đạo Tôn nhưng hương hỏa giới đã bị hủy diệt, tâm thần thương tổn.","anchor":"Cửu Thiên bị thương nhẹ hơn Diệu âm đ*o tôn nhiều nhưng hương hỏa giới đã bị ta hủy diệt, bị thương tâm thần"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Muốn rút hồn Vương Lâm thiêu đốt vạn năm","text":"Thương thế chưa hồi phục nhưng vẫn lao tới chỗ Vương Lâm, muốn rút hồn hắn ra thiêu đốt vạn năm.","anchor":"Lão phu muốn rút hồn hắn ra, thiêu đốt vạn năm"},{"importance":"normal","mucCt":"vua","chuong":"@c1596","tieuDe":"Bị bắt gọn nguyên thần","text":"Xuất hiện cùng Diệu Âm Đạo Tôn và Thất Phi vây Vương Lâm. Bị mũi tên cung Lý Quảng đánh nổ tung thân thể, nguyên thần bị Vương Lâm bắt gọn.","anchor":"nguyên thần đang muốn lui lại thì bị tay áo Vương Lâm vung lên, trực tiếp bắt gọn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Diệu Âm đạo tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Đại Hoang Thượng Nhân","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583","@c1594","@c1596"]},{"id":"dai-hoang-thuong-nhan","name":"Đại Hoang Thượng Nhân","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đại Hoang thượng nhân là cường giả cảnh Không Huyền, lão giả mặc da thú trú trên một tu chân tinh khô héo. Không có phân thân sẵn và không dám suy yếu tu vi bản thể, hắn đoạt xá tu sĩ khác để phân hồn tiến vào cổ mộ, gây ra hàng loạt cuộc tranh đoạt tàn khốc — giải ấn Tam Tiên biến biển hương hỏa thành biển độc, đoạt xá thành công Diệu Âm Đạo Tôn, phân hồn bị hủy diệt khi tham lam lao tới đài mộ cấp chín. Bổn tôn bị nhốt lại trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt, về sau được Chưởng Tôn cứu ra nhưng bại trận thảm hại, bị đoán định sống không quá mười năm.","vaiTro":"Cường giả Không Huyền — kẻ đoạt xá tàn độc trong cổ mộ","tinhCach":"Tàn nhẫn bất chấp, sẵn sàng hy sinh người khác để đạt mục đích; mưu mô thâm trầm, tính toán nhiều bước nhưng hay bị phản đòn; tham lam không kiềm chế, lao vào nguy hiểm vì lợi ích trước mắt","tabs":{"diem":[{"text":"Không có phân thân, bắt tu sĩ bên ngoài sương mù để đoạt xá nhằm đưa phân hồn vào cổ mộ","chuong":"@c1345"},{"text":"Giải ấn Tam Tiên, biến biển hương hỏa thành biển độc; bổn tôn ở tinh cầu hoang dã phun máu khiến toàn tinh cầu chết","chuong":"@c1365"},{"text":"Đoạt xá thành công Diệu Âm Đạo Tôn, hóa hắc khí chui vào thất khiếu chiếm cứ thân xác","chuong":"@c1366"},{"text":"Phân hồn bị hủy diệt khi tham lam lao tới đài mộ cấp chín, bị cánh tay khổng lồ tiêu diệt","chuong":"@c1377"},{"text":"Bổn tôn bị nhốt trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt","chuong":"@c1386"},{"text":"Được Chưởng Tôn cứu khỏi cổ mộ nhưng bại trận nặng nhất, bị đoán định sống không quá mười năm","chuong":"@c1583"}],"kinhLich":[{"mucCt":"vua","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Diệu Âm đạo tôn và Cửu Thiên ma tôn mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chặn lại.","anchor":"trong ba đạo cầu vồng đó chính là ba người mà Vương Lâm quen thuộc","bridge":true,"khoang":"@c1582"},{"text":"Bại trận nặng nhất trong ba người, dùng bí thuật bỏ chạy. Lam Mộng Đạo Tôn đoán hắn sống không quá mười năm.","anchor":"Đại Hoang Thượng Nhân bị thương nặng nhất, dùng bí thuật bỏ chạy. Hắn sống không quá mười năm nữa!","bridge":true,"khoang":"@c1583"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Diệu Âm đạo tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Cửu Thiên ma tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","mucCt":"gon","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1583","importance":"normal","tieuDe":"Được Vương Lâm xác nhận là thê tử","text":"Được Vương Lâm tuyên bố vẫn là thê tử duy nhất, đợi nàng tỉnh dậy sẽ cùng thành thân.","anchor":"Uyển Nhi là thê tử của ta, đợi sau khi nàng tỉnh dậy chúng ta sẽ cùng nhau thành thân"},{"chuong":"@c1613","importance":"bridge","mucCt":"gon","text":"Được nhắc trong đoạn hồi tưởng hành trình Vương Lâm: khi hắn ôm thi thể nàng gầm thét lên trời, khi phấn đấu vì nàng.","anchor":"Khi Vương Lâm sống vì Lý Mộ Uyển, khi hắn ôm thi thể của nàng ngửa mặt lên trời gầm thét"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Vương Lâm nhớ tới nàng và cảnh trên Chu Tước Tinh năm đó, cảm thấy có lỗi với nàng nhưng giấu nỗi đau.","anchor":"Hắn càng cảm thấy mình có lỗi với Uyển nhi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị Song Tu Môn truy sát vì Thiên Ly đan, được Vương Lâm cứu; bắt đầu bốn năm đồng hành tại Tu Ma Hải, khắc gần 19.000 ngọc giản đan phương","chuong":"@c0123"},{"text":"Dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công đan dược giữa lúc mười Kết Đan kỳ công phá động phủ, thể hiện thiên phú luyện đan dưới áp lực cực hạn","chuong":"@c0127"},{"text":"Ba lần Kết Anh thất bại, tuổi thọ cạn kiệt, thân xác suy tàn dù Vương Lâm tìm mọi cách điều trị; cuối cùng thân thể hóa xương khô, nguyên anh được bức tranh Sinh Tử Luân Hồi đưa vào chuyển sinh","chuong":"@c0313"},{"text":"Sau chín mươi năm trong thân Chu Như, thức tỉnh rồi từ chối cắn nuốt hồn phách đứa trẻ, tự đẩy nguyên anh ra để cứu Chu Như — hy sinh cơ hội tái sinh","chuong":"@c0381"},{"text":"Nguyên anh bị chẩn đoán tử vong, hồi sinh bất thành nhiều lần; Vương Lâm bảo tồn gần bảy trăm năm và cầu cứu khắp nơi kể cả Lôi Tiên điện","chuong":"@c0827"},{"text":"Vương Lâm phát hiện vận mệnh nàng đã bị kẻ bí ẩn đoạt mất từ mặt trời thứ chín, phát thề thu hồi và xác nhận nàng là thê tử duy nhất","chuong":"@c1541"}]},"nguon":["@c1583","@c1613","@c1621"],"gioiTinh":"nu","vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, thiên tài luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp, sáng tạo trong chiến đấu; kiên cường chịu đựng trước suy kiệt kéo dài và cái chết cận kề; nặng tình với Vương Lâm dù duyên phận mong manh; giàu lòng trắc ẩn và tự hy sinh — từ chối cắn nuốt hồn phách Chu Như dù phải đánh đổi cơ hội tái sinh","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ có thiên phú luyện đan và trận pháp hiếm thấy, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu, hai người đồng hành bốn năm tại Tu Ma Hải và khắc sâu tình cảm. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến tuổi thọ cạn kiệt; dù Vương Lâm tìm mọi cách điều trị, thân xác nàng vẫn hóa xương khô, nguyên anh được dùng bức tranh Sinh Tử Luân Hồi đưa vào luân hồi rồi chuyển sinh thành bé gái Chu Như, nhưng sau chín mươi năm nàng thức tỉnh và tự đẩy nguyên anh ra khỏi thân thể Chu Như để cứu đứa trẻ. Nguyên anh được Vương Lâm bảo tồn gần bảy tră"},{"id":"van-thu","name":"Văn Thú","cn":"纹兽","gioiTinh":"khong-ro","trangThai":"song","nguon":["@c1584","@c1585","@c1587"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1584","tieuDe":"Gặp lại Vương Lâm trong Phong Tiên giới","text":"Bị thất lạc trong đại chiến trăm năm trước, vào Phong Tiên giới sinh tồn, dẫn đàn Văn thú hung mãnh tàn sát các đàn khác trên khắp Phong Tiên giới để giải tỏa bi ai vì tìm không thấy chủ nhân. Khi cảm nhận được khí tức Vương Lâm, hàn quang trong mắt sụp đổ, kích động điên cuồng lao về phía chủ nhân.","anchor":"Nó run rẩy, hàn quang trong mắt sụp đổ, thay thế bằng vẻ mê man cả trăm năm nay không tiêu tan!"},{"importance":"normal","mucCt":"ky","chuong":"@c1585","tieuDe":"Tiến hóa gần bước thứ ba","text":"Dẫn đầu đàn trên vạn Văn thú, kích thước trăm trượng, tu vi tiếp cận bước thứ ba chỉ còn kém một bước lột xác. Hưng phấn hội ngộ Vương Lâm, lao tới đâm vào người hắn thể hiện tình cảm chủ thú. Dẫn Vương Lâm vào vùng sâu Phong Tiên giới, hút tinh hoa từ thi thể Văn thú ngàn trượng khiến toàn thân lóe kim quang. Dẫn Vương Lâm vào bên trong cái khe, nơi chứa hàng trăm vạn trứng Văn thú, hút sạch tinh hoa bên trong trứng — đây chính là nguồn cơ duyên giúp nó tiến hóa mạnh mẽ.","anchor":"Loại biến hóa này khiến cho Vương Lâm rất ngạc nhiên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1587","text":"Đang thôn phệ trứng Văn thú trong thông đạo, sau khi Vương Lâm thu hết trứng thì hoan hỉ đi theo hắn rời đi.","anchor":"Văn vương hoan hỉ rít lên, lúc này không còn lưu luyến chút nào"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Đột phá trung phẩm linh cấp (tương đương Nguyên Anh hậu kỳ đại viên mãn) sau khi dung hợp Cực Quang Hỏa Tuyến","chuong":"@c0266"},{"text":"Được xác nhận là thú đến từ tinh không, hung tính vượt xa yêu thú tu chân giới, sống bằng cắn nuốt vạn vật","chuong":"@c0479"},{"text":"Lột xác thành công sau trăm năm tế luyện bằng nguyên tinh, khí tức đạt ngang Tịnh Niết, toàn thân chuyển màu vàng nhạt","chuong":"@c1153"},{"text":"Hạ sát bốn Văn Thú lam, chiến thắng Văn Thú Vương tím và tiến hóa thành tân Văn Thú Vương thống lĩnh cả bầy","chuong":"@c1169"},{"text":"Máu hóa vàng, hiện hình bóng Văn Vương vạn trượng, hút máu Văn Vương khổng lồ trong khe nứt Phong Tiên Giới","chuong":"@c1178"},{"text":"Sau trăm năm thất lạc, tái ngộ Vương Lâm trong Phong Tiên Giới, dẫn đàn trên vạn con với tu vi tiếp cận bước thứ ba","chuong":"@c1585"}]},"canhGioiCaoNhat":"Tiếp cận bước thứ ba (tương đương thiên nhân ngũ suy)","aliases":["Văn vương"],"vaiTro":"Linh thú tọa kỵ trung thành nhất của Vương Lâm — Văn Thú Vương đến từ tinh không","tinhCach":"Trung thành tuyệt đối với chủ nhân, sống chết không rời; hung mãnh hiếu chiến, sống bằng cắn nuốt hút máu vạn vật; nặng tình đồng tộc, liều mình cứu bầy dù mang trọng thương; cảnh giác nhạy bén, phản ứng cực nhanh trước nguy hiểm","blurb":"Văn Thú — thường được gọi là con muỗi khổng lồ — là hung thú đến từ tinh không với bản tính hung tàn vượt xa yêu thú tu chân giới, trở thành linh thú tọa kỵ trung thành nhất của Vương Lâm từ thuở hắn còn Ngưng Khí. Sau khi dung hợp Cực Quang Hỏa Tuyến đột phá lên trung phẩm linh cấp, nó trải qua trăm năm tế luyện bằng nguyên tinh để lột xác đạt khí tức ngang Tịnh Niết, rồi tại Phong Tiên Giới khuất phục gần nghìn đồng tộc, hạ sát Văn Thú lam, chiến thắng Văn Thú Vương tím và tiến hóa thành tân Văn Thú Vương thống lĩnh hơn vạn Văn Thú. Trong trận đối đầu Văn Vương khổng lồ tại trung tâm Phong T"},{"id":"chuong-mon-phan-tong-quy-nhat","name":"Chưởng môn phân tông Quy Nhất tông","cn":"","aliases":["nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền đỉnh phong","trangThai":"song","blurb":"Chưởng môn phân tông phía đông Quy Nhất tông trên Tiên Cương đại lục. Tu vi Không Huyền đỉnh phong, đã vượt qua nhiều lần huyền kiếp.","vaiTro":"Chưởng môn phân tông Quy Nhất tông, canh giữ Đông Đan chung","tinhCach":"Thận trọng; tôn trọng lời dặn sư huynh","tabs":{"diem":[{"text":"Tu vi Không Huyền đỉnh phong, đã vượt nhiều lần huyền kiếp, canh giữ Đông Đan chung theo lời dặn Mã sư huynh","chuong":"@c1586"},{"text":"Nhận ra mũi kiếm xuyên qua Đông Đan chung là kiếm của Diệp Mịch, quyết định không mở chuông theo lời dặn năm xưa của Mã sư huynh","chuong":"@c1586"},{"text":"Tu vi Không Huyền đỉnh phong, vượt nhiều lần huyền kiếp, nhận ra kiếm của Diệp Mịch ngay khi mũi kiếm lộ trên Đông Đan chung","chuong":"@c1586"}],"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"vua","tieuDe":"Mũi kiếm xuyên Đông Đan chung","text":"Khi Đông Đan chung chấn động, dẫn đầu bay tới, nhận ra mũi kiếm đỏ đậm tỏa huyết quang là kiếm của Diệp Mịch. Quyết định tạm không mở chuông theo lời dặn của Mã sư huynh năm đó, xác nhận lời đồn Diệp Mịch bị Thất Đạo Tông dẫn vào động phủ là thật.","anchor":"Kiếm của Diệp Mịch!"}],"tuViMoc":[{"chuong":"@c1586","canhGioi":"Không Huyền đỉnh phong","text":"Được giới thiệu với tu vi Không Huyền đỉnh phong, đã vượt qua nhiều lần huyền kiếp.","importance":"major"}],"nhanMach":[{"ten":"Mã sư huynh","tag":"su-mon","quanHe":"Sư huynh trong Quy Nhất tông, đã dặn dò trước khi dẫn người vào động phủ","ghiChu":"@c1586"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Nhận diện qua huyết kiếm","ghiChu":"Biết Diệp Mịch bị dẫn vào động phủ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"]},{"id":"ma-su-huynh","name":"Mã sư huynh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Sư huynh trong Quy Nhất tông, từng dùng chí bảo tông phái mở thông đạo tới động phủ Thất Đạo Tông, dẫn người đi vào và dặn chuông không được mở.","vaiTro":"Thành viên Quy Nhất tông, người mở thông đạo tới động phủ","tinhCach":"Kiên quyết; có mưu lược","tabs":{"diem":[{"text":"Dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, phải tự mình trở về","chuong":"@c1586"}],"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"gon","tieuDe":"Mở thông đạo vào động phủ","text":"Nghiên cứu rất lâu rồi dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, dẫn người đi vào, phải tự mình trở về.","anchor":"Mã sư huynh trước khi dẫn người đi đã từng nói, chuông này không thể mở ra, hắn phải tự mình trở về"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn phân tông Quy Nhất tông","tag":"su-mon","quanHe":"Sư đệ, chưởng môn phân tông","ghiChu":"@c1586"},{"ten":"Chưởng môn phân tông Quy Nhất","tag":"su-mon","quanHe":"Sư đệ trong Quy Nhất tông, người nhớ lời dặn của Mã sư huynh","ghiChu":"@c1586"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"],"canhGioiCaoNhat":"khong-ro"},{"id":"dao-nhan-bay-mau","name":"Đạo nhân bảy màu","cn":"","aliases":["Thất Thải Tiên Tôn","Quái nhân tóc bạc","Thất Thải Thiên Tôn","thất thải"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1589","tieuDe":"Tiết lộ huyết trận hoàn thành, tìm người thứ ba","text":"Xuất hiện trong hắc động do mấy tu chân tinh tạo thành dòng xoáy, tiết lộ chính hắn đã sắp đặt cho Chưởng Tôn đưa cung Lý Quảng cho Vương Lâm coi đó là cơ duyên. Nhận xét Vương Lâm rất giống chiến lão quỷ, muốn lợi dụng nếu Vương Lâm không phải người thứ ba. Huyết trận đã hoàn thành, đang tiếp tục tính toán vị trí người thứ ba đã luân hồi vô số lần.","anchor":"Huyết trận đã thành, đang tiếp tục tính toán, không bao lâu nữa ta sẽ biết được người thứ ba luân hồi vô số lần rốt cục ở đâu"},{"chuong":"@c1597","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện tinh không, tuyên bố thu hồi cung Lý Quảng","text":"Hiện thân từ ánh sáng bảy màu dưới hình nam tử trung niên mặc đạo bào tiên phong đạo cốt. Điểm một chỉ ngưng tụ ánh sáng bảy màu vạn trượng nhắm Vương Lâm nhưng bị ngọc thủ Phàn San Lộ thi triển Thái Ngọc Thất Thủ Ấn chặn lại. Bình thản hóa giải ấn quyết, nhận ra thần thông mình đạt được không phải toàn bộ. Tuyên bố cung Lý Quảng đã hoàn thành sứ mạng cần thu hồi, rồi biến mất bước vào tinh không đuổi theo.","anchor":"Cây cung của Lý Quảng cũng đã hoàn thành sứ mạng rồi, nên thu hồi thôi"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Truy đuổi Vương Lâm đòi cung Lý Quảng","text":"Xé tinh không xuất hiện truy đuổi Vương Lâm và Phàn San Lộ, hừ lạnh một tiếng hủy diệt hơn trăm mãnh thú. Yêu cầu Vương Lâm giao cung của Lý Quảng. Tự xưng là Thất Thải Tiên Tôn, nhận Phàn San Lộ là đệ nhất phi. Triệu chín hỏa điểu (chín tu chân tinh bị luyện hóa) tấn công, rồi phóng tinh thể bảy màu vây khốn hai người. Bị Phàn San Lộ dùng thủ ấn bảy màu cộng lực từ tỷ tỷ phá vây.","anchor":"Lão phu đương nhiên là Thất Thải Tiên Tôn"},{"importance":"normal","mucCt":"vua","chuong":"@c1599","tieuDe":"Tấn công chiến thuyền, bị lộ quá khứ ám toán Phàn San Mộng","text":"Bước ra từ tinh không, nhìn chiến thuyền thấy quen nhưng không nhớ do chưa đạt ký ức đầy đủ. Ra tay phá vỡ một tầng phòng hộ, đẩy thuyền lùi mười trượng. Theo lời Phàn San Mộng tiết lộ: năm xưa nhờ cơ duyên lấy mảnh vỡ từ Thái Cổ Thần Cảnh, ám toán Phàn San Mộng chiếm tu vi để mở mảnh vỡ, dụ Đạo Cổ Diệp Mịch tới phong kín tông sơn rồi nhờ Lý Quảng chém giết Đạo Cổ.","anchor":"Ta còn chưa đạt được ký ức, rất nhiều chuyện không nhớ ra"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Được xác nhận là hồn thứ nhất Thất Thải Thiên Tôn","text":"Được nữ tử tiết lộ chính là hồn thứ nhất của Thất Thải Thiên Tôn, nắm toàn bộ đạo thuật thần thông cả đời, chiến lực cao nhất trong ba hồn. Chiếm cứ giới ngoại, ép tiên phi nghe lệnh, thu phục Chưởng Tôn. Không ngừng tìm kiếm hồn thứ ba để dung hợp trở thành Thất Thải Thiên Tôn hoàn chỉnh.","anchor":"Một trong tam hồn có được thần thông chính là đạo nhân bảy màu"},{"chuong":"@c1603","importance":"normal","mucCt":"vua","tieuDe":"Lên thuyền phá tầng hai, bị tuyên bố là huyễn ảnh","text":"Đặt chân lên boong tàu tầng một khi Phàn San Mộng mở phòng hộ, xuyên qua vào tầng hai và phá dần cấm chế trong hai canh giờ khiến tầng này sụp đổ. Vương Lâm tuyên bố sự hiện diện của hắn trên thuyền là giả — phần của huyễn giới do Phàn San Lộ tạo ra, còn bản thể có lẽ là thật.","anchor":"Đạo nhân bảy màu có lẽ là thật nhưng hắn ở trên thuyền này là giả"},{"chuong":"@c1605","importance":"normal","mucCt":"ky","tieuDe":"Chìm đắm trong ảo giác, Vương Lâm thử xâm nhập thất bại","text":"Bị Vương Lâm phát hiện đang ngồi khoanh chân trên thi hài mãnh thú, toàn thân tỏa ánh sáng bảy màu, thần sắc biến đổi phức tạp — chìm đắm trong ảo giác không thể tự kiềm chế. Xung quanh có cấm chế tự động hủy diệt vô thanh vô tức mọi vật trong phạm vi trăm trượng. Vương Lâm thi triển Mộng Đạo thuật cố xâm nhập ảo giác nhưng thất bại do tu vi quá cao và cấm chế ngăn cản.","anchor":"Toàn thân kẻ đó tỏa ra ánh sáng bảy màu, ngồi yên bất động"},{"importance":"normal","mucCt":"ky","chuong":"@c1608","tieuDe":"Mất dấu hồn thứ ba, thề giết Vương Lâm","text":"Trong huyễn cảnh tầng hai, lần đầu tiên tới gần được hồn thứ ba, nhìn thấy hồn thứ ba xuyên qua Triệu Hà hướng Côn Hư vạn năm sau, cực kỳ kích động. Bị tiếng rống Vương Lâm phá tan huyễn cảnh, tinh đồ sụp đổ, hồn thứ ba tiêu tán ngay trước mắt. Phẫn nộ tột cùng gào thét, thề không làm người nếu không giết Vương Lâm, mang sát khí truy kích.","anchor":"Vương Lâm, thất thải ta nếu không giết ngươi, thề không làm người!"},{"mucCt":"vua","text":"Cùng chín hỏa điểu khổng lồ hóa chín mặt trời truy kích Vương Lâm trong tinh không. Tuyên bố muốn luyện hóa thân thể Vương Lâm thành tro, rút hồn phách nguyên thần luyện thành pháp bảo. Điểm chỉ cho chín mặt trời lao thẳng tới Vương Lâm trên tế đàn.","anchor":"Ta muốn rút hồn phách của ngươi, nguyên thần của ngươi luyện thành pháp bảo, như thế mới giải được mối hận trong lòng ta","bridge":true,"khoang":"@c1609"},{"chuong":"@c1610","importance":"normal","mucCt":"vua","tieuDe":"Bị khí tức đại thiên tôn dọa chạy","text":"Nhận ra khí tức đại thiên tôn từ ký ức khắc trong linh hồn, sợ hãi phun máu, điên cuồng bỏ chạy khỏi cái khe Vân Hải tinh vực, không dám quay đầu, hoàn toàn từ bỏ ý định luyện hóa Vương Lâm.","anchor":"hoàn toàn đã bị khí tức trước mặt này dọa cho tan nát tâm thần"},{"mucCt":"vua","text":"Triệu tập Chưởng Tôn và tiên phi hướng về Côn Hư tìm kiếm hồn thứ ba. Thi triển thần thông dựa vào sự tử vong của vô số tu sĩ trong đại chiến giới nội–giới ngoại.","anchor":"Thần thông này chính là sau khi giới nội và giới ngoại đại chiến dùng sự tử vong của vô số tu sĩ đạo nhân bảy màu mới có thể thi triển được","bridge":true,"khoang":"@c1621"},{"importance":"normal","mucCt":"vua","chuong":"@c1623","tieuDe":"Tấn công Thanh Lâm bảo vệ đường dây Triệu Hà","text":"Giọng nói già nua vang lên trong tinh không Triệu Hà tinh vực cảnh cáo Thanh Lâm, thi triển lưỡi hái bảy màu khổng lồ tấn công. Lưỡi hái bị Thanh Lâm phá vỡ nhưng đã đẩy được Thanh Lâm ra khỏi khu vực.","anchor":"Thanh Lâm.đây không phải là chuyện ngươi có thể quản, xéo cho lão phu!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"doi-thu","quanHe":"Kẻ thù (đệ nhất phi bị hắn gây thương)","ghiChu":"Muội muội đạo lữ, bị hắn phản bội gây thương tích"},{"ten":"Phàn San Mộng","tag":"the-thiep","quanHe":"Đạo lữ (bạn đời)","ghiChu":"Bị hắn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín"},{"ten":"Phàn San Lộ","tag":"khac","quanHe":"Tiểu di (muội muội đạo lữ)","ghiChu":"Nhận ra qua Thái Ngọc Thất Thủ Ấn, từng gây thương tích cho nàng"},{"ten":"Phàn San Lộ","tag":"the-thiep","quanHe":"Đệ nhất phi","ghiChu":"Tự nhận Phàn San Lộ là đệ nhất phi của bổn tôn, nàng bỏ chạy không xác nhận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện tại chín đại lục trong Thái Cổ Tinh Thần, thân ảnh huyễn hóa xuất hiện từ cầu vồng bảy màu, bàn mưu đồ thôn phệ người thứ ba cùng Chưởng Tôn","chuong":"@c1573"},{"text":"Tiết lộ huyết trận đã hoàn thành và chính hắn sắp đặt cho Chưởng Tôn mọi bước đi nhằm tìm người thứ ba","chuong":"@c1589"},{"text":"Được xác nhận là hồn thứ nhất của Thất Thải Thiên Tôn, nắm toàn bộ đạo thuật thần thông cả đời","chuong":"@c1600"},{"text":"Mất dấu hồn thứ ba trong huyễn cảnh tầng hai, thề giết Vương Lâm","chuong":"@c1608"},{"text":"Nhận ra khí tức đại thiên tôn từ ký ức khắc trong linh hồn, sợ hãi phun máu và điên cuồng bỏ chạy","chuong":"@c1610"},{"text":"Triệu tập Chưởng Tôn và tiên phi hướng về Côn Hư truy tìm hồn thứ ba, tấn công Thanh Lâm để bảo vệ đường dây Triệu Hà","chuong":"@c1621"}]},"nguon":["@c1586","@c1589","@c1597","@c1598","@c1599","@c1600","@c1603","@c1605","@c1608","@c1609","@c1610","@c1621","@c1623"],"tinhCach":"Thâm trầm mưu lược, sắp đặt kế hoạch xuyên suốt nhiều đời; tự tin tuyệt đối vào thần thông và quyền năng bản thân; coi mọi người như quân cờ phục vụ mưu đồ thôn phệ; hung tàn quyết đoán nhưng vẫn biết sợ trước khí tức đại thiên tôn","vaiTro":"Phản diện ẩn cấp cao — sư tôn của Chưởng Tôn, hồn thứ nhất của Thất Thải Thiên Tôn","blurb":"Đạo nhân bảy màu là hồn thứ nhất của Thất Thải Thiên Tôn, cường giả ẩn cư tại chín đại lục trôi nổi trong Thái Cổ Tinh Thần, nắm giữ toàn bộ đạo thuật thần thông cả đời của Thất Thải Thiên Tôn. Với tư cách sư tôn của Chưởng Tôn, lão sắp đặt huyết trận, mang tổ tiên viễn cổ mãnh thú từ Tiên giới, và âm mưu truy tìm hồn thứ ba để thôn phệ rồi vượt qua Chiến Không Liệt. Trong quá trình truy đuổi Vương Lâm đòi cung Lý Quảng và truy kích hồn thứ ba, lão nhiều lần lộ diện tinh không, nhưng cũng bộc lộ điểm yếu khi hoảng sợ bỏ chạy trước khí tức đại thiên tôn."},{"id":"chien-lao-quy","name":"Chiến lão quỷ","aliases":["Chiến Không Liệt"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1588","tieuDe":"Ẩn thế trong Lôi Tiên Giới quan sát Vương Lâm","text":"Ẩn thế sâu trong Lôi Tiên Giới, thần thức Vương Lâm không phát hiện ra nhưng hắn lại quan sát được Vương Lâm. Tự hỏi Vương Lâm biết được bao nhiêu và có phải là người thứ ba hay không, không ngăn cản Vương Lâm rời đi.","anchor":"hắn rốt cục biết được bao nhiêu rồi.hắn rốt cục có phải là người thứ ba hay không"},{"mucCt":"vua","text":"Đang đuổi theo tứ đại chiến tướng ở La Thiên Tinh Vực xem họ tìm hồn thứ ba, đột nhiên cảm nhận khí tức đại thiên tôn, sắc mặt tái nhợt. Một giọng nói khác từ bên trong cơ thể hắn vang lên kinh ngạc.","anchor":"một giọng nói từ trong cơ thể hắn ầm ầm vang lên cao vút","bridge":true,"khoang":"@c1610"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Chỉ dùng thần thức quan sát tứ đại chiến tướng tìm hồn thứ ba từ xa, không có bất kỳ hành động nào.","anchor":"Chiến lão quỷ dường như không có chút hành động nào"},{"mucCt":"vua","text":"Mặc đạo bào, thần sắc thong dong, theo sau nhóm tứ đại chiến tướng viễn cổ tiên vực và hơn trăm tiên nhân trong Triệu Hà tinh vực. Hai bên lờ nhau không tương tác. Được nhắc là một trong những người tìm hồn thứ ba có ý đồ với thiên đạo.","anchor":"Theo sau đám tiên nhân này là Chiến lão quỷ mặc đạo bào, thần sắc thong dong","bridge":true,"khoang":"@c1631"},{"mucCt":"vua","text":"Đi theo đám viễn cổ tiên nhân, nhướng mày khi phát hiện dấu vết bổn nguyên nhưng không tìm ra Vương Lâm. Khi thấy U Minh thú cảm thấy nguy cơ dựng tóc gáy, nhận ra tứ đại chiến tướng mượn mình tạo áp lực. Gật đầu hứng thú, đề nghị đáp ứng một điều kiện nếu Vương Lâm tiết lộ nguồn gốc.","anchor":"Chiến mỗ đúng là rất hứng thú đối với con thú này","bridge":true,"khoang":"@c1632"}],"tuiDo":{},"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được Chưởng Tôn nhắc đến khi giết Chiến Tinh Dã, là kẻ khiến Chưởng Tôn e sợ nhất, tu vi đạt cảnh giới Không Kiếp","chuong":"@c1134"},{"text":"Tái xuất tuyên bố vẫn chưa chết, nhắc chiến tích năm xưa đánh bại Thái Cổ Ngũ Tôn tại giới ngoại, đoạt cây cung và phát hiện Bách Vạn Tu Linh Ấn","chuong":"@c1438"},{"text":"Xuất hiện vô thanh điểm một chỉ khiến Chưởng Tôn bị thương tan vỡ biến mất, sau đó quan sát hắc động tầng phủ bích rồi rời đi","chuong":"@c1493"},{"text":"Quan sát Vương Lâm vượt thiên kiếp, nhận ra hắn sở hữu Tam Thiên phất trần, Trấn Tiên bảo tháp và Phong Mệnh Hoàn, ánh mắt lộ vẻ tham lam chưa từng có","chuong":"@c1533"},{"text":"Ẩn thế sâu trong Lôi Tiên Giới, thần thức Vương Lâm không phát hiện ra nhưng hắn lại quan sát được Vương Lâm","chuong":"@c1588"},{"text":"Theo dõi tứ đại chiến tướng và đám viễn cổ tiên nhân tìm hồn thứ ba, nhướng mày khi phát hiện dấu vết bổn nguyên nhưng không tìm ra Vương Lâm","chuong":"@c1632"}]},"nguon":["@c1588","@c1610","@c1621","@c1631","@c1632"],"gioiTinh":"nam","trangThai":"song","vaiTro":"Sư phụ Chiến Tinh Dã — cường giả Không Kiếp, mục tiêu của Thiên Đạo Kế","tinhCach":"Thâm trầm mưu lược, kiên nhẫn ẩn nhẫn chờ thời; hung hãn quyết đoán khi ra tay; tham lam trước cơ duyên hiếm có","blurb":"Chiến Lão Quỷ là cường giả cảnh giới Không Kiếp Sơ Kỳ, sư phụ của Chiến Tinh Dã, từng đánh bại Thái Cổ Ngũ Tôn tại giới ngoại và là kẻ khiến Chưởng Tôn kiêng kỵ nhất. Sau khi Chiến Tinh Dã bị giết, hắn tuyên bố vẫn chưa chết, ẩn cư tại Lôi Tiên Giới hoang tàn rồi bất ngờ xuất thủ điểm chỉ khiến Chưởng Tôn bị thương. Hắn âm thầm quan sát Vương Lâm vượt thiên kiếp, nhận ra hắn sở hữu nhiều pháp bảo trọng yếu như Tam Thiên phất trần, Trấn Tiên bảo tháp và Phong Mệnh Hoàn, đồng thời theo dõi tứ đại chiến tướng tìm hồn thứ ba, tỏ ra vô cùng kích động trước cơ duyên chưa từng có."},{"id":"thanh-lam","name":"Thanh Lâm","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1588","tieuDe":"Dẫn đầu thu tinh hồn và vái tiễn Vương Lâm","text":"Dẫn đầu mấy vạn tu sĩ giới nội tản ra tứ đại tinh vực thu tinh hồn theo truyền âm của Vương Lâm, cuối cùng vái tiễn Vương Lâm rời đi.","anchor":"Dưới sự dẫn đầu của Thanh Lâm bọn họ liền nhận được truyền âm của Vương Lâm"},{"chuong":"@c1592","importance":"normal","tieuDe":"Bái kiến tiên nhân viễn cổ bị phớt lờ","text":"Sắc mặt tái nhợt khi cảm nhận khí tức viễn cổ tiên vực, bay lên tinh không cùng Hồng Sam Tử, Nam Vân Tử, Thanh Thủy. Xưng là đệ tử Phong Tôn, cung kính bái kiến tiên nhân viễn cổ nhưng bị hoàn toàn phớt lờ — tiên nhân cười lớn xuyên qua bốn người lao thẳng về tân tiên giới thôn phệ hương hỏa. Trái tim chấn động trước cảnh tượng này.","anchor":"Đệ tử của Phong Tôn, Thanh Lâm, bái kiến các vị tiên nhân viễn cổ","mucCt":"ky"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Nổi giận gầm lên yêu cầu tiên nhân dừng tay nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Thanh Lâm nổi giận gầm lên một tiếng, trực tiếp đạp bước mà đi"},{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Nghênh đón Vương Lâm trở về, nhận toàn bộ tiên thuật Lôi Tiên Giới để truyền thụ nâng cao lực lượng tiên giới.","anchor":"lấy toàn bộ tiên thuật ra đưa cho đám người Thanh Lâm"},{"mucCt":"ky","text":"Mặc y phục lam trong lầu các trắng trên đỉnh tuyết sơn, xưng Vương Lâm là Vương huynh thay vì gọi đệ tử như trước do tu vi và thân phận Vương Lâm đã thay đổi. Tiếp nhận yêu cầu hộ pháp và tính toán của Vương Lâm, nắm lấy hồn phách phân thân Thiên Vận Tử để ngưng thần quan sát.","anchor":"Thanh Lâm giơ tay phải lên nắm lấy hồn phách của Thiên Vận Tử, ngưng thần quan sát","bridge":true,"khoang":"@c1622"},{"mucCt":"ky","text":"Kiểm tra phân hồn Thiên Vận Tử, xác nhận cực yếu không có mánh khóe. Dung nhập thần thức vào cơ thể Vương Lâm, kinh hoàng phát hiện bảy đạo bổn nguyên và khí tức huyết mạch cổ xưa bá đạo khủng bố không phải Cổ Thần thông thường. Phát hiện cấm chế bổn nguyên tự vận chuyển dị thường, lập tức dùng Định Thần Thuật ngăn lại, rút sợi tơ u quang từ ngực Vương Lâm. Dung hợp thần thức với sợi tơ truy tìm trong Triệu Hà tinh vực, bị đạo nhân bảy màu dùng lưỡi hái bảy màu khổng lồ tấn công, thi triển Tam quang hộ thể tam kiếm khai hà chống đỡ, phá vỡ lưỡi hái nhưng bản thân bị chấn, mất liên lạc quay về tuyết sơn.","anchor":"Sắc mặt Thanh Lâm lập tức tái nhợt, thân thể nhoáng lên theo tiềm thức lui lại phía sau","bridge":true,"khoang":"@c1623"},{"chuong":"@c1624","importance":"normal","mucCt":"vua","tieuDe":"Kêu gọi trợ giúp Vương Lâm truy sát Thiên Vận Tử","text":"Lo lắng nhìn Vương Lâm rời tiên giới, lao lên bầu trời truy theo. Truyền thần niệm khắp tiên giới kêu gọi Hồng Sam Tử và Nam Vân Tử cùng đi hỗ trợ.","anchor":"Vương Lâm đ*o hữu bị một gã tên là Thiên Vận Tử tính kế"},{"importance":"bridge","mucCt":"gon","chuong":"@c1626","tieuDe":"Hộ pháp bổn tôn Vương Lâm","text":"Cùng Hồng Sam Tử theo Lam Mộng Đạo Tôn tới hộ pháp bổn tôn Vương Lâm.","anchor":"phía sau là Thanh Lâm và Hồng Sam Tử"},{"importance":"bridge","mucCt":"gon","chuong":"@c1628","tieuDe":"Khống chế phân thân Vương Lâm","text":"Được Vương Lâm nhờ cùng Lam Mộng Đạo Tôn và Hồng Sam Tử khống chế phân thân Vương Lâm tranh thủ thời gian khi hắn lên đường tìm bổn tôn Thiên Vận Tử.","anchor":"Ba vị tiền bối không cần đi cùng ta"},{"importance":"bridge","mucCt":"gon","chuong":"@c1629","tieuDe":"Chặn Thiên Vận Tử","text":"Lộ vẻ lo lắng khi phân thân Vương Lâm bị chiếm cứ, cùng Hồng Sam Tử áp sát chặn Thiên Vận Tử khi hắn muốn rời đi.","anchor":"Thanh Lâm và Hồng Sam Tử cũng áp sát Thiên Vận Tử"},{"chuong":"@c1630","importance":"bridge","mucCt":"gon","tieuDe":"Từ biệt Vương Lâm","text":"Có mặt cùng Lam Mộng Đạo Tôn, được Vương Lâm ôm quyền từ biệt và nhờ chuyển lời cho Thanh Thủy.","anchor":"Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử tiền bối"}],"tuiDo":{},"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được xác nhận là Tiên Đế, đệ nhất cường giả Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Thi triển Định Thân Thuật và lập Cửu Ấn Trận áp chế thánh tổ Phù Tộc trong động phủ Tiên Đế","chuong":"@c0968"},{"text":"Hiện thân trong Thức Hải truyền thụ Quy tắc thân thể cho Vương Lâm, chuyển giao khống chế Thức Hải rồi tiêu tan","chuong":"@c1047"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi các đệ tử","chuong":"@c1050"},{"text":"Thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ giết tu sĩ giới ngoại, bảo vệ giới nội","chuong":"@c1453"},{"text":"Dẫn đầu mấy vạn tu sĩ thu tinh hồn, vái tiễn Vương Lâm rồi hộ pháp trong trận chiến cuối cùng với Thiên Vận Tử","chuong":"@c1588"}]},"nguon":["@c1588","@c1592","@c1593","@c1621","@c1622","@c1623","@c1624","@c1626","@c1628","@c1629","@c1630"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Tiên Đế — đệ nhất cường giả Tiên giới, phụ thân Thanh Sương, ân sư Vương Nguy và Hồ Quyên","tinhCach":"Ôn hòa, che chở đệ tử và người thân; mưu tính sâu xa với bố cục vượt thời gian khiến Cổ Ma kiêng dè; lạnh lùng quyết đoán khi đối đầu kẻ địch; trọng ân nghĩa, từng cứu người kết duyên","blurb":"Thanh Lâm là Tiên Đế, đệ nhất cường giả Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy cùng Hồ Quyên và có đại ân với Lữ Vân Đạo. Sau khi Tiên giới vỡ nát, thân thể ông tồn tại trong khe không gian rồi bị Cổ Ma Tháp Già nhập thể; hiện thân của ông trong Thức Hải đã truyền thụ Quy tắc thân thể và chuyển giao khống chế Thức Hải cho Vương Lâm, sau đó thức tỉnh trong trận pháp hồi sinh và khai sinh Tân Vũ Giới. Ông bế quan chữa thương mấy trăm năm tại Vũ Tiên Giới, thi triển viễn cổ tiên thuật bảo vệ giới nội, tham chiến đại chiến giới ngoại, và được tiết lộ là một trong h"},{"id":"tu-do-nam","name":"Tư Đồ Nam","aliases":["Tham Lang"],"tabs":{"kinhLich":[{"mucCt":"gon","text":"Được Vương Lâm gửi gắm: nếu Vương Lâm chết, bố cáo toàn thiên hạ chuyện Vương Lâm đã nói, viết thành ngọc giản lưu trên mỗi tu chân tinh và trong tân tiên giới. Vái tiễn Vương Lâm cùng mấy vạn tu sĩ.","anchor":"Tư Đồ, nếu ta chết đi, mong ngươi nói chuyện ta đã nói cho ngươi bố cáo toàn thiên hạ","bridge":true,"khoang":"@c1588"},{"text":"Ở trong đám tu sĩ trên mặt đất tân tiên giới, nhìn khe viễn cổ tiên vực nhớ lại lời Vương Lâm từng nói, không có chút kính sợ, chỉ cảm thấy mờ mịt và phức tạp. Chưa tiết lộ nội dung ấy cho ai.","anchor":"Lúc này nhìn thấy cái khe viễn cổ tiên vực, trong lòng hắn không có chút kính sợ, chỉ cảm thấy mờ mịt và phức tạp","mucCt":"vua","bridge":true,"khoang":"@c1592"},{"mucCt":"vua","text":"Giật mình tỉnh lại, bóp nát ngọc giản mà Vương Lâm giao ba năm trước ở Chu Tước Tinh. Thần thức Vương Lâm tuôn ra huyễn hóa thành thân ảnh, phát sát lục đuổi tiên nhân khỏi tiên giới.","anchor":"Ngọc giản này là ba năm trước khi hắn gặp Vương Lâm ở Chu Tước Tinh","bridge":true,"khoang":"@c1593"},{"mucCt":"ky","text":"Xuất hiện từ khe nứt gần tế đàn, trong không gian kỳ dị dạng đào viên. Khuôn mặt tiều tụy, mắt vô thần, bị hai cô bé Hàm Hàm và Oa Oa giữ suốt một trăm năm bắt kể chuyện cổ. Ban đầu khi mới tới từng uy hiếp hai cô bé nhưng bị khuất phục. Cầu xin được tha, khóc lóc nói không còn chuyện cổ, muốn uống nước. Đã kể chuyện tới đoạn về Vọng Nguyệt.","anchor":"Các tiểu tổ tông ơi, các người buông tha cho ta đi","bridge":true,"khoang":"@c1608"},{"chuong":"@c1621","importance":"bridge","mucCt":"vua","text":"Cùng Vương Lâm uống rượu, thoải mái cười to, vỗ vai Vương Lâm, cảm khái vì thật lâu không làm vương gia.","anchor":"lắc đầu cảm khái, cảm khái không phải là vì Vương Lâm đã trưởng thành mà vì thật lâu hắn không làm vương gia"}],"tuiDo":{},"nhanMach":[{"ten":"Hàm Hàm","tag":"khac","quanHe":"Cô bé giam giữ Tham Lang trong đào viên","ghiChu":"Bắt kể chuyện cổ suốt trăm năm @c1608"},{"ten":"Oa Oa (đào viên)","tag":"khac","quanHe":"Cô bé giam giữ Tham Lang trong đào viên","ghiChu":"Đề nghị kể thêm ngàn năm mới thả @c1608"}],"tuViMoc":[],"diem":[{"text":"Tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu của Vương Lâm, lần đầu lên tiếng dẫn dắt hắn từ thuở nhỏ","chuong":"@c0046"},{"text":"Đoạt xá thành công thân xác đồng tử áo đỏ sau khi được lửa Chu Tước đánh thức, nuốt tứ tổ Tiên Di Tộc đạt Vấn Đỉnh Kỳ","chuong":"@c0411"},{"text":"Tu vi đạt Tịnh Niết sơ kỳ, nổi danh với thân phận cung chủ Hồng Phấn cung trên Thiên Vận tinh","chuong":"@c0932"},{"text":"Được Thanh Lâm thu nhận làm đệ tử tại Vũ Tiên Giới với điều kiện không bị hạn chế tự do","chuong":"@c1050"},{"text":"Được Thanh Lâm trợ giúp phá không môn, đột phá bước thứ ba, tham gia tử chiến bảo vệ Chu Tước Tinh","chuong":"@c1520"},{"text":"Nhận ngọc giản ủy thác từ Vương Lâm, bóp nát phát tín hiệu khi Vương Lâm gặp nạn, cuối cùng hội ngộ tại tân tiên giới","chuong":"@c1593"}]},"nguon":["@c1588","@c1592","@c1593","@c1608","@c1621"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Thế lực ẩn — cường giả lục cấp Chu Tước Quốc, huynh trưởng và ân nhân lớn nhất của Vương Lâm","tinhCach":"Kiêu ngạo bất kính, hành xử ngang tàng không kiêng nể; tàn độc quyết đoán, chủ trương diệt địch tận gốc; trọng tình nghĩa với Vương Lâm, sẵn sàng xả thân tương trợ; thận trọng toan tính lâu dài nhưng dễ mất kiên nhẫn","blurb":"Tư Đồ Nam vốn là đệ nhất cao thủ lục cấp tu chân quốc Chu Tước, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn náu trong Thiên Nghịch Châu của Vương Lâm suốt hàng trăm năm, dẫn dắt hắn từ thuở nhỏ. Sau khi được lửa Chu Tước đánh thức, ông đoạt xá thành công thân xác đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc đạt Vấn Đỉnh Kỳ rồi tu luyện tới Tịnh Niết sơ kỳ, gây họa khắp tinh vực và bị Loan Phượng tinh truy nã, nhưng luôn quay về bên Vương Lâm trong những lúc nguy cấp nhất. Tại Vũ Tiên Giới, ông được Thanh Lâm thu nhận làm đệ tử với điều kiện không bị hạn c"},{"id":"hong-sam-tu","name":"Hồng Sam Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1588","text":"Có mặt trong đám mấy vạn tu sĩ vái tiễn Vương Lâm rời đi nghịch tiên.","anchor":"kể cả Thanh Lâm, Hồng Sam Tử, Tư Đồ Nam đều hướng về phía Vương Lâm vái một vái"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Cùng Nam Vân Tử bước ra đối mặt tiên nhân nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Hồng Sam Tử, Nam Vân Tử sửng sốt một chút, lập tức thần sắc đại biến"},{"chuong":"@c1624","importance":"minor","mucCt":"gon","tieuDe":"Lao theo hỗ trợ Vương Lâm","text":"Nghe truyền thần niệm của Thanh Lâm, không do dự lao thẳng lên bầu trời đuổi theo Vương Lâm.","anchor":"khí tức của Hồng Sam Tử bốc lên, thân ảnh biến ảo ra không chút do dự liền đạp bước lao thẳng lên bầu trời"},{"importance":"bridge","mucCt":"gon","chuong":"@c1626","tieuDe":"Hộ pháp bổn tôn Vương Lâm","text":"Cùng Thanh Lâm theo Lam Mộng Đạo Tôn tới hộ pháp bổn tôn Vương Lâm.","anchor":"phía sau là Thanh Lâm và Hồng Sam Tử"},{"importance":"bridge","mucCt":"gon","chuong":"@c1628","tieuDe":"Khống chế phân thân Vương Lâm","text":"Được Vương Lâm nhờ cùng Thanh Lâm và Lam Mộng Đạo Tôn khống chế phân thân Vương Lâm tranh thủ thời gian.","anchor":"Ba vị tiền bối không cần đi cùng ta"},{"importance":"bridge","mucCt":"gon","chuong":"@c1629","tieuDe":"Áp sát chặn Thiên Vận Tử","text":"Lộ vẻ lo lắng khi phân thân Vương Lâm bị chiếm cứ, cùng Thanh Lâm áp sát Thiên Vận Tử khi hắn muốn rời đi.","anchor":"Thanh Lâm và Hồng Sam Tử cũng áp sát Thiên Vận Tử"},{"chuong":"@c1630","importance":"bridge","mucCt":"gon","tieuDe":"Từ biệt Vương Lâm","text":"Có mặt cùng Lam Mộng Đạo Tôn và Thanh Lâm, được Vương Lâm ôm quyền từ biệt.","anchor":"Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử tiền bối"}],"tuiDo":{},"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, lệnh Huyền Bỉnh đi tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải từ tinh không lao tới tiếp viện giới nội khi chiến tranh bùng nổ","chuong":"@c1425"},{"text":"Phá sát giới mấy vạn năm, thi triển thần thông Huyết Sam, một mình đối đầu năm–sáu cao thủ bước thứ ba giới ngoại","chuong":"@c1427"},{"text":"Bị phong ấn tại Thất Thải Giới trong đại chiến thứ hai, bổn tôn bị giam trong đạo quả, được Vương Lâm giải cứu","chuong":"@c1469"},{"text":"Cùng Thanh Lâm và Lam Mộng Đạo Tôn hộ pháp bổn tôn Vương Lâm, khống chế phân thân và chặn Thiên Vận Tử","chuong":"@c1628"},{"text":"Từ biệt Vương Lâm cùng Lam Mộng Đạo Tôn và Thanh Lâm trước khi hắn lên đường nghịch tiên","chuong":"@c1630"}]},"nguon":["@c1588","@c1593","@c1624","@c1626","@c1628","@c1629","@c1630"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chi"},{"id":"tam-phi","name":"Tam phi","gioiTinh":"nu","aliases":[],"theLuc":[{"ten":"Bát phi tiên tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bát phi của tiên tôn, nữ tử bạch y dung nhan tuyệt mỹ, tính tình băng lạnh. Sau khi rời vùng đất cổ mộ đã ở trong Thái Cổ Tinh Thần chờ đợi điều gì đó.","vaiTro":"Một trong bát phi tiên tôn, chờ đợi bí ẩn trong Thái Cổ Tinh Thần","tinhCach":"Băng lạnh; bí ẩn; kiên nhẫn chờ đợi","nguon":["@c1589","@c1593"],"tabs":{"diem":[{"text":"Một trong bát phi tiên tôn, dung nhan tuyệt mỹ, băng lạnh","chuong":"@c1589"},{"text":"Rời vùng đất cổ mộ rồi ở Thái Cổ Tinh Thần chờ đợi mục đích chưa rõ","chuong":"@c1589"}],"kinhLich":[{"mucCt":"vua","text":"Nữ tử bạch y dung nhan tuyệt mỹ, băng lạnh, đang khoanh chân trên đỉnh núi một tu chân tinh trong Thái Cổ Tinh Thần. Sau khi từ vùng đất cổ mộ đi ra đã ở đây chờ đợi, mở mắt nhận ra Vương Lâm xuất hiện và nghi hoặc hắn muốn làm gì.","anchor":"Nữ tử này chính là một trong bát phi của tiên tôn, tam phi","bridge":true,"khoang":"@c1589"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Tâm thần chấn động khi thấy Vương Lâm hành động, vội vàng vọt tới.","anchor":"Dù là tiên phi thứ ba thì tâm thần cũng chấn động, vội vàng vọt tới"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nhận ra sự xuất hiện của Vương Lâm, nghi hoặc mục đích"}],"tuiDo":{}}},{"id":"thien-van-tu","name":"Thiên Vận Tử","nguon":["@c1589","@c1601","@c1608","@c1618","@c1619","@c1621","@c1622","@c1623","@c1624","@c1625","@c1626","@c1627","@c1628","@c1629","@c1630","@c1631","@c1632"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1589","tieuDe":"Cảm ứng biến đổi kinh thiên sắp xảy ra","text":"Vẫn ngồi khoanh chân trên khối đá ở Triệu Hà tinh vực, bàn tay không ngừng biến hóa tính toán, ánh mắt ngày càng sáng. Là người duy nhất ngoài Vương Lâm hơi cảm ứng được biến đổi kinh thiên chỉ còn mười hai giờ nữa sẽ xảy ra.","anchor":"Ánh mắt Thiên Vận Tử lộ ra ánh sáng kỳ dị, bàn tay không ngừng biến hóa nhanh"},{"chuong":"@c1601","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc đến trong nội tâm như người duy nhất mà hắn không thể nắm được tâm tư. Vương Lâm nhận định cả đời gặp nhiều người nhưng chỉ Thiên Vận Tử là không thể nắm được tâm tư.","anchor":"trừ Thiên Vận Tử là hắn không thể nắm được"},{"importance":"bridge","mucCt":"gon","chuong":"@c1608","tieuDe":"","text":"Hồn phách bị Vương Lâm dung nhập để triển khai bói toán xác nhận tế đàn là sinh cơ.","anchor":"dung nhập bên trong hồn phách của Thiên Vận Tử, triển khai bói toán"},{"importance":"bridge","mucCt":"gon","chuong":"@c1618","tieuDe":"Bị Vương Lâm nghi ngờ là hồn thứ ba","text":"Bị Vương Lâm nhớ tới và phân tích kỹ: đạt được máu thiên đạo, không chết, không xuất hiện suốt đại chiến, mưu kế thâm sâu, có hơn ba nghìn phân thân từng thôn phệ đệ tử, bị nghi là hồn thứ ba của Thất Thải Tiên Tôn hoặc thuộc bảy phách.","anchor":"Thiên Vận Tử! Người này năm đó đạt được máu thiên đạo, cho dù là có chuyện giống như Thanh Long Thánh Hoàng nói về máu này nhưng Thiên Vận Tử không thể chết như thế"},{"importance":"bridge","mucCt":"gon","chuong":"@c1619","tieuDe":"Bị Vương Lâm nhận định ẩn giấu trình độ cấm chế","text":"Được Vương Lâm nhắc đến khi ngộ ra bổn nguyên cấm chế: nhận định Thiên Vận Tử có thuật tính toán cấm chế bổn nguyên và đã ẩn giấu trình độ cấm chế kinh thiên.","anchor":"Thiên Vận Tử có thuật này, trước ta không hiểu lắm, giờ xem ra ngày đó hắn ẩn dấu trình độ cấm chế kinh thiên!"},{"mucCt":"vua","text":"Vương Lâm coi hắn là cái gai phải rút, tiến vào hồn Thiên Vận Tử mà hắn nắm giữ để truy tìm nơi bổn tôn ẩn náu và quyết tâm giết. Đây là lần đầu tiên Vương Lâm muốn giải quyết gút mắc ngàn năm này.","anchor":"Cái gai này chính là Thiên Vận Tử!","bridge":true,"khoang":"@c1621"},{"importance":"normal","mucCt":"ky","chuong":"@c1622","tieuDe":"Bổn tôn lộ diện, hé lộ âm mưu hai ngàn năm","text":"Bổn tôn Thiên Vận Tử ngồi trên thiên thạch trong Triệu Hà tinh không, tóc trắng, nụ cười quỷ dị. Khi Vương Lâm dung hợp phân thân, hắn lập tức cảm ứng được và ánh mắt xuyên tinh không nhìn thấy Vương Lâm. Gọi Vương Lâm là đồ nhi, nói tu vi Vương Lâm càng cao thì lợi ích cho hắn càng lớn. Lần lượt thể hiện các bổn nguyên đã có: Nhân Quả, Sinh Tử, Chân Giả, hỏa và lôi đình trong đôi mắt, Sát Lục trên mi tâm với hình ảnh Thiên Vận Tử áo xám. Nói đã thu được bổn nguyên thứ bảy là cấm chế bổn nguyên, tơ máu trong đồng tử đang dung hợp thành cấm chế theo phương pháp Vương Lâm sáng tạo. Tán dương phương pháp này là cổ kim chưa ai nghĩ ra. Nói Vương Lâm là người nghịch thiên mà hắn tổn hao vô số năm tính toán, cái cây hai ngàn năm đã khai hoa nhưng chưa tới ngày hái quả. Khi Vương Lâm tách dung hợp thì quá trình lĩnh ngộ cấm chế dừng lại.","anchor":"Không hổ là đồ nhi tốt của lão phu"},{"importance":"normal","mucCt":"ky","chuong":"@c1623","tieuDe":"Bổn tôn bị định vị trên thiên thạch Triệu Hà","text":"Phân hồn bị Vương Lâm nắm giữ, được Thanh Lâm kiểm tra xác nhận cực yếu. Bị Lam Mộng Đạo Tôn xác định đang thi triển Luân Hồi nhất thể thuật, lợi dụng phân thân để trộm bổn nguyên Vương Lâm. Bổn tôn bị Lam Mộng Đạo Tôn dùng lam quang định vị, đang ở trên viên thiên thạch sâu trong Triệu Hà tinh vực, mở bừng mắt với ánh mắt khiếp sợ khi bị phát hiện.","anchor":"Trên thiên thạch này, Thiên Vận Tử mở bừng đôi mắt, ánh mắt khiếp sợ!"},{"chuong":"@c1624","importance":"major","mucCt":"ky","tieuDe":"Chủ động hiến hồn — đoạt cấm chế bổn nguyên, tiết lộ Luân Hồi Toàn Thể Thuật","text":"Bị Vương Lâm truy tới thiên thạch trong Triệu Hà, dùng hỏa bổn nguyên (hỏa Chu Tước) và lôi bổn nguyên (chín Lôi Long) đối kháng, thần thông giống hệt Vương Lâm. Cận chiến chiếm thượng phong khiến Vương Lâm phun máu. Lần 1 bị Sát cấm chia lìa thân thể, cười quỷ dị nói mình và Vương Lâm đã thành một thể, hồn phách tự dung nhập vào Vương Lâm. Trên tu chân tinh, mắt đã có sẵn tơ máu cấm chế hoàn chỉnh — chứng tỏ đã đoạt được cấm chế bổn nguyên của Vương Lâm từ lần đối chiến trước. Tự nhận đánh đổi một hồn lấy cấm chế là đáng. Lần 2 chủ động tự sát bằng cách điểm ngón tay xuyên đầu, phân hồn lại nhập vào Vương Lâm. Tiết lộ thuật pháp tên Luân Hồi Toàn Thể Thuật, bản thân đã tỉnh giấc 97 lần, lần này là lần thứ 98, không phải người đầu tiên tỉnh giấc (sau hai người khác). Kế hoạch càng gần hoàn thành.","anchor":"Tặng hắn một hồn đổi lấy cấm chế bổn nguyên, ta cũng coi là đáng"},{"importance":"normal","mucCt":"ky","chuong":"@c1625","tieuDe":"Bị Vương Lâm vạch trần sơ hở và lật ngược cục diện","text":"Ngồi chờ sẵn trong đám đá vụn Triệu Hà tinh vực, tự tin coi thường Vương Lâm, tự nhận hắn là đồ nhi. Tặng thủy bổn nguyên (một tia trộm từ người khác) và thổ bổn nguyên (đám bùn đất nhúc nhích) cho Vương Lâm, đề xuất trò chơi đã bắt đầu từ nhiều năm trước. Định diễn cảnh tử vong quỷ dị bằng cách tự điểm xuyên mi tâm lần hai nhưng bị Vương Lâm dùng cuồng phong huyết mạch Đạo cổ cản lại. Bị vạch trần mọi sự thần bí quỷ dị chỉ là vờ vịt nhằm che giấu sơ hở: Luân Hồi toàn thể thuật không trộm nổi huyết mạch Đạo cổ. Bị thách thi triển thần thông Đạo cổ nhưng không thể, sắc mặt âm trầm. Bị Vương Lâm khẳng định hiện tại chỉ là phân thân, bổn tôn ở nơi khác, và tuyên bố bổn tôn Vương Lâm sẽ đi tìm bổn tôn hắn mà giết.","anchor":"Không hổ là đồ nhi của Thiên Vận Tử ta, nhanh như vậy đã bình tĩnh trở lại"},{"mucCt":"ky","text":"Ở phía đông Triệu Hà, sắc mặt âm trầm, tự tin bổn tôn không thể bị tìm thấy vì bản thân cũng đã quên vị trí. Lo ngại Vương Lâm quỷ kế đa đoan, quyết nhanh chóng hoàn thành kế hoạch, đồng loạt triệu hồi gần ba nghìn phân thân trong tứ đại tinh vực (Triệu Hà, Côn Hư, La Thiên, Vân Hải). Hồn phách trong cơ thể Vương Lâm sôi trào liên lạc toàn bộ phân thân — Vương Lâm cảm ứng vị trí từng phân thân, trúng kế. Trong huyễn cảnh quá khứ: ngồi trên thiên thạch Triệu Hà xưa, tay dính máu thiên đạo cướp từ Thanh Long Thánh Hoàng, sắc mặt thống khổ, mở mắt — mắt lóe hư ảnh phân thân — rồi há miệng cắn nuốt Lăng Thiên Hầu đang hôn mê. Sau khi nuốt, năm tháng trôi, thức tỉnh lần nữa, xác nhận đã chuẩn bị cho lần ngủ-thức tỉnh tiếp theo với đối tượng là Vương Lâm.","anchor":"Bản thân ta cũng đã quên bổn tôn ở đâu, ngươi tìm thế nào được!","bridge":true,"khoang":"@c1626"},{"chuong":"@c1627","importance":"major","mucCt":"ky","tieuDe":"Lộ thân phận thật — thực thể nguyên thủy nuốt phách Thất Thải Tiên Tôn","text":"Qua luân hồi, toàn bộ bản chất Thiên Vận Tử bị phơi bày: hắn KHÔNG phải tam hồn thất phách của Thất Thải Tiên Tôn mà là một thực thể cổ xưa tồn tại từ tinh vực tử vong (trước khi có sinh mạng trong động phủ). Lần thức tỉnh đầu tiên, hắn hiện ra từ cái khe khổng lồ vô thanh vô tức trong tinh không, nuốt phách nguyên thủy của Thất Thải Tiên Tôn để trưởng thành. Lần thức tỉnh thứ hai ở thái cổ, hắn nuốt thất phách của Thất Thải Tiên Tôn. Đã trải qua hơn chín mươi bảy lần cắn nuốt — tỉnh giấc, lực lượng thôn phệ suy yếu dần (lần thứ ba nuốt cả tu chân tinh, lần chín mươi chỉ nuốt được người). Hắn thay đổi hình dạng qua các thời đại: lão già áo da thú ở thái cổ, nam tử thanh sam ở thượng cổ, nữ tử kiều mị, rồi Thiên Vận Tử hiện tại. Mục đích cuối cùng: mạo danh Thất Thải Tiên Tôn hoàn chỉnh và nắm luân hồi. Hắn tuyên bố đây là lần ngủ say cuối cùng, phát động kế hoạch luân hồi vạn cổ — gần ba nghìn phân thân ở tứ đại tinh vực đồng loạt xuyên mi tâm tự hủy, hồn phách hợp nhất lao vào phân thân Vương Lâm ở Triệu Hà để đoạt xác. Hồn phách tràn vào thân thể phân thân Vương Lâm ngày càng lớn mạnh, mơ hồ chiếm toàn bộ.","anchor":"tỉnh giấc lần này ta sẽ hoàn thành kế hoạch luân hồi vạn cổ"},{"importance":"major","mucCt":"ky","chuong":"@c1628","tieuDe":"Hé lộ chân tướng: chính là Thiên Đạo, bổn tôn là nửa nghịch la bàn","text":"Chân tướng được hé lộ: Thiên Vận Tử chính là Thiên Đạo mà vô số người tìm kiếm bấy lâu. Bổn tôn thật sự là nửa nghịch la bàn mang ấn ký cổ xưa, nằm sâu trong tu chân tinh không sinh mạng. Vốn là thiên đạo không có linh trí, sau khi cắn nuốt tiên nhân Liên Đạo Phi, hấp thu phần thần thức tự bạo cùng phần tham lam và tính xấu mà sinh ra suy nghĩ, hóa hình thanh niên. Để bổn tôn (nửa nghịch la bàn) tại tu chân tinh vì khí tức không ai cảm nhận được, nơi đó an toàn nhất. Đang tung vô số hồn phách từ Triệu Hà, Côn Hư, La Thiên, Vân Hải dung nhập vào phân thân Vương Lâm, tuyên bố có thể chiếm cứ thân thể phân thân trước khi bổn tôn bị tìm ra.","anchor":"Ngươi lấy cái gì mà muốn nhanh hơn lão phu"},{"importance":"major","mucCt":"ky","chuong":"@c1629","tieuDe":"Hoàn thành thức tỉnh thứ 99, bị đoạt bổn tôn","text":"Hồn phách từ tứ đại tinh vực hội tụ chiếm cứ phân thân Vương Lâm qua Luân Hồi nhất thể thuật, thôn phệ từ bên trong khiến phân thân biến hình thành Thiên Vận Tử đầu tóc bạc phơ. Hoàn thành lần thức tỉnh thứ 99, tự xưng mình chính là thiên đạo, trên người tràn ngập sương mù hình thái thiên đạo. Toan rời đi nhưng bị Lam Mộng Đạo Tôn chặn trước mặt, Thanh Lâm và Hồng Sam Tử áp sát, vung tay triệu sương mù vô tận giao chiến ngắn. Bổn tôn thật sự (nửa cái la bàn chôn ở Côn Hư) bị bổn tôn Vương Lâm đoạt mất trước khi kịp dung hợp.","anchor":"Chín mươi chín lần thức tỉnh. Lão phu rốt cục đã tỉnh lại lần này. Thiên đạo, lão phu chính là thiên đạo!"},{"chuong":"@c1630","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm tiêu diệt hoàn toàn","text":"Kinh hoàng khi thấy Vương Lâm cầm nửa la bàn — bổn tôn của hắn. Tự xưng thức tỉnh chín mươi chín lần và là thiên đạo, thi triển Thiên đạo nhất thể triệu hồi miệng khổng lồ nhưng thất bại. Đánh lui Lam Mộng Đạo Tôn rồi áp sát Vương Lâm, nhưng bị ấn ký phân thân tiêu hủy lần lượt bảy đạo bổn nguyên, nguyên thần, hồn phách — thân thể tan nát, 2999 hồn phách nổ tung. Nhận ra U Minh Thú là bộ phận thân thể hắn năm xưa bị thần thức Liên Đạo Phi tự bạo phân ra. Bổn tôn (nửa la bàn) bị đưa vào U Minh Thú, toàn bộ 2999 hồn phách bỏ chạy nhưng bị U Minh Thú hút nuốt sạch.","anchor":"Ta đã thức tỉnh chín mươi chín lần, ta chính là thiên đạo!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1631","tieuDe":"Được nhắc là bộ phận thiên đạo","text":"Được Vương Lâm hồi tưởng: cũng là một bộ phận của thiên đạo, hắn thờ phụng thiên vận thực chất là thờ chính bản thân mình.","anchor":"Thiên Vận Tử cũng là một bộ phận của thiên đạo"},{"chuong":"@c1632","importance":"bridge","mucCt":"gon","text":"Được nhắc: hồn phách phân thân Thiên Vận Tử không còn trong phân thân Vương Lâm, bị coi là cây đinh đã rút ra.","anchor":"Một thứ duy nhất khác biệt chính là không còn hồn phách của phân thân Thiên Vận Tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Nạn nhân — Thiên Vận Tử nuốt thất phách và phách nguyên thủy của Thất Thải Tiên Tôn để trưởng thành, mục đích mạo danh thành Thất Thải Tiên Tôn hoàn chỉnh","ghiChu":"Thiên Vận Tử tự nhận từng giúp Thất Thải Tiên Tôn rất nhiều khi còn sống"}],"tuiDo":{},"diem":[{"text":"Cưỡi tảng đá như sao băng qua Chu Tước tinh, cứu Vương Lâm khỏi cảm ngộ thiên đạo luân hồi suýt lạc vào nguy hiểm","chuong":"@c0241"},{"text":"Tổ chức đại thọ vạn năm trên Thiên Vận Tinh, giảng đạo phân tu đạo làm ba bước và thi triển Dẫn Tiên thuật làm nhục Lăng Thiên Hầu","chuong":"@c0466"},{"text":"Nhận Vương Lâm làm đệ tử chân chính, mở tâm thần bảy màu chứa 3600 phân thân cho tự chọn thần thông cấm pháp","chuong":"@c0474"},{"text":"Lần lượt mở hai đạo phong ấn, giải phóng tu vi Thiên Nhân nhất suy và nhị suy trong đại chiến","chuong":"@c1008"},{"text":"Chủ động hiến hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật nhằm hoàn thành âm mưu hai ngàn năm","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: thực thể nguyên thủy nuốt phách Thất Thải Tiên Tôn, bổn tôn là nửa nghịch la bàn — chính là Thiên Đạo — rồi bị Vương Lâm đoạt bổn tôn và tiêu diệt hoàn toàn","chuong":"@c1628"}]},"trangThai":"khong-ro","cn":"天运子","gioiTinh":"nam","aliases":["Thiên Đạo"],"canhGioiCaoNhat":"Thiên đạo (lần thức tỉnh thứ 99)","vaiTro":"Chưởng môn Thiên Vận Tông — sư tôn Vương Lâm, thành viên Trưởng Lão Đoàn, thực thể Thiên Đạo ẩn thân","tinhCach":"Toan tính thâm sâu, bố cục hàng ngàn năm bằng thuật thiên vận và la bàn đen trắng; uy nghi điềm tĩnh trước biến cố, thản nhiên giảng đạo và chủ trì đại sự; cứng rắn quyết liệt trước cường địch, sẵn sàng tự phá phong ấn đánh đổi tất cả; che giấu dã tâm thôn phệ dưới vẻ hòa ái sư tôn, bản chất là thực","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông kiêm thành viên Liên Minh Trưởng Lão Đoàn, tu vi thực tế vượt Hóa Thần với ba đạo phong ấn phong tỏa cảnh giới Thiên Nhân, sở hữu huyết tinh sát khí cực mạnh và thần thông bảy màu độc đáo. Suốt hàng ngàn năm, ông bố cục lên Vương Lâm qua lạc ấn, kế hoạch Đông Hải Yêu Linh và Luân Hồi Toàn Thể Thuật, nhận đệ tử chân chính rồi ngầm lợi dụng làm vật chủ dung hợp. Chân tướng cuối cùng được phơi bày: Thiên Vận Tử chính là thực thể nguyên thủy đã nuốt phách Thất Thải Tiên Tôn, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo — và sau chín mươi chín l"},{"id":"that-phi","name":"Thất phi","aliases":["tiên phi thứ bảy","Viễn cổ Thất Phi"],"nguon":["@c1589","@c1594","@c1596","@c1597"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1589","text":"Đang ẩn tu trong khe khổng lồ ở Thái Cổ Tinh Thần, mở mắt lộ ánh sáng kỳ dị khi cảm nhận Vương Lâm xuất hiện.","anchor":"giờ phút này thất phi mở hai mắt, lộ ra ánh sáng kỳ dị"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Oán hận lao tới giết Vương Lâm","text":"Sắc mặt tái nhợt, oán hận ngập trời, muốn tự tay giết Vương Lâm, cùng Diệu Âm đạo tôn và Cửu Thiên ma tôn đồng loạt hướng về phía hắn.","anchor":"Vương Lâm, ta muốn tự tay giết ngươi"},{"mucCt":"vua","text":"Xuất hiện cùng Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn vây Vương Lâm, khi thấy cung Lý Quảng hiện ra liền sững lại. Bị mũi tên trọng thương phun máu tươi nhưng nhờ là tiên phi có chí bảo phòng thân nên may mắn trốn thoát.","anchor":"chỉ có thất phi là sau khi lui lại liền phun một ngụm máu tươi, bị trọng thương dưới một tiễn vừa rồi, nhưng vì là tiên phi, có chí bảo phòng thân nên mới may mắn trốn thoát","bridge":true,"khoang":"@c1596"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Đại tỷ (đệ nhất phi)","ghiChu":"Cùng là thất phi Thất Đạo Tông, thất phi gọi nàng là đại tỷ"}],"tuiDo":{}}},{"id":"viem-long","name":"Viêm long","aliases":["Tiểu Hồng","huyết viêm long","rồng ngốc"],"tabs":{"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1590","tieuDe":"Tái xuất và bị Vương Lâm chặn đường","text":"Sau trăm năm kể từ vùng đất Điên Lạc, đã tự lập Tiên Long Đạo với hơn ngàn tu sĩ, sống hưởng thụ trên đài linh thạch ngàn trượng trong thế giới động phủ. Khi đoàn Tiên Long Đạo tiến gần khu vực Vương Lâm, bị thần thức các toàn năng Thái Cổ Tinh Thần áp chế, hoảng sợ gần vỡ mật, tự hạ mình xưng chỉ là một con rắn. Bỏ đài linh thạch định tẩu nhưng bị Vương Lâm chặn đường, ngốc nghếch phun hỏa cầu tấn công nhưng bị phá tan dễ dàng, cuối cùng run rẩy choáng váng nhận ra thực lực khủng khiếp của đối phương.","anchor":"con rồng ngốc nghếch này gào lên một tiếng nức nở"},{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Bị Vương Lâm thu phục, lộ lai lịch Liên Đạo Phi","text":"Thi triển toàn lực bao phủ ngọn lửa tháo chạy nhưng cảm nhận hỏa bổn nguyên của Vương Lâm mạnh hơn rất nhiều. Bị ấn quyết Chu Tước kích hoạt ấn ký trên mi tâm, đau đớn kêu thảm rồi đầu hàng. Hiện nguyên hình vạn trượng nhìn về Tiên Long Tông mà khóc. Xin Vương Lâm phối hợp diễn kịch giữ thể diện, tuyên bố Vương Lâm làm phó tông chủ trước hơn ngàn môn đồ rồi sai họ lui về. Khai nhận tên Tiểu Hồng do chủ nhân cũ đặt, xác nhận đến từ Tiên Cương đại lục, theo Liên Đạo Phi cùng một kẻ khác vào Thái Cổ Tinh Thần, bị lừa tới Thất Đạo Tông rồi bị bắt. Xác nhận Liên Đạo Phi đã chết. Bị Vương Lâm thu vào khe trữ vật.","anchor":"Chủ nhân bảo ta gọi là Tiểu Hồng rất hay, thế nên mới đặt ta là Tiểu Hồng!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân mới, dùng ấn quyết Chu Tước thu phục","ghiChu":"@c1591"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Chủ nhân cũ, đã chết","ghiChu":"Theo Liên Đạo Phi từ Tiên Cương đại lục vào Thái Cổ Tinh Thần @c1591"}],"tuViMoc":[],"diem":[{"text":"Tự xưng tiên long nhưng thực lực chỉ tương đương Không Niết sơ kỳ, bị Vương Lâm dùng ấn quyết Chu Tước trấn áp dễ dàng.","chuong":"@c1591"},{"text":"Linh trí cực cao, nói tiếng người lưu loát, xin chủ nhân mới diễn kịch giữ thể diện trước đám môn đồ.","chuong":"@c1591"},{"text":"Chủ nhân cũ là Liên Đạo Phi, trong thân ẩn chứa huyết mạch tiên nhân.","chuong":"@c1591"}]},"nguon":["@c1590","@c1591"],"canhGioiCaoNhat":"Không Niết sơ kỳ (tương đương)","trangThai":"song","vaiTro":"Linh thú của Liên Đạo Phi, sau bị Vương Lâm thu phục, tự xưng tiên long lập Tiên Long Tông","tinhCach":"Háo danh, sợ mạnh, khóc nhè, linh trí cao, trung thành với chủ","blurb":"Huyết viêm long tự xưng tiên long, lập Tiên Long Tông nô dịch hơn ngàn tu sĩ trong Thái Cổ Tinh Thần. Thực chất là thú cưỡi cũ của Liên Đạo Phi, trong thân ẩn chứa huyết mạch tiên nhân.","cn":"炎龙","gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Long Đạo","trangThai":"gan-bo"}]},{"id":"lien-dao-phi","name":"Liên Đạo Phi","cn":"连道飞","aliases":["người điên"],"gioiTinh":"nam","trangThai":"khong-ro","blurb":"Liên Đạo Phi là cường giả từ Tiên Cương đại lục, tự xưng bổn vương, chủ nhân cũ của viêm long Tiểu Hồng và là cố nhân của Vương Lâm. Vì mê sắc đẹp Phàn San Mộng mà bị dụ tới Thất Đạo Tông, một mình giao chiến tứ đại chiến tướng cùng đệ tử của tông môn, cuối cùng bị thiên đạo nuốt — nhưng nhờ bất diệt thể mà vẫn chưa thực sự diệt vong. Viêm long Tiểu Hồng xác nhận hắn đã chết, song thân phận và kết cục thực sự vẫn là ẩn số.","vaiTro":"Chủ nhân cũ của viêm long Tiểu Hồng — cường giả bí ẩn tự xưng bổn vương","tinhCach":"Điên cuồng, ngạo mạn dám một mình chiến quần hùng; háo sắc, dễ bị mỹ nhân dụ; ý chí kiên cường, sở hữu bất diệt thể vẫn tồn tại sau khi bị thiên đạo nuốt","theLuc":[],"tabs":{"diem":[{"text":"Viêm long Tiểu Hồng xác nhận Liên Đạo Phi là chủ nhân cũ của nó và đã chết","chuong":"@c1591"},{"text":"Vì mê sắc đẹp Phàn San Mộng mà bị nàng dụ tới Thất Đạo Tông để phá cuộc","chuong":"@c1599"},{"text":"Tu vi thông thiên, một mình đánh tứ đại chiến tướng và đệ tử Thất Đạo Tông; bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn sống","chuong":"@c1600"},{"text":"Lộ diện trong ký ức dưới hình dạng nam tử trung niên áo xám, phá sơn môn Tiên Tôn","chuong":"@c1606"},{"text":"Được Vương Lâm nhắc là người đầu tiên trong vạn cổ bị thiên đạo nuốt, đồng thời là cố nhân của hắn","chuong":"@c1631"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Viêm long xác nhận đã chết","text":"Viêm long Tiểu Hồng xác nhận Liên Đạo Phi chính là chủ nhân cũ của nó, đã chết. Vương Lâm nhớ lại lời người điên năm xưa nhiều lần gọi Tiểu Hồng và nói thứ đồ của bổn vương ở chỗ Tiểu Hồng.","anchor":"Liên Đạo Phi là chủ nhân trước kia của ta.đáng tiếc là hắn đã chết rồi."},{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Bị Phàn San Mộng dụ tới Thất Đạo Tông","text":"Được Phàn San Mộng nhắc: vốn mê sắc đẹp nàng, bị nàng dụ tới Thất Đạo Tông để phá cuộc.","anchor":"Ta đem tin tức này nói cho Liên Đạo Phi vốn vẫn không buông tha sắc đẹp của ta"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Bị thiên đạo nuốt — nhờ bất diệt thể vẫn sống","text":"Được kể lại: tu vi thông thiên, một mình đánh tứ đại chiến tướng và đệ tử Thất Đạo Tông. Cuối cùng bị Thất Thải Thiên Tôn triệu hồi thiên đạo nuốt, trọng thương. Nhờ tiên nhân bất diệt thể không chết, vẫn ở đâu đó trong thế giới động phủ.","anchor":"lấy tiên nhân bất diệt thể của hắn thì sẽ không thể chết được"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Lộ diện trong ký ức — phá sơn môn Tiên Tôn","text":"Trong ký ức Thất Thải Tiên Tôn xuất hiện dưới hình dạng nam tử trung niên áo xám, tướng mạo anh tuấn, hai mắt hàn quang, kiêu hãnh tới cực điểm. Cười điên cuồng phá hủy lầu các sơn môn Tiên Tôn, phía sau có viêm long đỏ rực bay múa và thiếu niên đầu trọc áo vải xanh đang chém giết với Thanh Long chiến tướng. Xưng bổn vương, thừa nhận bị Phàn San Mộng câu dẫn, nói chỉ vì mảnh vỡ mà Tiên Tôn đạt được. Khi Tiên Tôn triệu hồi Thiên Đạo đồng quy vu tận, biến sắc thốt lên Thiên Đạo.","anchor":"Là nàng câu dẫn bổn vương, nhưng bổn vương đối với đạo lữ của người khác không có hứng thú"},{"importance":"bridge","mucCt":"gon","chuong":"@c1631","tieuDe":"Được nhắc là cố nhân bị thiên đạo nuốt","text":"Được Vương Lâm nhắc: là người đầu tiên bị thiên đạo nuốt trong vạn cổ, và là cố nhân của hắn.","anchor":"người đầu tiên bị thiên đạo nuốt trong năm tháng vạn cổ lại trờ thành cố nhân của ta"},{"chuong":"@c1632","importance":"bridge","mucCt":"gon","text":"Được nhắc: ngày đó bị U Minh thú nuốt nên mới sợ hãi.","anchor":"Ngày đó Liên Đạo Phi bị u Minh thú nuốt nên mới có cảm giác sợ hãi như vậy"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm long","tag":"khac","quanHe":"Thú cưỡi / linh thú trung thành","ghiChu":"@c1591"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người từng gặp khi còn sống (người điên)","ghiChu":"@c1591"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Mục tiêu tấn công","ghiChu":"Phá sơn môn để đoạt mảnh vỡ, bị Phàn San Mộng câu dẫn"},{"ten":"Phàn San Mộng","tag":"khac","quanHe":"Người câu dẫn","ghiChu":"Nàng câu dẫn Liên Đạo Phi tới tấn công Tiên Tôn"}],"tuiDo":{}},"nguon":["@c1591","@c1599","@c1600","@c1606","@c1631","@c1632"]},{"id":"chien-khong-liet","name":"Chiến Không Liệt","aliases":["chiến lão quỷ"],"nguon":["@c1592","@c1600"],"tabs":{"kinhLich":[{"chuong":"@c1592","importance":"normal","tieuDe":"Cảnh giác trước khe nứt viễn cổ tiên vực","text":"Đang ngồi trong Lôi Tiên giới, nghe tiếng chấn động liền đứng phắt dậy, vọt ra Thiểm Lôi tộc, nhìn chằm chằm khe nứt tinh không, hai mắt lộ hàn quang, nhận ra đây là viễn cổ tiên vực.","anchor":"Đôi mắt hắn lộ ra ánh sáng kỳ dị, nhìn chằm chằm vào cái khe vừa bị xé mở trong tinh không","mucCt":"vua"},{"importance":"major","mucCt":"ky","chuong":"@c1600","tieuDe":"Bị suy luận là hồn thứ hai Thất Thải Thiên Tôn","text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lực, giải thích vì sao đủ tư cách đối kháng đạo nhân bảy màu và vì sao Chưởng Tôn e sợ khi gặp lại. Đây là suy luận của Vương Lâm, chưa được xác nhận tuyệt đối.","anchor":"chẳng lẽ Chiến lão quỷ này chính là hồn thứ hai"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Gặp Vương Lâm tại Lôi Trì, từ nghi ngờ chuyển sang cung kính bái kiến, báo tin trọng bảo","chuong":"@c0733"},{"text":"Được Vương Lâm chỉ ra chiến ý Chiến gia thiếu niềm tin bất khuất, chấn động ngộ đạo","chuong":"@c0809"},{"text":"Tu vi đạt Tịnh Niết viên mãn, chỉ huy gần trăm tu sĩ kéo tu chân tinh phục vụ chiến tranh Ngoại Vực","chuong":"@c1388"},{"text":"Chuẩn bị tự bạo cùng Tây Tử Phượng và Thân Công Hổ khi phòng tuyến sụp đổ","chuong":"@c1559"},{"text":"Được tiết lộ là người duy nhất trong lịch sử động phủ vượt tám lần huyền kiếp với thân phận tu sĩ bên trong","chuong":"@c1568"},{"text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn, chứa ý cảnh và bổn nguyên lực","chuong":"@c1600"}]},"vaiTro":"Tu sĩ Chiến gia — hồn thứ hai Thất Thải Thiên Tôn, truy tùy trung thành của Vương Lâm","tinhCach":"thận trọng biết thời thế, suy đoán sắc bén trước cường giả; cung kính cầu đạo, sùng kính Vương Lâm sau khi chứng kiến uy lực; mang chiến ý bất khuất cố hữu của Chiến gia; trung thành kiên định, sẵn sàng tự bạo vì đại cục","blurb":"Chiến Không Liệt là tu sĩ Chiến gia xuất thân từ Lôi Tiên Giới, ban đầu ở cảnh Dương Thực viên mãn, về sau đạt tới Tịnh Niết viên mãn và vượt qua tám lần huyền kiếp — là người duy nhất trong lịch sử động phủ dựa vào thân phận tu sĩ bên trong mà đạt tới mốc này. Hắn gặp Vương Lâm tại Lôi Trì, từ nghi ngờ chuyển sang cung kính bái kiến, được Vương Lâm chỉ điểm về niềm tin bất khuất của chiến ý Chiến gia, rồi theo Vương Lâm suốt hành trình từ tranh đoạt phong hào đến chiến tranh Ngoại Vực. Về sau bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lự"},{"id":"phong-ton","name":"Phong Tôn","gioiTinh":"nam","theLuc":[{"ten":"Viễn Cổ Tiên Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Tiên nhân viễn cổ mà Thanh Lâm xưng là đệ tử, được nhắc tên khi Thanh Lâm bái kiến đám tiên nhân bước ra từ khe nứt viễn cổ tiên vực.","vaiTro":"Sư tôn của Thanh Lâm, tiên nhân viễn cổ","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Thanh Lâm xưng là đệ tử của Phong Tôn khi bái kiến tiên nhân viễn cổ","chuong":"@c1592"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Lâm","tag":"su-mon","quanHe":"Đệ tử"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1592"]},{"id":"nam-van-tu","name":"Nam Vân Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Cùng Hồng Sam Tử bước ra đối mặt tiên nhân nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Hồng Sam Tử, Nam Vân Tử sửng sốt một chút, lập tức thần sắc đại biến"},{"chuong":"@c1624","importance":"minor","mucCt":"gon","tieuDe":"Ở lại trấn giữ tiên giới","text":"Chọn ở lại tiên giới thay vì truy theo, vì bậc toàn năng không nhiều, đi hết bất lợi.","anchor":"Nam Vân Tử hơi suy nghĩ một chút, không đi theo mà lựa chọn ở lại nơi này"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được Chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận bảo vệ Vân Hải, đồng thời đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công bàn tay khổng lồ của kẻ địch","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh","chuong":"@c1520"},{"text":"Dốc toàn lực trợ giúp Vương Lâm mở Không Môn tại thời điểm mấu chốt của đại chiến","chuong":"@c1524"},{"text":"Chọn ở lại trấn giữ tiên giới sau khi xuất chinh, vì bậc toàn năng không nhiều","chuong":"@c1624"}]},"nguon":["@c1593","@c1624"],"vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được Chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận chiến đấu bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và phối hợp ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan, ông phục hồi rồi cầm đầu lực lượng cuối cùng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vươ"},{"id":"thanh-long-thanh-hoang","name":"Thanh Long Thánh Hoàng","aliases":["Thanh Long","Thanh Long chiến tướng"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện bên ngoài tiên giới dưới hình dạng lão già, hừ lạnh nhìn đám tiên nhân xông vào. Ôm quyền xin lỗi thân ảnh Vương Lâm, hứa quản giáo nghiêm, giữ giao dịch cũ, cam kết viễn cổ tiên vực sẽ không giết tu sĩ giới nội.","anchor":"Lão phu quản giáo không nghiêm, đã tới chậm một bước, mong đạo hữu lượng thứ","bridge":true,"khoang":"@c1593"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Chứng kiến uy lực cung Lý Quảng, cảnh giác Vương Lâm","text":"Đứng trong tinh không giới nội chứng kiến viễn cổ tiên vực giới ngoại chấn động bởi cung Lý Quảng, thở dài nói không nên trêu chọc người này.","anchor":"chúng ta không nên trêu chọc là tốt nhất"},{"importance":"bridge","mucCt":"gon","chuong":"@c1606","tieuDe":"","text":"Trong ký ức đại chiến, đang chém giết với thiếu niên đầu trọc áo vải xanh phía sau Liên Đạo Phi tại sơn môn Thất Thải Tiên Tôn.","anchor":"Người này Vương Lâm cũng không xa lạ, đó là Thanh Long chiến tướng trong tứ đại chiến tướng!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1626","tieuDe":"Máu thiên đạo bị Thiên Vận Tử cướp","text":"Được nhắc gián tiếp: máu thiên đạo trên tay Thiên Vận Tử trong huyễn cảnh quá khứ là thứ bị cướp từ tay Thanh Long Thánh Hoàng.","anchor":"máu thiên đạo bị Thiên Vận Tử cướp đi từ tay Thanh Long Thánh Hoàng"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Thần niệm được giấu trong Thanh quang thuẫn gửi lời cầu cứu khi bị phong ấn","chuong":"@c0923"},{"text":"Thoát khỏi phong ấn của Tiên Đế Thanh Lâm, triệu hoán Thanh Long phá hủy ngọn núi trấn áp","chuong":"@c1044"},{"text":"Chỉnh hợp Tứ Thánh Tông thành một tông duy nhất và xưng thánh tôn, thu thái cổ thánh khí các tông","chuong":"@c1054"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông, đánh bại tông chủ Đệ Nhất Vương","chuong":"@c1147"},{"text":"Tái xuất cùng Tứ Thánh Tông tham chiến tại Chu Tước Tinh, tu vi đạt thiên nhân ngũ suy","chuong":"@c1520"},{"text":"Máu thiên đạo bị Thiên Vận Tử cướp mất","chuong":"@c1626"}]},"nguon":["@c1593","@c1594","@c1606","@c1626"],"trangThai":"song","gioiTinh":"nam","vaiTro":"Thánh Hoàng hùng mạnh nhất Tứ Thánh Tông, sau chỉnh hợp bốn tông xưng thánh tôn","tinhCach":"Năm xưa hào sảng phóng khoáng, nay âm trầm tâm cơ sâu do ảnh hưởng máu thiên đạo; giỏi bày mưu giăng bẫy, quyết đoán cứng rắn trong việc chỉnh hợp và thu phục các thế lực","blurb":"Thanh Long Thánh Hoàng là Thánh Hoàng hùng mạnh nhất của Tứ Thánh Tông, vừa nhậm chức liền đi điều tra nguyên nhân Tiên giới sụp đổ, bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới, chỉ kịp để lại thần niệm cầu cứu trong Thanh quang thuẫn. Sau khi được đoàn của Vương Lâm giải cứu, ông trở về chỉnh hợp Tứ Thánh Tông thành một tông duy nhất và xưng thánh tôn, tính tình đổi khác do ảnh hưởng máu thiên đạo, bế quan trấn áp nội hoạ rồi ra tay thu phục các thế lực, một mình đánh bại Thi Âm Tông. Vài thập niên sau tái xuất cùng Tứ Thánh Tông trở thành lực lượng hùng mạnh tham chiến "},{"id":"tien-phi-thu-bay","name":"Tiên phi thứ bảy","aliases":["Thất phi","tiên phi thứ bảy"],"gioiTinh":"nu","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đạo lữ cũ của Thất Thải Tiên Tôn, bị hắn vứt bỏ khi lâm nguy. Chỉ huy đệ tử Thất Đạo Tông phong ấn trong viễn cổ tiên vực giới ngoại, đệ tử này là lá bài sát thủ cuối cùng của nàng.","vaiTro":"Tiên phi chỉ huy đệ tử Thất Đạo Tông trong viễn cổ tiên vực giới ngoại","tinhCach":"Kiên quyết; mưu tính lâu dài","tabs":{"diem":[{"text":"Đạo lữ cũ bị Thất Thải Tiên Tôn vứt bỏ khi lâm nguy, nắm giữ lá bài sát thủ cuối cùng là đám đệ tử Thất Đạo Tông phong ấn trong viễn cổ tiên vực giới ngoại.","chuong":"@c1593"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1593","tieuDe":"Sắc mặt kịch biến, lao về phía Vương Lâm","text":"Khi rõ mục đích Vương Lâm muốn hủy viễn cổ tiên vực giới ngoại, sắc mặt biến hóa kịch liệt, lao thẳng về phía hắn.","anchor":"sau khi rõ mục đích của Vương Lâm, tiên phi thứ bảy sắc mặt biến hóa kịch liệt"},{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra đại tỷ Phàn San Lộ còn sống","text":"May mắn sống sót nhờ pháp bảo sau khi chịu lực cung Lý Quảng. Nhận ra ấn quyết đại tỷ, thất thanh xác nhận đệ nhất phi còn sống.","anchor":"Đại tỷ! Người không chết!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ cũ, bị Thất Thải Tiên Tôn vứt bỏ khi lâm nguy"},{"ten":"Phàn San Lộ","tag":"dong-minh","quanHe":"Đại tỷ (đệ nhất phi)","ghiChu":"Nhận ra ấn quyết đại tỷ từ hắc động, xác nhận nàng còn sống"},{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Đại tỷ đồng môn","ghiChu":"Đệ nhất phi Thất Đạo Tông, tưởng đã chết nay xác nhận còn sống"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1593","@c1597"]},{"id":"huyen-vu","name":"Huyền Vũ","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Đoán Vương Lâm có lực bắn ba mũi tên","text":"Phân tích rằng Vương Lâm tâm trí cẩn thận không để lộ nhược điểm, đoán hắn nhất định có lực lượng bắn ba mũi tên chứ không chỉ hai, bốn chiến tướng giới nội đều gật đầu đồng ý.","anchor":"Ta đoán là hắn nhất định có lực lượng bắn ba mũi tên"},{"chuong":"@c1632","importance":"bridge","mucCt":"gon","text":"Đứng bên trái Vương Lâm uy hiếp, kéo Chiến lão quỷ vào cuộc tạo thêm áp lực cho Vương Lâm.","anchor":"Tin rằng cho dù là Chiến đạo hữu thì đối với nơi có con thú này cũng rất hứng thú phải không"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1594","@c1632"],"gioiTinh":"nam"},{"id":"phan-san-lo","name":"Phàn San Lộ","cn":"樊山露","aliases":["đệ nhất phi"],"gioiTinh":"nữ","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"da-roi"},{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đệ nhất phi trong thất phi của Thất Đạo Tông, thân phận thật là muội muội của Phàn San Mộng (đạo lữ Thất Thải Thiên Tôn), đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Bị Thất Thải Thiên Tôn gây thương tích không thể khôi phục, ẩn náu trong khe sâu Yêu Tông cũ, sau đó xuất hiện cứu Vương Lâm và đề nghị hợp tác chống lại kẻ thù chung. Trao cho Vương Lâm bản đồ tế đàn cùng thuật thôn hồn, thiết lập liên minh dựa trên thệ huyết.","vaiTro":"Đệ nhất phi Thất Đạo Tông — đệ tử hạch tâm Đại Hồn Môn, đồng minh hợp tác với Vương Lâm","tinhCach":"Cẩn trọng, không tin bất cứ ai từ Tiên Cương đại lục; kiên nhẫn chờ đợi cơ hội báo thù; trọng lời hứa, giữ ước hẹn","tabs":{"diem":[{"text":"Xuất thủ đỡ chỉ phong bảy màu cứu Vương Lâm, tiết lộ thân phận đệ nhất phi và đề nghị hợp tác","chuong":"@c1597"},{"text":"Huyết tế kích nổ sư thú dụ mãnh thú cản đường, thi triển Đại Hồn đạo Dẫn Hồn Minh phản kích đạo nhân bảy màu","chuong":"@c1598"},{"text":"Bị Vương Lâm vạch trần đang giả dạng Phàn San Mộng, buộc phải thừa nhận thân phận thật","chuong":"@c1603"},{"text":"Trao ngọc giản chứa bản đồ tế đàn và thuật thôn hồn cho Vương Lâm, lập thệ huyết liên minh","chuong":"@c1605"},{"text":"Bị Thất Thải Thiên Tôn gọi tên chất vấn sự phản bội, xác nhận cùng phe tấn công sơn môn","chuong":"@c1606"}],"kinhLich":[{"chuong":"@c1597","importance":"major","mucCt":"ky","tieuDe":"Đỡ đòn cứu Vương Lâm, tiết lộ thân phận và đề nghị hợp tác","text":"Từ hắc động vươn ngọc thủ đeo nhẫn xanh biếc ngón giữa đỡ chỉ phong bảy màu của đạo nhân bảy màu, thi triển Thái Ngọc Thất Thủ Ấn nhưng bị khí bảy màu xâm nhập rên đau. Cứu Vương Lâm thoát vào hắc động tới khe sâu Yêu Tông cũ. Tiết lộ tên thật Phàn San Lộ, từng là đệ nhất phi Thất Đạo Tông, muội muội Phàn San Mộng — đạo lữ Thất Thải Thiên Tôn. Kể quá khứ bị phản bội: Thất Thải Thiên Tôn dùng tỷ tỷ làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín, phong kín Thất Đạo Tông, gây thương tích cho nàng mãi không khôi phục. Đề nghị Vương Lâm giết Thất Thải Thiên Tôn đoạt sơn môn, hứa giúp nhập Đại Hồn Môn và cầu sư tôn giảm kiếp nạn nhập giới Tiên Cương đại lục. Khẳng định Phàn San Mộng chưa chết, đang ở Tiên Cương đại lục.","anchor":"muội muội của đạo lữ của Thất Thải Thiên Tôn – Phàn San Mộng, tên ta là Phàn San Lộ!"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Phản kích đạo nhân bảy màu, cầu viện tỷ tỷ phá vây","text":"Dùng huyết tế kích nổ sư thú dụ hơn trăm mãnh thú cản đường. Thi triển Đại Hồn đạo Dẫn Hồn Minh, phun máu hóa trường đao đỏ chém chín hỏa điểu. Bị đạo nhân bảy màu nhận là đệ nhất phi của bổn tôn. Trong nguy cấp triệu thủ ấn bảy màu, gọi tỷ tỷ trợ giúp — liên kết với nữ tử giống hệt mình trong núi băng ở Tiên Cương đại lục, nhận lực lượng xuyên không gian phá hủy tinh thể vây khốn. Kiệt sức, được Vương Lâm mang vào thuyền lớn màu tím.","anchor":"Ta thi triển toàn lực rồi, mang ta đi!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Thân xác bị Phàn San Mộng chiếm, được gọi là muội muội","text":"Thân xác trên thuyền thực chất do Phàn San Mộng chiếm/chia sẻ, được Phàn San Mộng gọi là muội muội — người đã tuyển Vương Lâm hợp tác.","anchor":"Không hổ là người được muội muội ta tuyển làm người hợp tác"},{"chuong":"@c1603","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm vạch trần giả dạng Phàn San Mộng","text":"Khi Vương Lâm sắp chiếm thuyền, nàng mở phòng hộ cho đạo nhân bảy màu vào nhưng bị Vương Lâm phản chế, buộc phải dùng toàn lực trì hoãn đạo nhân bảy màu ở tầng hai. Sau hai canh giờ tầng hai sụp đổ, nàng phun máu tươi. Tiến vào tầng bốn tiếp tục dụ Vương Lâm trao đổi thệ huyết. Bị Vương Lâm vạch trần danh tính thực là Phàn San Lộ — từ đầu đã phun máu biến hóa thần sắc khí tức giả dạng Phàn San Mộng, toàn bộ tầng hai đến tầng bốn cùng đạo nhân bảy màu trên thuyền đều là huyễn giới do nàng bày ra. Cười khổ phủ nhận nhưng không thể ngăn Vương Lâm đánh sập tầng ba.","anchor":"Hắn từng bước một cướp thế chủ động mà ta vẫn nắm trong tay"},{"mucCt":"ky","text":"Trong ảo cảnh kinh hãi lui lại, triệu kiếm bảy màu và hư ảnh đóa hoa bảy màu phòng thủ. Khi thức tỉnh mắt mở to mê man, bản thân cũng không biết đang ở trong ảo giác. Bị Vương Lâm chỉ ra đã rơi vào ảo thuật của tỷ tỷ Phàn San Mộng, sắc mặt tái nhợt phun máu tươi xác nhận. Tiết lộ Đại Hồn Môn nổi danh nhất bởi ảo thuật, tỷ tỷ đã đạt huyễn cảnh song trọng, nếu tam trọng thì không ai thoát.","anchor":"Đại Hồn Môn nổi danh nhất đúng là ảo thuật. Thuật này không phải ai cũng học được","bridge":true,"khoang":"@c1604"},{"chuong":"@c1605","importance":"normal","mucCt":"vua","tieuDe":"Trao bản đồ tế đàn và thệ huyết cho Vương Lâm","text":"Trao ngọc giản chứa bản đồ dẫn tới tế đàn và thuật thôn hồn người thứ ba cho Vương Lâm. Giải thích không gian vết rách hình thành từ trận chiến năm xưa, tiếp giáp kỳ dị với một giới. Tiết lộ điều kiện mở nội phủ Thất Thải Tiên Tôn: cần hồn thứ ba xuất hiện triệu hồi thiên đạo dẫn đường. Xin Vương Lâm mang mình về Tiên Cương đại lục, cắn lưỡi phun thệ huyết (máu đỏ chuyển vàng) trao cho hắn.","anchor":"Ta muốn về nhà"},{"mucCt":"gon","text":"Bị Thất Thải Tiên Tôn gọi tên chung với Phàn San Mộng khi chất vấn sự phản bội, cùng phe tấn công sơn môn.","anchor":"Phàn San Mộng. Phàn San Lộ, hai ngươi vì sao phản bội ta!","bridge":true,"khoang":"@c1606"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng minh hợp tác","ghiChu":"Từng giúp Vương Lâm rời khỏi nơi ẩn náu, đạt thỏa thuận hợp tác qua ngọc giản"},{"ten":"Phàn San Mộng","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"Đạo lữ Thất Thải Thiên Tôn, bị dùng làm mồi đoạt bảo vật, chưa chết, đang ở Tiên Cương đại lục"},{"ten":"Thất Thải Thiên Tôn","tag":"doi-thu","quanHe":"Kẻ thù","ghiChu":"Phản bội tỷ tỷ nàng, gây thương tích cho nàng không thể khôi phục"},{"ten":"Nữ tử trong băng sơn","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"Tướng mạo giống hệt Phàn San Lộ, ngồi tu luyện trong núi băng Tiên Cương đại lục, truyền lực xuyên không gian cứu viện khi nàng bị vây khốn"},{"ten":"Thất phi","tag":"ho-hang","quanHe":"Muội muội đồng môn","ghiChu":"Phi thứ bảy Thất Đạo Tông, nhận ra đại tỷ còn sống"},{"ten":"Nữ tử trong núi băng","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"Tướng mạo giống hệt Phàn San Lộ, ngồi tu luyện trong núi băng ở Tiên Cương đại lục, có liên kết mi tâm bảy màu truyền lực xuyên không gian"}],"tuiDo":{"phapBao":[{"ten":"Nhẫn xanh biếc","moTa":"Đeo ở ngón giữa ngọc thủ, chi tiết nhận dạng","nguon":"@c1597"}],"danDuoc":[],"congPhap":[{"ten":"Thái Ngọc Thất Thủ Ấn","moTa":"Ấn quyết hóa bảy bàn tay bảy màu công kích","nguon":"@c1597"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1597","@c1598","@c1599","@c1603","@c1604","@c1605","@c1606"]},{"id":"phan-san-mong","name":"Phàn San Mộng","cn":"樊山夢","aliases":["nữ tử trong băng sơn","nữ tử áo trắng","tỷ tỷ Phàn San Lộ"],"gioiTinh":"nữ","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tỷ tỷ của Phàn San Lộ, đệ tử hạch tâm Đại Hồn Môn và cựu đạo lữ của Thất Thải Thiên Tôn. Năm xưa từng phản bội Thất Thải Thiên Tôn rồi câu dẫn Liên Đạo Phi dẫn ngoại nhân can thiệp, bị Thất Thải Thiên Tôn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín nhưng không chết. Ẩn mình trong băng sơn ở Tiên Cương đại lục suốt thời gian dài, từng ký sinh trong thân xác Phàn San Lộ và lộ diện khi toan tính biến Vương Lâm thành con rối, song mưu kế bị Vương Lâm phá giải.","vaiTro":"Tỷ tỷ Phàn San Lộ — đệ tử hạch tâm Đại Hồn Môn, cựu đạo lữ Thất Thải Thiên Tôn","tinhCach":"Mưu mô thâm trầm, giỏi ẩn nhẫn chờ thời; phản trắc, sẵn sàng phản bội đồng minh để mưu lợi; tự phụ về trí mưu nhưng hay đánh giá thấp đối thủ","tabs":{"diem":[{"text":"Được tiết lộ còn sống, đang ẩn cư tại Tiên Cương đại lục sau khi bị Thất Thải Thiên Tôn dùng làm mồi đoạt bảo vật","chuong":"@c1597"},{"text":"Ẩn trong thân xác Phàn San Lộ, chính thức lộ diện xưng danh — mi tâm hiện dòng xoáy bảy màu, tiết lộ bí mật Thái Cổ Thần Cảnh","chuong":"@c1599"},{"text":"Tiết lộ diễn biến đại chiến Liên Đạo Phi — Thất Thải Thiên Tôn và bí mật ba hồn bảy phách, đề xuất hợp tác với Vương Lâm","chuong":"@c1600"},{"text":"Lộ mục đích thật: dụ Vương Lâm phá tế đàn chứa cổ lực để biến hắn thành con rối, nhưng bị mất quyền kiểm soát thuyền","chuong":"@c1601"},{"text":"Từ xa ngồi trong băng sơn thi triển Đại Hồn chân ảo thuật, bị Vương Lâm phá giải","chuong":"@c1604"},{"text":"Bị vạch trần quá khứ phản bội: từng đánh lén Thất Thải Thiên Tôn và câu dẫn Liên Đạo Phi dẫn ngoại nhân can thiệp","chuong":"@c1606"}],"kinhLich":[{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Được tiết lộ còn sống tại Tiên Cương đại lục","text":"Phàn San Lộ tiết lộ tỷ tỷ Phàn San Mộng chưa chết, đang ở Tiên Cương đại lục. Năm xưa bị Thất Thải Thiên Tôn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín.","anchor":"Tỷ tỷ của ta không chết!"},{"importance":"normal","mucCt":"ky","chuong":"@c1599","tieuDe":"Lộ diện tiết lộ thân phận và bí mật Thái Cổ Thần Cảnh","text":"Ẩn trong thân xác Phàn San Lộ, mi tâm có dòng xoáy bảy màu, sau dị biến chính thức lộ diện xưng danh Phàn San Mộng — tỷ tỷ của Phàn San Lộ, đạo lữ của Thất Thải Tiên Tôn. Gia cố tấm màn phòng hộ bằng ánh sáng bảy màu. Kể lại quá khứ: năm xưa cùng Thất Thải Tiên Tôn nhờ cơ duyên lấy được mảnh vỡ bảo vật từ Thái Cổ Thần Cảnh khi Đạo Nhất và Huyền La tranh đoạt. Bị Thất Thải Tiên Tôn ám toán trên đường về, chiếm hết tu vi rồi giết diệt khẩu. Nhờ mệnh hồn do sư tôn giữ được cứu sống bằng thuật luân hồi. Sau đó mượn pháp lực sư tôn, dụ Liên Đạo Phi tới, phối hợp muội muội Phàn San Lộ liên lạc các phi tử gây chia rẽ nội bộ Thất Đạo Tông thành giới nội giới ngoại. Tiết lộ đạo nhân bảy màu hiện tại không phải đầy đủ, và bên trong mảnh vỡ chính là thiên đạo ngày nay.","anchor":"Ta đích xác không phải là Phàn San Lộ, ta là tỷ tỷ nàng, Phàn San Mộng!"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Tiết lộ bí mật ba hồn bảy phách — đề xuất hợp tác","text":"Kể tiếp toàn bộ diễn biến trận đại chiến giữa Liên Đạo Phi và Thất Thải Thiên Tôn: Liên Đạo Phi bị thiên đạo nuốt nhưng nhờ tiên nhân bất diệt thể không chết. Tiết lộ bí mật ba hồn bảy phách: kim thân Thất Thải Thiên Tôn tan nát hóa ba chủ hồn và thất phách, ai nuốt được hồn thứ ba sẽ có thể dung hợp tất cả thành Thất Thải Thiên Tôn mới. Đề xuất hai phương pháp giết Thất Thải Thiên Tôn: dụ hồn tới cửa động phủ để nguyên thần ra tay, hoặc dạy Vương Lâm thần thông thôn phệ hồn thứ ba rồi nuốt nốt tất cả. Gợi ý Vương Lâm trở thành Thất Thải Thiên Tôn mới, nàng làm đạo lữ song tu, muội muội làm phi tử. Hứa nhờ sư tôn đưa Vương Lâm tới Tiên Cương, tặng Thất Đạo Tông, giúp người thân Vương Lâm chuyển thế luân hồi. Đề nghị thệ huyết xác nhận hợp tác.","anchor":"Ta sẽ giúp ngươi thôn phệ đạo nhân bảy màu và hồn phách thứ hai"},{"importance":"normal","mucCt":"ky","chuong":"@c1601","tieuDe":"Lộ mục đích thật — muốn biến Vương Lâm thành con rối","text":"Tiết lộ trên thuyền có tế đàn chứa cổ lực do muội muội vô ý đạt được, đề nghị Vương Lâm dùng ba ngày phá phòng hộ tế đàn để hấp thu truyền thừa. Khinh thường năng lực cấm chế của Vương Lâm, tuyên bố nếu hắn nghiên cứu ra toàn bộ cấm chế sẽ tặng luôn thuyền, nhưng kinh ngạc khi hắn phá được tầng phòng hộ. Nội tâm lộ âm mưu thật: cần thệ huyết của Vương Lâm để nhận trợ giúp sư tôn, dẫn động pháp thuật kỳ dị biến Vương Lâm thành con rối nhằm giết Thất Thải Tiên Tôn.","anchor":"Người này chỉ là một tu sĩ thấp hèn trong động phủ mà muốn tính toán cấm bảo của Đại Hồn Môn ta, thật sự là buồn cười tới cực điểm"},{"importance":"normal","mucCt":"vua","chuong":"@c1602","tieuDe":"Mất quyền kiểm soát thuyền","text":"Ban đầu cười lạnh khi thấy Vương Lâm bất động ba canh giờ trước cấm chế trên thuyền, cho rằng hắn không thể giải nổi và giục đi tế đàn, nhưng bị phớt lờ. Kinh hoảng khi Vương Lâm phá đồng loạt hàng vạn cấm chế liên hoàn, bị đoạt quyền điều khiển thuyền ở cả tầng một và tầng hai, lúc này chỉ còn nhiều hơn Vương Lâm một chút. Lộ ra bản thể không thể tiến vào nơi này, chỉ phát huy chưa tới ba phần sức mạnh của thuyền.","anchor":"Ta không tin là một tu sĩ thấp hèn trong động phủ như hắn lại có thể hoàn toàn điều khiển chiếc thuyền này"},{"chuong":"@c1604","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Đại Hồn chân ảo thuật từ xa, bị Vương Lâm phá giải","text":"Từ xa ngồi trong hàn băng trên dãy núi đóng băng ở Tiên Cương đại lục, thi triển Đại Hồn chân ảo thuật biến toàn bộ cảnh tượng trên thuyền thành huyễn giới ngay từ lúc Vương Lâm xuất hiện. Huyễn hóa cả đạo nhân bảy màu tấn công, che mắt cả Phàn San Lộ lẫn Vương Lâm, thi triển huyễn trong huyễn suýt ép Vương Lâm giao thệ huyết. Bị Vương Lâm phá ảo thuật, phun máu tươi kinh hãi. Vương Lâm suy luận nàng chưa từng bị Thất Thải Tiên Tôn giết chết, rất có thể dùng ảo thuật lừa gạt hắn, thậm chí mối đạo lữ năm đó cũng chưa chắc thật.","anchor":"Hắn không ngờ lại phá được Đại Hồn chân ảo thuật của ta!"},{"importance":"normal","mucCt":"vua","chuong":"@c1606","tieuDe":"Phản bội Thất Thải Tiên Tôn","text":"Từng đánh lén Thất Thải Tiên Tôn trên đường nhưng được tha không giết. Sau đó câu dẫn Liên Đạo Phi dẫn ngoại nhân tới tấn công sơn môn Tiên Tôn để đoạt mảnh vỡ. Đạo nhân bảy màu trong huyễn cảnh thì thào nhớ lại tên nàng.","anchor":"San Mộng.ta nhớ rồi. Tên nàng là Phàn San Mộng"},{"mucCt":"gon","text":"Đang ngồi tu luyện trong băng sơn trên dãy núi đóng băng ở Tiên Cương đại lục, cảm nhận khí tức đại thiên tôn lan tới, sắc mặt trắng bệch, băng sơn sụp đổ, bay vọt lên hoảng sợ, nhận định đây là khí tức đại thiên tôn.","anchor":"Đây là.đây là khí tức của đại thiên tôn","bridge":true,"khoang":"@c1610"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Muội muội","ghiChu":"Đệ nhất phi Thất Đạo Tông, đệ tử hạch tâm Đại Hồn Môn"},{"ten":"Thất Thải Thiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ (bạn đời)","ghiChu":"Phản bội nàng, dùng làm mồi đoạt bảo vật"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Đạo lữ cũ, kẻ phản bội","ghiChu":"Từng là đạo lữ, bị hắn ám toán chiếm tu vi rồi giết"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người bị dụ lợi dụng","ghiChu":"Vốn mê sắc đẹp nàng, bị nàng dụ tới Thất Đạo Tông phá cuộc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người hợp tác do muội muội tuyển","ghiChu":"Kể quá khứ cho Vương Lâm nghe trên chiến thuyền"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Phá được Đại Hồn chân ảo thuật của nàng, chiếm cánh buồm mặt quỷ"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Cựu đạo lữ","ghiChu":"Vương Lâm suy luận nàng dùng ảo thuật giả chết lừa gạt hắn"},{"ten":"Thất Thải Tiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ (bạn đường)","ghiChu":"Phản bội, dẫn ngoại nhân tấn công sơn môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1597","@c1598","@c1599","@c1600","@c1601","@c1602","@c1604","@c1606","@c1610"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","trangThai":"song","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nhân vật được nhắc đến cùng Hứa Lập Quốc, năm xưa hai người lừa giọt huyết mạch tiên nhân từ người điên.","vaiTro":"Nhân vật phụ, đồng mưu cùng Hứa Lập Quốc lừa giọt huyết mạch","tinhCach":"Mưu mô","tabs":{"diem":[{"text":"Cùng Hứa Lập Quốc lừa giọt huyết mạch tiên nhân từ người điên, giọt máu này cuối cùng rơi vào tay Vương Lâm","chuong":"@c1598"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"dong-minh","quanHe":"Đồng mưu","ghiChu":"Cùng lừa giọt huyết mạch tiên nhân từ người điên"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"dao-nhat-dai-thien-ton","name":"Đạo Nhất đại thiên tôn","cn":"道一大天尊","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Đại thiên tôn","trangThai":"khong-ro","blurb":"Đại thiên tôn từng tranh đoạt bảo vật bay ra từ Thái Cổ Thần Cảnh cùng Huyền La đại thiên tôn tại phụ cận Thất Đạo Tông khi mặt trời thứ chín xuất hiện.","vaiTro":"Đại thiên tôn được nhắc trong quá khứ tranh đoạt bảo vật Thái Cổ Thần Cảnh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tranh đoạt bảo vật từ Thái Cổ Thần Cảnh cùng Huyền La đại thiên tôn","chuong":"@c1599"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới tranh bảo vật Thái Cổ Thần Cảnh","text":"Được Phàn San Mộng nhắc: khi mặt trời thứ chín xuất hiện, cùng Huyền La đại thiên tôn tranh đoạt bảo vật bay ra từ Thái Cổ Thần Cảnh tại phụ cận Thất Đạo Tông.","anchor":"Đạo Nhất đại thiên tôn và Cổ quốc Huyền La đại thiên tôn xuất hiện tại phụ cận của Thất Đạo Tông ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La Đại Thiên Tôn","tag":"doi-thu","quanHe":"Từng tranh đoạt mảnh nhỏ bên ngoài Thất Đạo Tông","ghiChu":"@c1611"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599","@c1611"]},{"id":"huyen-la-dai-thien-ton","name":"Huyền La đại thiên tôn","cn":"玄罗大天尊","aliases":["Cổ quốc Huyền La đại thiên tôn","Huyền La đại tôn","Huyền La"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Cổ quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","blurb":"Huyền La đại thiên tôn là cường giả thuộc Cổ quốc, từng cùng Đạo Nhất đại thiên tôn tranh đoạt bảo vật từ Thái Cổ Thần Cảnh và giao chiến với tu sĩ Đạo Nhất Tông trên chín tầng trời tại phạm vi tiên tộc. Ông giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết, sau khi cảm ứng được hồn huyết ngưng tụ đã dùng thuật bói toán truy tìm nguồn gốc, phong ấn tin tức và đích thân tới Thất Đạo Tông đón người thừa kế.","vaiTro":"Đại thiên tôn Cổ quốc — cường giả giữ kỷ lục cổ Mạch Thương Khung Huyết","tinhCach":"Mưu lược thâm trầm, biết dùng thuật bói toán truy nguyên; quyết đoán khi phong ấn tin tức và đích thân hành động; bình thản trước biến cố nhưng vẫn có thể rung động trước sự kiện chưa từng có","tabs":{"diem":[{"text":"Cùng Đạo Nhất đại thiên tôn tranh đoạt bảo vật từ Thái Cổ Thần Cảnh","chuong":"@c1599"},{"text":"Giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết","chuong":"@c1611"},{"text":"Cảm ứng cổ Mạch Thương Khung Huyết ngưng tụ, dùng thuật bói toán truy nguồn gốc và tuyên bố nhận đệ tử","chuong":"@c1612"},{"text":"Phong ấn tin tức hồn huyết, phân hóa mặt trời đỏ dung nhập thân tộc nhân Đạo cổ, đích thân tới Thất Đạo Tông đón Vương Lâm","chuong":"@c1615"},{"text":"Giao chiến trên chín tầng trời tại phạm vi tiên tộc với tu sĩ Đạo Nhất Tông","chuong":"@c1620"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới tranh bảo vật Thái Cổ Thần Cảnh","text":"Được Phàn San Mộng nhắc: cùng Đạo Nhất đại thiên tôn tranh đoạt bảo vật từ Thái Cổ Thần Cảnh khi mặt trời thứ chín xuất hiện.","anchor":"Đạo Nhất đại thiên tôn và Cổ quốc Huyền La đại thiên tôn xuất hiện tại phụ cận của Thất Đạo Tông ta"},{"mucCt":"vua","text":"Được nhắc là người giữ kỷ lục tám giọt máu tươi trong kiếp Cổ Mạch Thương Khung Huyết, một trong chín vầng mặt trời Tiên Cương đại lục, thuộc cổ quốc, từng tranh đoạt mảnh nhỏ với Đạo Nhất đại thiên tôn bên ngoài Thất Đạo Tông.","anchor":"Người này chính là một trong chín vầng mặt trời của Tiên Cương đại lục, Huyền La Đại Thiên Tôn của cổ quốc","bridge":true,"khoang":"@c1611"},{"chuong":"@c1612","importance":"normal","mucCt":"vua","tieuDe":"Cảm ứng cổ Mạch Thương Khung Huyết, tuyên bố nhận đệ tử","text":"Bảy ngày trước cảm nhận cổ Mạch Thương Khung Huyết ngưng tụ, dùng thuật bói toán tìm ra nguồn gốc là người thừa kế Diệp Mịch. Tuyên bố nếu người đó tới Tiên Cương sẽ nhận làm đệ tử duy nhất, kỳ vọng sau khi mình chuyển thế người đó bảo vệ Đạo cổ nhất mạch. Cảnh cáo cổ hoàng không nên để ý Cực đạo tam hoàng vì đây là đại sự của Đạo cổ nhất mạch.","anchor":"Thanh niên tóc đen này không ngờ lại chính là một trong chín mặt trời, cổ quốc Huyền La"},{"mucCt":"vua","text":"Bình thản quan sát pho tượng cổ tổ, bảo mọi người chờ thêm khi tưởng đã kết thúc. Khi giọt thứ tám xuất hiện ngang kỷ lục bản thân năm xưa, ngửa mặt lên trời cười to.","anchor":"thậm chí khiến cho Huyền La Đại Thiên Tôn ngửa mặt lên trời cười to là sau bảy giọt bất ngờ lại xuất hiện giọt thứ tám","bridge":true,"khoang":"@c1613"},{"mucCt":"ky","text":"Theo dõi sự kiện từ thành trì Đạo cổ, vui sướng khi giọt máu tăng tới chín, lần đầu rung động khiếp sợ khi giọt thứ mười — hồn huyết tím — xuất hiện. Nhớ lại từ cổ chí kim chỉ có chín giọt hồn huyết, ba giọt tạo thành một tộc cổ. Lập tức dùng lực lượng Huyền Dương triệu mặt trời khổng lồ màu đỏ phong bế thiên địa, hạ sắc lệnh toàn bộ tộc nhân không được tiết lộ, vi phạm thì giết bất kể thân phận. Nhìn xuyên thấu nội tâm âm hiểm của hoàng tôn hoàng bào, cảnh cáo trực tiếp. Quyết định đích thân tới chỗ tiên tộc đón Vương Lâm về.","anchor":"Lấy lực lượng Huyền Dương của ta phong bế nơi này","bridge":true,"khoang":"@c1614"},{"importance":"major","mucCt":"vua","chuong":"@c1615","tieuDe":"Phong ấn tin tức hồn huyết, đích thân tới Thất Đạo Tông đón Vương Lâm","text":"Phân hóa mặt trời đỏ thành gần trăm vạn phần dung nhập vào thân tộc nhân Đạo cổ, hình thành thuật phong ấn cấm lan truyền tin tức hồn huyết thứ mười. Hoàn thành xong liền bước một bước biến mất, đích thân tới Thất Đạo Tông ở tiên tộc để đón Vương Lâm về nhà.","anchor":"Hắn muốn tới tiên tộc, đi tới Thất Đạo Tông, vào trong động phủ kia, đón hài tử của Đạo cổ nhất mạch hắn về nhà!"},{"mucCt":"vua","text":"Giao chiến trên chín tầng trời tại phạm vi tiên tộc Tiên Cương đại lục với tu sĩ Đạo Nhất Tông, bầu trời hôn ám mấy tháng. Bị đối phương nhận định tu vi yếu hơn năm xưa, sắp chuyển thế. Đe dọa giết sạch Đạo Nhất Tông nếu ngăn trở, khinh thường việc dùng âm mưu quỷ kế, vội vã xông vào lãnh thổ tiên tộc vì chuyện trọng đại.","anchor":"Nơi Huyền La ta muốn đi khắp nơi đều là chuyện trọng đại","bridge":true,"khoang":"@c1620"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Nhất đại thiên tôn","tag":"doi-thu","quanHe":"Từng tranh đoạt mảnh nhỏ bên ngoài Thất Đạo Tông","ghiChu":"@c1611"},{"ten":"Cổ Hoàng","tag":"ho-hang","quanHe":"Cổ hoàng gọi Huyền La là tộc thúc, xưng cung kính đại thiên tôn","gap":"@c1612"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Dùng thuật bói toán phát hiện người thừa kế Diệp Mịch đang ngưng tụ cổ Mạch Thương Khung Huyết","gap":"@c1612"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Tuyên bố sẽ nhận Vương Lâm (người thừa kế Diệp Mịch) làm đệ tử duy nhất","gap":"@c1612"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599","@c1611","@c1612","@c1613","@c1614","@c1615","@c1620"]},{"id":"khong-huyen","name":"Không Huyền","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Toàn năng","trangThai":"khong-ro","blurb":"Bậc toàn năng mà Vương Lâm cần cung Lý Quảng để đối đầu.","vaiTro":"Bậc toàn năng, đối thủ tiềm tàng của Vương Lâm","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Bậc toàn năng mà Vương Lâm xác định cần cung Lý Quảng để đấu","chuong":"@c1599"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Được Vương Lâm nhắc tới","text":"Vương Lâm nhắc cần giữ cung Lý Quảng để đấu với bậc toàn năng Không Huyền.","anchor":"hắn muốn đấu với bậc toàn năng Không Huyền đều phải dựa vào nó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599"]},{"id":"ly-quang","name":"Lý Quảng","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới chém giết Đạo Cổ Diệp Mịch","text":"Được Phàn San Mộng nhắc: Thất Thải Tiên Tôn không rõ bằng cách nào khiến Lý Quảng trợ giúp chém giết Đạo Cổ Diệp Mịch.","anchor":"Ta không biết hắn làm sao khiến Lý Quảng trợ giúp mà chém giết Đạo Cổ Diệp Mịch"}],"diem":[{"text":"Bắn rơi mắt trái Đạo Cổ Hoa Mịch trong cuộc bao vây của đạo môn","chuong":"@c1378"},{"text":"Dùng cây cung lớn chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong","chuong":"@c1380"},{"text":"Tư thế bắn cung oai hùng trở thành ký ức sâu đậm của Vương Lâm","chuong":"@c1436"},{"text":"Mũi tên năm xưa được Vương Lâm thu phục làm bảo vật","chuong":"@c1482"},{"text":"Được tiết lộ từng được Thất Thải Tiên Tôn bằng cách nào đó thu nạp trợ giúp chém giết Đạo Cổ Diệp Mịch","chuong":"@c1599"}]},"nguon":["@c1599"],"vaiTro":"Đạo sĩ áo đen bắn cung — người bắn rơi mắt trái Đạo Cổ Hoa Mịch / Diệp Mịch","tinhCach":"Quyết đoán, dứt khoát trong chiến đấu; thiện xạ phi phàm; oai hùng, bất khuất trước cường địch","blurb":"Lý Quảng là đạo sĩ áo đen nổi danh với tài bắn cung, từng tham gia cuộc bao vây của đạo môn đối với Đạo Cổ Hoa Mịch và bắn rơi mắt trái của Hoa Mịch. Về sau tại vùng đất cổ mộ, ông được Thất Thải Tiên Tôn thu nạp trợ giúp, dùng cây cung lớn mang chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân xuyên qua mọi trở ngại, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong, để lại ấn tượng oai hùng tuyệt đối trong ký ức Vương Lâm. Mũi tên năm ấy sau này được Vương Lâm thu phục làm bảo vật."},{"id":"dao-co-diep-mich","name":"Đạo Cổ Diệp Mịch","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới bị dụ đến và bị Lý Quảng chém giết","text":"Được Phàn San Mộng nhắc: bị Thất Thải Tiên Tôn dụ tới phong kín tông sơn Thất Đạo Tông, rồi bị Lý Quảng chém giết.","anchor":"Ta không biết hắn làm sao khiến Lý Quảng trợ giúp mà chém giết Đạo Cổ Diệp Mịch"},{"chuong":"@c1611","importance":"bridge","mucCt":"vua","tieuDe":"Nhắc tiền lệ vượt kiếp Cổ Mạch Thương Khung Huyết","text":"Được nhắc làm tiền lệ: năm đó vượt kiếp cuối cùng tại cổ miếu cổ quốc, trong kiếp Cổ Mạch Thương Khung Huyết được ba giọt máu tươi, dung hợp danh hiệu tam tộc cổ thành đại tôn.","anchor":"Đạo cổ Diệp Mịch năm đó ở trong cổ miếu của cổ quốc khi vượt qua được kiếp cuối cùng"}],"diem":[{"text":"Để lại hệ thống truyền thừa thí luyện trong cổ mộ: mở đài mộ cấp năm sẽ mở cánh cửa luân hồi, trở thành người thí luyện truyền thừa","chuong":"@c1368"},{"text":"Dung hợp tam đạo: trong trận chiến hư ảo năm xưa tuần tự thi triển thần thuật, yêu thuật và ma thuật của Đạo Cổ","chuong":"@c1380"},{"text":"Mắt trái bị Lý Quảng bắn rơi, phong ấn tại tầng 19 hố sâu Phù Văn tộc","chuong":"@c1479"},{"text":"Có thanh danh hiển hách tại đại tôn cổ quốc; từng tìm đến động phủ Thất Đạo Tông chỉ trích Thất Thải Đạo Tôn","chuong":"@c1545"},{"text":"Trước khi chết, ba ngàn giọt máu hóa thành ba tộc, chín giọt trong đó là tâm huyết; không có con trai nối dõi","chuong":"@c1578"},{"text":"Bị Thất Thải Tiên Tôn dụ tới tông sơn Thất Đạo Tông rồi bị Lý Quảng chém giết; từng vượt kiếp Cổ Mạch Thương Khung Huyết tại cổ miếu cổ quốc","chuong":"@c1599"}]},"nguon":["@c1599","@c1611"],"cn":"道古叶寂","gioiTinh":"nam","vaiTro":"Chủ nhân cổ mộ — đại năng thượng cổ nắm tam phủ Đạo Cổ, ngoài hàng ngũ tiên tôn","tinhCach":"Bí ẩn, mưu lược sâu xa (thiết kế hệ thống truyền thừa thí luyện nhiều cấp); uy nghiêm, có thanh danh hiển hách tại đại tôn cổ quốc; dung hợp đa đạo, không câu nệ ranh giới thần–yêu–ma","blurb":"Đạo Cổ Diệp Mịch là chủ nhân cổ mộ, một đại năng thượng cổ đạt cảnh giới Cửu tinh Cổ Thần / Cổ Yêu / Cổ Ma, tu vi đủ khiến các tiên tôn e dè dù không nằm trong hàng ngũ tiên tôn. Ông nắm giữ tam phủ Thiên Địa Nhân của Đạo Cổ, dung hợp cả thần thuật, yêu thuật và ma thuật, đồng thời để lại hệ thống truyền thừa thí luyện gồm đài mộ nhiều cấp và cánh cửa luân hồi. Trước khi chết, ông bị Thất Thải Tiên Tôn dụ tới tông sơn Thất Đạo Tông rồi bị Lý Quảng chém giết; ba ngàn giọt máu của ông hóa thành ba tộc, trong đó chín giọt là tâm huyết, và ông không có con trai nối dõi."},{"id":"that-thai-thien-ton","name":"Thất Thải Thiên Tôn","aliases":["đạo nhân bảy màu","Quái nhân tóc bạc","Thất Thải Tiên Tôn"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Kim thân tan nát — hóa ba hồn bảy phách","text":"Được tiết lộ: kim thân tan nát sau đại chiến, hóa thành ba chủ hồn. Hồn thứ nhất chứa đạo thuật thần thông chính là đạo nhân bảy màu, chiếm cứ giới ngoại. Hồn thứ hai chứa ý cảnh và bổn nguyên lực, bỏ chạy sau đại chiến. Hồn thứ ba nắm toàn bộ trí nhớ và bí mật triệu hoán thiên đạo, đã trải vô số luân hồi có thể quên thân phận. Ngoài ra có thất phách cũng luân hồi thay đổi thân phận. Ai nuốt được hồn thứ ba mới có thể dung hợp tất cả trở thành Thất Thải Thiên Tôn hoàn chỉnh.","anchor":"Kim thân của Thất Thải Thiên Tôn tan nát, hoá thành một chủ hồn"},{"chuong":"@c1601","importance":"bridge","mucCt":"gon","text":"Bên ngoài thuyền liên tục vung tay phóng cuồng phong tấn công tầng sáng phòng hộ, phá vỡ hơn một nửa.","anchor":"đạo nhân bảy màu đang không ngừng vung hai tay về phía trước, mỗi lần vung tay áo đều có cuồng phong gào thét"},{"importance":"bridge","mucCt":"gon","chuong":"@c1602","tieuDe":"Tiếp tục phá tầng sáng thuyền cổ","text":"Tiếp tục tấn công tầng sáng bảo hộ bên ngoài thuyền cổ, sau một ngày đã phá hơn một nửa.","anchor":"đạo nhân bảy màu ở bên ngoài con thuyền ánh mắt cũng sững lại, cẩn thận nhìn tới"},{"chuong":"@c1604","importance":"normal","mucCt":"vua","tieuDe":"Tự nguyện đắm chìm trong ảo giác","text":"Ở một hướng khác trong không gian kỳ dị của chiếc thuyền, khoanh chân ngồi trên thi thể mãnh thú, thần sắc lúc thống khổ lúc hưng phấn, tự nguyện đắm chìm trong ảo giác dù với tu vi của hắn thoát ra không khó. Lý do cam tâm ở lại chỉ mình hắn biết.","anchor":"hắn tự nguyện chìm vào trong đó. nếu không với tu vi của hắn thì dù không bằng Phàn San Mộng nhưng muốn ra khỏi ảo giác này cũng không khó"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Ký ức đại chiến — triệu Thiên Đạo đồng quy vu tận","text":"Trong thực tại, tỏa uy áp kinh khiếp hơn thiên uy, xung quanh đầy thi thể mãnh thú, chìm trong ảo giác. Trong huyễn cảnh, ngồi khoanh chân trên đỉnh núi, mắt mở to nhìn trời thẫn thờ, thì thào nhắc tên Phàn San Mộng, bên ngoài thân có chín quang cầu chứa hỏa điểu (pháp bảo chín mặt trời). Trong ký ức đại chiến: bị liên minh Liên Đạo Phi, Phàn San Mộng, Phàn San Lộ tấn công tại sơn môn, bị đánh phun máu. Phẫn nộ chất vấn sự phản bội, nhắc San Mộng từng đánh lén nhưng được tha mạng nay lại dẫn ngoại nhân tới. Cuối cùng vung tay triệu hồi dòng xoáy trên trời lộ ra đôi mắt vô tình — Thiên Đạo — đồng quy vu tận. Thân thể tan nát vỡ thành ba phần: hồn thứ nhất là đạo nhân bảy màu, hồn thứ hai là ý cảnh, hồn thứ ba chứa toàn bộ trí nhớ hóa cầu vồng bay đi. Phần đạo nhân bảy màu lao tới cố lấy lại phần trí nhớ — đây chính là nguyên nhân hắn tự giam trong ảo giác.","anchor":"Phàn San Mộng. Phàn San Lộ, hai ngươi vì sao phản bội ta!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Mộng","tag":"the-thiep","quanHe":"Đạo lữ (bạn đường/người tình)","ghiChu":"Phản bội, câu dẫn Liên Đạo Phi tấn công sơn môn"},{"ten":"Phàn San Lộ","tag":"doi-thu","quanHe":"Kẻ phản bội","ghiChu":"Cùng Phàn San Mộng phản bội Tiên Tôn"},{"ten":"Liên Đạo Phi","tag":"doi-thu","quanHe":"Kẻ tấn công sơn môn","ghiChu":"Bị Phàn San Mộng câu dẫn tới, muốn mảnh vỡ"}],"tuiDo":{},"diem":[{"text":"Cùng đạo lữ khai tông lập phái Thất Đạo Tông trên Tiên Cương đại lục, trải vô số ngàn năm uy vọng cực cao","chuong":"@c1545"},{"text":"Tu vi xác nhận Không Kiếp trung kỳ, đủ tư cách đại tôn khai tông lập phái","chuong":"@c1568"},{"text":"Kim thân tan nát sau đại chiến, hóa thành ba chủ hồn bảy phách, mỗi hồn chứa đạo thuật thần thông riêng","chuong":"@c1600"},{"text":"Tàn hồn tự nguyện đắm chìm trong ảo giác, khoanh chân ngồi trên thi thể mãnh thú trong không gian kỳ dị của thuyền cổ","chuong":"@c1604"},{"text":"Trong ảo giác tái hiện ký ức đại chiến, tỏa uy áp kinh khiếp hơn thiên uy, xung quanh đầy thi thể mãnh thú","chuong":"@c1606"}]},"nguon":["@c1600","@c1601","@c1602","@c1604","@c1606"],"trangThai":"khong-ro","cn":"七彩仙尊","gioiTinh":"nam","vaiTro":"Tông chủ Thất Đạo Tông — viễn cổ tiên hoàng trên Tiên Cương đại lục","tinhCach":"Uy nghiêm thâm trầm, uy áp vượt thiên uy; sẵn sàng hy sinh đạo lữ vì bảo vật (theo lời Diệp Mịch); chấp niệm cực thâm, tự nguyện đắm chìm trong ảo giác ký ức","blurb":"Viễn cổ tiên hoàng tu vi Không Kiếp trung kỳ, cùng đạo lữ khai tông lập phái Thất Đạo Tông trên Tiên Cương đại lục, uy vọng cực cao suốt vô số ngàn năm. Sau đại chiến viễn cổ, kim thân tan nát, hóa thành ba chủ hồn bảy phách tản mác, mỗi hồn mang một phần đạo thuật thần thông. Tàn hồn của y vẫn tỏa uy áp kinh khiếp vượt thiên uy, chìm trong ảo giác ký ức đại chiến năm xưa."},{"id":"thieu-nien-dau-troc","name":"Thiếu niên đầu trọc áo vải xanh","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thiếu niên bí ẩn phía sau Liên Đạo Phi trong đại chiến tại sơn môn Thất Thải Tiên Tôn, thân hình gầy gò, mắt hung quang, đang chém giết với Thanh Long chiến tướng.","vaiTro":"Chiến binh theo Liên Đạo Phi trong đại chiến tại sơn môn Tiên Tôn","tinhCach":"Hung hãn","tabs":{"diem":[{"text":"Gầy gò, mặc y phục kỳ quái bằng vải xanh, mắt hung quang, chiến đấu với Thanh Long chiến tướng","chuong":"@c1606"}],"kinhLich":[{"mucCt":"vua","text":"Xuất hiện phía sau Liên Đạo Phi trong đại chiến tại sơn môn Thất Thải Tiên Tôn, thân hình gầy gò, mặc y phục kỳ quái bằng vải xanh, mắt hung quang, đang chém giết với Thanh Long chiến tướng.","anchor":"Người này Vương Lâm cũng không xa lạ, đó là Thanh Long chiến tướng trong tứ đại chiến tướng!","bridge":true,"khoang":"@c1606"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"dong-minh","quanHe":"Chủ nhân / người dẫn dắt","ghiChu":"Theo sau Liên Đạo Phi trong đại chiến"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1606"]},{"id":"that-thai-tien-ton","name":"Thất Thải Tiên Tôn","aliases":["Đạo nhân bảy màu","Quái nhân tóc bạc","thất thải"],"trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"gon","tieuDe":"Từ bỏ đạo lữ phong tỏa Thất Đạo Tông","text":"Từ bỏ đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật cực kỳ quý trọng bên trong.","anchor":"Thất Thải Tiên Tôn từ bỏ đạo lữ, phong tỏa Thất Đạo Tông, muốn đạt được bảo vật cực kỳ quý trọng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1601","tieuDe":"Tấn công thuyền Đại Hồn Môn","text":"Liên tục vung tay tạo cuồng phong tấn công thuyền từ bên ngoài, phá vỡ hơn một nửa tầng sáng phòng hộ.","anchor":"đạo nhân bảy màu đang không ngừng vung hai tay về phía trước, mỗi lần vung tay áo đều có cuồng phong gào thét"},{"importance":"bridge","mucCt":"gon","chuong":"@c1602","tieuDe":"Phá hơn nửa tầng sáng thuyền","text":"Tiếp tục đánh phá tầng sáng bảo hộ bên ngoài con thuyền, sau một ngày đã phá tan hơn một nửa.","anchor":"đạo nhân bảy màu ở bên ngoài con thuyền ánh mắt cũng sững lại, cẩn thận nhìn tới"},{"importance":"normal","mucCt":"ky","chuong":"@c1607","tieuDe":"Lợi dụng ảo giác truy tìm hồn thứ ba","text":"Dùng tu vi cường hãn sửa lại ảo giác của Phàn San Mộng, biến thành cảnh quay ngược thời gian về lúc thân thể bị phân ba hồn bảy phách, theo dõi hồn thứ ba bay vào giới nội rồi xuyên Vân Hải tinh vực hướng Triệu Hà. Đây là cơ hội đầu tiên trong vô số ngàn năm để tìm nơi luân hồi của hồn thứ ba — khát vọng cả đời. Kích động cực độ, phóng đại tinh đồ theo dõi. Thân thể thật ngồi khoanh chân trên đỉnh núi trong huyễn cảnh tầng một, được chín vầng mặt trời và chín hỏa điểu bảo vệ bằng quang nhiệt.","anchor":"Vô số ngàn năm qua, đây là cơ hội đầu tiên của hắn!"},{"chuong":"@c1627","importance":"normal","mucCt":"vua","tieuDe":"Hé lộ thất phách và phách nguyên thủy bị Thiên Vận Tử nuốt","text":"Được hé lộ: thất phách bị Thiên Vận Tử nuốt từ lần thức tỉnh thứ hai ở thái cổ, phách nguyên thủy bị nuốt từ lần đầu tiên ở tinh vực tử vong. Thiên Vận Tử dùng phách này trưởng thành và tính toán mạo danh thành Thất Thải Tiên Tôn hoàn chỉnh. Tam hồn (bao gồm Tham Lang) là phần Thiên Vận Tử không dám chạm vào vì lực lượng quá lớn.","anchor":"đáng tiếc là lực lượng tam hồn của hắn quá lớn ta và thân thể sau khi chia lìa không dám chọc vào hắn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1631","tieuDe":"Được nhắc về mảnh nhỏ thiên đạo","text":"Được nhắc: năm xưa đạt được một mảnh nhỏ chứa không gian trữ vật, phát hiện thiên đạo và Thiên Nghịch, từ đó mới có la bàn.","anchor":"Thất Thải Tiên Tôn năm đó đạt được một mảnh nhỏ này"},{"chuong":"@c1632","importance":"bridge","mucCt":"gon","text":"Được nhắc: năm đó ngoài Thất Thải Tiên Tôn không ai nhìn thấy chân thân thiên đạo.","anchor":"ngoài Thất Thải Tiên Tôn ra cũng không có ai nhìn thấy chân thân của thiên đạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Kẻ nuốt phách — Thiên Vận Tử đã nuốt thất phách và phách nguyên thủy của Thất Thải Tiên Tôn để trưởng thành, mưu đồ mạo danh","ghiChu":"Thiên Vận Tử tự nhận từng giúp Thất Thải Tiên Tôn rất nhiều"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Từ bỏ đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật quý trọng bên trong","chuong":"@c1586"},{"text":"Tấn công thuyền Đại Hồn Môn, phá vỡ hơn một nửa tầng sáng phòng hộ trong một ngày","chuong":"@c1601"},{"text":"Dùng tu vi cường hãn sửa lại ảo giác Phàn San Mộng để truy tìm hồn thứ ba","chuong":"@c1607"},{"text":"Thất phách bị Thiên Vận Tử nuốt từ lần thức tỉnh thứ hai ở thái cổ, phách nguyên thủy bị nuốt từ trước đó","chuong":"@c1627"},{"text":"Là người duy nhất từng nhìn thấy chân thân thiên đạo","chuong":"@c1632"}]},"nguon":["@c1607","@c1586","@c1601","@c1602","@c1627","@c1631","@c1632"],"cn":"七彩仙尊","gioiTinh":"nam","vaiTro":"Cường giả thượng cổ — từng chứng kiến chân thân thiên đạo, liên quan mật thiết đến Thiên Vận Tử","tinhCach":"tâm cơ thâm trầm, hành sự quyết đoán không từ thủ đoạn; theo đuổi bí mật thiên đạo một cách cuồng nhiệt","blurb":"Thất Thải Tiên Tôn là cường giả từ thời thái cổ, người duy nhất từng nhìn thấy chân thân thiên đạo. Thất phách và phách nguyên thủy của hắn bị Thiên Vận Tử nuốt qua hai lần thức tỉnh khác nhau, khiến hắn trở thành một tồn tại tàn khuyết. Hắn từng phản bội đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật, và sau đó tấn công thuyền Đại Hồn Môn nhằm truy tìm hồn phách đã mất."},{"id":"ham-ham","name":"Hàm Hàm","cn":"","aliases":[],"gioiTinh":"nữ","theLuc":[{"ten":"Tử Dương Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô bé tầm tám tuổi mặc váy tím sống trong không gian kỳ dị dạng đào viên tiếp giáp tế đàn trong khe Vân Hải tinh vực. Cùng Oa Oa giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","vaiTro":"Cô bé bí ẩn trong đào viên, giam giữ Tham Lang","tinhCach":"Ngang tàng, không sợ kẻ mạnh; thích nghe chuyện cổ","tabs":{"diem":[{"text":"Cùng Oa Oa khuất phục và giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ, dù Tham Lang là tu sĩ cường đại","chuong":"@c1608"},{"text":"Nghe Tham Lang kể chuyện Vương Lâm, nhăn mũi tỏ vẻ ghê tởm với Vương Lâm","chuong":"@c1609"},{"text":"Cùng Oa Oa truyền tu vi cường hãn cho Tham Lang, tạo mặt trời chấn động tinh không","chuong":"@c1609"},{"text":"Đại thiên tôn chuyển thế của Tử Dương tông, hiện thân là tiểu cô nương đáng yêu trong tự thú giới, cùng bạn phong bế cái khe và giấu Tham Lang.","chuong":"@c1610"}],"kinhLich":[{"mucCt":"vua","text":"Nắm chân Tham Lang lôi lại khi hắn cố thoát ra qua khe nứt. Cùng Oa Oa giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","anchor":"Hắn lúc vừa tới nơi này không phải còn uy h**p chúng ta sao","bridge":true,"khoang":"@c1608"},{"mucCt":"vua","text":"Nghe Tham Lang kể chuyện Vương Lâm, nhăn mũi tỏ vẻ ghê tởm. Khi chín mặt trời ập tới, cùng Oa Oa đặt tay lên lưng Tham Lang truyền tu vi cường hãn, khiến hắn tỏa kim quang và xuất hiện mặt trời màu vàng.","anchor":"Vương Lâm thật đúng là ghê tởm! Hắn làm sao lại có thể như vậy chứ!","bridge":true,"khoang":"@c1609"},{"mucCt":"gon","text":"Cùng bạn vội vàng phong bế vết nứt cái khe và giấu Tham Lang, không muốn mấy lão đầu phát hiện.","anchor":"Hắn chính là người ta nhắc tới lúc trước, hắn cũng tên là Vương Lâm","bridge":true,"khoang":"@c1610"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Người bị giam giữ, bắt kể chuyện cổ","ghiChu":"@c1608"},{"ten":"Oa Oa (đào viên)","tag":"ban-be","quanHe":"Bạn đồng hành trong đào viên","ghiChu":"@c1608"},{"ten":"Tham Lang","tag":"khac","quanHe":"Kẻ xâm nhập thú giới, bị bắt kể chuyện","ghiChu":"@c1609"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người quen từ trước, nhận ra khi nhìn qua cái khe","ghiChu":"Bạn của Hàm Hàm nhận ra Vương Lâm, nói từng nhắc tới hắn trước đó"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1608","@c1609","@c1610"]},{"id":"oa-oa-dao-vien","name":"Oa Oa (đào viên)","cn":"","aliases":[],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô bé tầm tám tuổi mặc váy xanh sống trong không gian kỳ dị dạng đào viên tiếp giáp tế đàn trong khe Vân Hải tinh vực. Cùng Hàm Hàm giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","vaiTro":"Cô bé bí ẩn trong đào viên, giam giữ Tham Lang","tinhCach":"Có vẻ nhân từ hơn nhưng vẫn giữ người; thích nghe chuyện cổ","tabs":{"diem":[{"text":"Tỏ vẻ không nỡ nhưng đề nghị Tham Lang kể chuyện cổ một ngàn năm mới được thả, cho thấy năng lực bí ẩn vượt xa vẻ ngoài trẻ nhỏ","chuong":"@c1608"}],"kinhLich":[{"mucCt":"vua","text":"Cùng Hàm Hàm giữ Tham Lang suốt trăm năm. Tỏ vẻ không nỡ nhưng rồi đề nghị Tham Lang kể chuyện cổ một ngàn năm mới được thả.","anchor":"Ngươi kể chuyện cổ cho chúng ta một ngàn năm ta sẽ thả cho ngươi rời đi","bridge":true,"khoang":"@c1608"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Người bị giam giữ, bắt kể chuyện cổ","ghiChu":"@c1608"},{"ten":"Hàm Hàm","tag":"ban-be","quanHe":"Bạn đồng hành trong đào viên","ghiChu":"@c1608"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1608"]},{"id":"ma-su-huynh-quy-nhat","name":"Mã sư huynh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Thành viên Quy Nhất tông, năm xưa dùng chí bảo của tông phái mở thông đạo tới động phủ Thất Đạo Tông rồi dẫn người đi vào, dặn lại không được mở Đông Đan chung.","vaiTro":"Tu sĩ Quy Nhất tông, người mở thông đạo tới động phủ Thất Đạo Tông","tinhCach":[{"text":"Kiên nghị, nghiên cứu lâu dài để đạt mục đích"}],"tabs":{"diem":[{"text":"Dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, phải tự mình trở về","chuong":"@c1586"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn phân tông Quy Nhất","tag":"su-mon","quanHe":"Sư đệ trong Quy Nhất tông","ghiChu":"Chưởng môn nhắc đến lời dặn của Mã sư huynh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"]},{"id":"nu-tu-bang-son","name":"Nữ tử trong băng sơn","cn":"","aliases":["Tỷ tỷ Phàn San Lộ"],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử tướng mạo giống hệt Phàn San Lộ, tu luyện trong núi băng vùng đóng băng Tiên Cương đại lục, có thể truyền lực xuyên không gian trợ giúp Phàn San Lộ.","vaiTro":"Tỷ tỷ của Phàn San Lộ, xuất hiện qua liên kết xuyên không gian khi Phàn San Lộ kêu cứu.","tinhCach":[{"text":"Chưa rõ, chỉ biết lập tức đáp ứng khi Phàn San Lộ cầu viện"}],"tabs":{"diem":[{"text":"Tướng mạo giống hệt Phàn San Lộ, tu luyện trong băng sơn Tiên Cương đại lục, truyền lực xuyên không gian phá vây cho muội muội.","chuong":"@c1598"}],"kinhLich":[{"chuong":"@c1598","importance":"normal","mucCt":"vua","tieuDe":"Truyền lực xuyên không gian cứu Phàn San Lộ","text":"Khi Phàn San Lộ bị đạo nhân bảy màu vây khốn bằng tinh thể và kêu cứu, nữ tử mở mắt, điểm chỉ lên mi tâm, phóng ánh sáng bảy màu truyền lực xuyên không gian tới Phàn San Lộ, khiến ấn quyết bành trướng mấy ngàn trượng phá vây.","anchor":"Trong lòng đất đóng băng này có một núi băng. Bên trong đó có một nữ tử ngồi khoanh chân"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Muội muội, tướng mạo giống hệt, truyền lực xuyên không gian cứu viện khi bị vây khốn","ghiChu":"@c1598"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"nu-tu-nui-bang","name":"Nữ tử trong núi băng","cn":"","aliases":["Tỷ tỷ của Phàn San Lộ"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử tướng mạo giống hệt Phàn San Lộ, ngồi tu luyện trong núi băng tại vùng đất đóng băng thuộc Tiên Cương đại lục, có thể truyền lực lượng xuyên không gian qua liên kết mi tâm bảy màu.","vaiTro":"Tỷ tỷ của Phàn San Lộ, trợ giúp nàng từ xa phá vây tinh thể của đạo nhân bảy màu.","tinhCach":[{"text":"Bí ẩn, ẩn tu trong núi băng, sẵn sàng trợ giúp khi Phàn San Lộ kêu cứu"}],"tabs":{"diem":[{"text":"Tướng mạo giống hệt Phàn San Lộ, có liên kết mi tâm bảy màu xuyên không gian","chuong":"@c1598"}],"kinhLich":[{"chuong":"@c1598","importance":"normal","mucCt":"vua","tieuDe":"Truyền lực xuyên không gian cứu Phàn San Lộ","text":"Khi Phàn San Lộ kêu cứu, nữ tử mở mắt điểm chỉ lên mi tâm, ánh sáng bảy màu lóe lên, truyền lực lượng xuyên không gian tới giúp Phàn San Lộ phá hủy tinh thể vây khốn của đạo nhân bảy màu.","anchor":"Tướng mạo nữ tử này không ngờ lại giống hệt như Phàn San Lộ!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Muội muội","ghiChu":"Phàn San Lộ gọi là tỷ tỷ, hai người có liên kết mi tâm bảy màu xuyên không gian"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"tham-lang","name":"Tham Lang","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Hồi tưởng hành trình: theo đại quân giới ngoại vào Vân Hải tinh vực, âm thầm tìm được khe không gian chứa tế đàn Đạo Cổ và thú giới Tử Dương Tông. Cười điên cuồng bước vào khe, xâm nhập thú giới, vây hai tiểu cô nương hái tiên thảo nhưng bị Oa Oa phá vây dễ dàng, đá một cước suýt phế tu vi. Bị bắt co quắp ngồi kể chuyện Vương Lâm cho Hàm Hàm và Oa Oa. Nhân lúc hai cô bé nói chuyện, phát điên lao ra khe, vui sướng rơi nước mắt. Vừa ra ngoài gặp Vương Lâm bừng cháy lao tới tế đàn, sắc mặt tái nhợt hoảng sợ tưởng bị truy đuổi. Chín mặt trời ập tới, chui nửa người vào khe cầu cứu hai tiểu cô nương. Được hai tiểu cô nương đặt tay lên lưng truyền tu vi cường hãn, toàn thân tỏa kim quang vô tận, hai tay bất giác giơ lên hợp đồ án hình tròn xuất hiện mặt trời màu vàng, lực lượng chấn động tinh không, tứ đại tinh vực và Thái Cổ Tinh Thần giới ngoại.","anchor":"Luồng tu vi này khiến cho toàn thân Tham Lang tỏa ra kim quang vô tận","bridge":true,"khoang":"@c1609"},{"chuong":"@c1610","importance":"normal","mucCt":"vua","tieuDe":"Phóng khí tức đại thiên tôn, bị giấu vào tự thú giới","text":"Mặt trời trong hai tay bành trướng lớn bằng một người, ánh sáng vạn trượng phá hủy chín con hỏa điểu, tỏa khí tức đại thiên tôn lan khắp tứ đại tinh vực. Sau đó bị hút vào bên trong cái khe, được hai tiểu cô nương (đại thiên tôn chuyển thế Tử Dương tông) phong bế cái khe và giấu đi.","anchor":"Mặt trời trong hai tay Tham Lang lúc này nhanh chóng bành trướng"}],"tuViMoc":[],"nhanMach":[{"ten":"Oa Oa","tag":"khac","quanHe":"Tiểu cô nương Tử Dương Tông, đá Tham Lang suýt phế tu vi rồi truyền tu vi cho hắn","ghiChu":"@c1609"},{"ten":"Hàm Hàm","tag":"khac","quanHe":"Tiểu cô nương Tử Dương Tông, cùng Oa Oa bắt Tham Lang kể chuyện và truyền tu vi cho hắn","ghiChu":"@c1609"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tu vi từng đạt Âm Hư chi cảnh, chỉ kém Dương Thật, nhưng vì trọng thương mà rớt xuống Vấn Đỉnh kỳ đại viên mãn","chuong":"@c0571"},{"text":"Bị Vân Tiên đạo lữ một trảo bắt đi trước mặt các lão quái, sau đó bị giam rồi thả ra như lão nô đứng sau Hồ Quyên và Vương Tạ","chuong":"@c0614"},{"text":"Tham bảo đào Kim Viêm quáng mạch trên Vân Hà Tinh, chạm tới Nguyệt Hoa nên bị Vọng Nguyệt nuốt vào, mắc kẹt bảy mươi năm trong khu bài tiết và hấp thu","chuong":"@c0668"},{"text":"Thoát khỏi bụng Vọng Nguyệt trong tình trạng thân thể vỡ nát, nguyên thần tổn hại, rơi xuống tinh cầu nguyên thủy và bị Vương Lâm đoạt sạch bảo vật cùng lạc ấn","chuong":"@c0674"},{"text":"Phục hồi tu vi lên Toái Niết trung kỳ nhờ dâng pháp bảo cho Điên Lạc đại đế, trở thành đại cung phụng nổi danh trong Điên Lạc tinh vực","chuong":"@c1295"},{"text":"Theo đại quân giới ngoại vào Vân Hải tinh vực, phóng khí tức ngang tầm đại thiên tôn phá hủy chín con hỏa điểu","chuong":"@c1610"}]},"nguon":["@c1609","@c1610"],"gioiTinh":"nam","vaiTro":"Lão tu sĩ lưu lạc — cường giả trọng thương từ Đại La Kiếm Tông, khắc tinh duyên nợ với Vương Lâm","tinhCach":"Tàn bạo cưỡng ép, khống chế Văn thú bằng cực hình thay vì thuần phục; tham bảo liều thân, dám đào Kim Viêm quáng mạch và chạm Nguyệt Hoa dẫn tới bị nuốt vào Vân Hà Tinh; thận trọng biết thời, chủ động rời Chu Tước Tinh tránh Tư Đồ Nam khi thân mang trọng thương; kiên nhẫn bền bỉ, bảy mươi năm chật v","blurb":"Tham Lang là tiền bối đồng lứa với sư tôn của Thần Long và Vương Lâm, tu vi từng đạt Âm Hư chi cảnh nhưng vì trọng thương mà rớt còn Vấn Đỉnh kỳ đại viên mãn, phải rời Chu Tước Tinh tới Đại La Kiếm Tông rồi lưu lạc qua La Thiên Tinh Vực. Hắn trải qua hàng loạt kiếp nạn — vây khốn Đại La Kiếm Tông bằng bầy Văn thú, bị cường giả bắt trước mặt các lão quái, mắc kẹt bảy mươi năm trong bụng Vọng Nguyệt rồi thoát ra trong tình trạng thân vỡ nát và bị Vương Lâm đoạt sạch bảo vật. Tính tới mốc mới nhất, hắn đã phục hồi tu vi tới Toái Niết trung kỳ nhờ dâng pháp bảo cho Điên Lạc đại đế, trở thành đại c"},{"id":"oa-oa","name":"Oa Oa","gioiTinh":"nu","aliases":[],"theLuc":[{"ten":"Tử Dương Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tiểu cô nương thuộc Tử Dương Tông, trông coi thú giới trong khe Vân Hải tinh vực. Bề ngoài nhỏ tuổi nhưng tu vi cực kỳ cường hãn, từng cảm nhận thần thức Vương Lâm khi cùng sư phụ ra ngoài tìm dược thảo.","vaiTro":"Đệ tử Tử Dương Tông, trông coi thú giới","tinhCach":"Mạnh mẽ; hồn nhiên; không ngại ra tay","tabs":{"diem":[{"text":"Tu vi cường hãn dù bề ngoài nhỏ tuổi, đá Tham Lang một cước suýt phế tu vi","chuong":"@c1609"},{"text":"Từng cảm nhận thần thức kỳ quái và trao đổi với người tự xưng Vương Lâm khi cùng sư phụ tìm dược thảo","chuong":"@c1609"}],"kinhLich":[{"mucCt":"ky","text":"Phá vây khốn của Tham Lang dễ dàng, đá một cước suýt phế tu vi hắn. Cùng Hàm Hàm bắt Tham Lang kể chuyện Vương Lâm. Nhắc chuyện trước kia cùng sư phụ ra ngoài tìm dược thảo, đã cảm nhận thần thức kỳ quái và trao đổi với người tự xưng Vương Lâm. Khi chín mặt trời ập tới, cùng Hàm Hàm đặt tay lên lưng Tham Lang truyền tu vi cường hãn, khiến hắn tỏa kim quang và xuất hiện mặt trời màu vàng chấn động tinh không.","anchor":"Ta và sư phụ ra ngoài tìm dược thảo, lúc đó cảm nhận được một thần thức kỳ quái","bridge":true,"khoang":"@c1609"},{"mucCt":"gon","text":"Nhận ra Vương Lâm qua cái khe, gọi Hàm Hàm cùng xem, rồi hai cô bé vội phong bế vết nứt và giấu Tham Lang.","anchor":"Hắn chính là người ta nhắc tới lúc trước, hắn cũng tên là Vương Lâm","bridge":true,"khoang":"@c1610"}],"tuViMoc":[],"nhanMach":[{"ten":"Hàm Hàm","tag":"ban-be","quanHe":"Sư tỷ/sư muội cùng Tử Dương Tông, cùng trông coi thú giới","ghiChu":"@c1609"},{"ten":"Tham Lang","tag":"khac","quanHe":"Kẻ xâm nhập thú giới, bị Oa Oa đá suýt phế tu vi rồi bắt kể chuyện","ghiChu":"@c1609"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng cảm nhận thần thức và trao đổi khi cùng sư phụ tìm dược thảo","ghiChu":"@c1609"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1609","@c1610"]},{"id":"vong-nguyet","name":"Vọng Nguyệt","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1609","tieuDe":"","text":"Được Tham Lang nhắc tới khi kể chuyện Vương Lâm cho hai tiểu cô nương: Vương Lâm từng ở trong bụng Vọng Nguyệt.","anchor":"Sau một cước này chính là cuộc đời bi thảm của Tham Lang"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1609"]},{"id":"nam-tu-trung-nien-tu-duong-tong","name":"Nam tử trung niên Tử Dương tông","gioiTinh":"nam","trangThai":"song","blurb":"Nam tử trung niên vẻ mặt uy nghiêm trong đại điện Tử Dương tông, chịu trách nhiệm giám hộ hai đại thiên tôn chuyển thế.","vaiTro":"Cường giả Tử Dương tông, giám hộ đại thiên tôn chuyển thế","tinhCach":"Uy nghiêm; nóng nảy; lo lắng cho an nguy đại thiên tôn chuyển thế","theLuc":[{"ten":"Tử Dương Tông","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Trách mắng các lão giả vì để hai tiểu tổ tông (đại thiên tôn chuyển thế) phong bế tự thú giới đi chơi, nhấn mạnh không được sai lầm nửa điểm.","chuong":"@c1610"}],"kinhLich":[{"mucCt":"gon","text":"Gầm thét trách mắng bảy tám lão giả trong đại điện Tử Dương tông vì hai tiểu tổ tông (đại thiên tôn chuyển thế) phong bế tự thú giới đi chơi, dậm chân khiến cả Tử Dương tông ầm vang.","anchor":"Đại thiên tôn chuyển thế, không được phép sai lầm nửa điểm","bridge":true,"khoang":"@c1610"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1610"]},{"id":"co-hoang","name":"Cổ Hoàng","cn":"古皇","aliases":["Nam tử mặc hoàng bào","hoàng tôn"],"gioiTinh":"nam","theLuc":[{"ten":"Cổ quốc","trangThai":"gan-bo"},{"ten":"Đạo cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Cổ hoàng của cổ quốc, thuộc hoàng tôn nhất mạch, cháu tộc của Huyền La","tinhCach":"Uy nghi nhưng khiêm cung trước bậc trưởng bối; ban đầu khinh miệt khi thấy chỉ một giọt máu, sau kinh ngạc trước bốn giọt","blurb":"Nam tử mặc hoàng bào trông giống hệt pho tượng cổ tổ, thuộc hoàng tôn nhất mạch của cổ quốc. Xuất hiện cùng chín người khổng lồ vạn trượng, được trăm vạn tu sĩ cổ quốc kính bái. Gọi Huyền La Đại Thiên Tôn là tộc thúc.","tabs":{"diem":[{"text":"Trông giống hệt pho tượng cổ tổ, xuất hiện cùng chín người khổng lồ vạn trượng, được trăm vạn tu sĩ cổ quốc kính bái","chuong":"@c1612"},{"text":"Thuộc hoàng tôn nhất mạch, cung kính gọi Huyền La là tộc thúc","chuong":"@c1612"},{"text":"Hoàng tôn Đạo cổ nhất mạch, năm đó đạt sáu giọt máu cổ tổ, là người mạnh nhất chỉ sau Huyền La","chuong":"@c1613"},{"text":"Bất mãn vì Huyền La không nhận mình làm đệ tử, ghen ghét người thừa kế Diệp Mịch (Vương Lâm) vượt qua mình","chuong":"@c1613"},{"text":"Tự nhận hậu nhân chính thống cổ tổ, chảy xuôi huyết mạch cổ tổ, tuyên bố dù Vương Lâm có hồn huyết cũng phải quỳ trước hắn","chuong":"@c1615"},{"text":"Cầm hạt châu đỏ chứa phân hồn nữ tử bí ẩn — quốc sư tiên tri nữ tử này quyết định vận mệnh hắn (thống nhất cổ quốc hoặc tử vong)","chuong":"@c1615"}],"kinhLich":[{"mucCt":"vua","text":"Xuất hiện cùng chín người khổng lồ vạn trượng, được trăm vạn tu sĩ cổ quốc kính bái. Cung kính tham kiến Huyền La đại tôn, gọi là tộc thúc. Nhắc Cực đạo tam hoàng (Cực Hoàng, Cực Huyền) rất chú ý sự kiện. Ban đầu thất vọng khi chỉ thấy một giọt máu, cuối cùng kinh ngạc khi bốn giọt xuất hiện.","anchor":"Hắn xuất hiện khiến cho gần trăm vạn tu sĩ cổ quốc đồng loạt khom lưng vái một vái","bridge":true,"khoang":"@c1612"},{"mucCt":"vua","text":"Ban đầu khinh thường bốn giọt của người thừa kế Diệp Mịch, tự tin vì sáu giọt của mình. Khi giọt thứ sáu ngang bằng hắn thì mặt xanh mét, tới giọt thứ tám ngang Huyền La thì cực lực đè nén ghen ghét, giữ vẻ tươi cười bên ngoài.","anchor":"Nam tử mặc hoàng bào hít sâu một hơi, thật vất vả mới đè nén được lòng ghen ghét xuống","bridge":true,"khoang":"@c1613"},{"mucCt":"ky","text":"Khi giọt máu thứ năm xuất hiện, lần đầu lộ vẻ khiếp sợ. Ngoài mặt chúc mừng Huyền La, ám chỉ Vương Lâm có thể thành tân Đại Thiên Tôn nhằm gây nghi kỵ giữa Huyền La và Vương Lâm, nhưng nội tâm âm hiểm bị Huyền La nhìn xuyên thấu, liếc nhìn khiến hoàng tôn run lên. Khi giọt thứ mười hồn huyết tím hiện ra, sắc mặt xanh mét rồi trắng bệch, sự ghen ghét đạt đỉnh điểm sắp bùng nổ. Bị Huyền La cảnh cáo trực tiếp, vội cúi đầu vâng dạ.","anchor":"Nội tâm nam tử mặc hoàng bào âm hiểm ác độc, lời nói có vẻ dễ nghe nhưng trên thực tế lại dấu diếm hung hiểm","bridge":true,"khoang":"@c1614"},{"importance":"normal","mucCt":"ky","chuong":"@c1615","tieuDe":"Lộ diện — hoàng tôn Đạo cổ phẫn nộ, tiên tri hai kết cục","text":"Trở về hoàng cung trong Thiên Không Chi Thành, phẫn nộ trước việc Huyền La Đại Thiên Tôn coi trọng Vương Lâm, phá hủy hành cung, giết chết thị vệ gần đó, ra lệnh xây lại trong ba ngày. Tuyên bố dù Vương Lâm có hồn huyết cũng phải quỳ trước hắn. Triệu hắc bào lão giả Diệp Đạo hỏi về việc tìm nữ tử có hồn phách trong hạt châu đỏ — Diệp Đạo báo tra khắp cổ quốc không thấy, đang phái người sang tiên tộc. Nghe Diệp Đạo thuật lời tiên tri quốc sư: hai hình ảnh bất động, một là hoàng tôn thống nhất cổ quốc, hai là hoàng tôn tử vong, cả hai đều có thân ảnh người tóc bạc mơ hồ. Hắn tỏ hứng thú, suy tư về mối liên hệ giữa nữ tử và người tóc bạc. Sương mù trong hạt châu hé lộ tướng mạo nữ tử nhưng bị ngón tay hắn che mất.","anchor":"Ta mới là hoàng tôn của Đạo cổ, là hậu nhân được truyền thừa của cổ tổ, chảy xuôi huyết mạch cổ tổ."}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La Đại Thiên Tôn","tag":"ho-hang","quanHe":"Gọi Huyền La là tộc thúc, xưng cung kính đại thiên tôn","gap":"@c1612"},{"ten":"Cực Hoàng","tag":"khac","quanHe":"Cực Hoàng thuộc Cực đạo tam hoàng, mấy lần dùng thần thức trao đổi với cổ hoàng","gap":"@c1612"},{"ten":"Cực Huyền","tag":"khac","quanHe":"Cực Huyền thuộc Cực đạo tam hoàng, cùng Cực Hoàng chú ý sự kiện này","gap":"@c1612"},{"ten":"Huyền La Đại Thiên Tôn","tag":"su-mon","quanHe":"Tộc thúc, người hắn muốn bái sư nhưng bị từ chối","ghiChu":"@c1613"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người thừa kế Diệp Mịch, đạt tám giọt vượt qua sáu giọt của hắn, đối tượng ghen ghét","ghiChu":"@c1613"},{"ten":"Huyền La Đại Thiên Tôn","tag":"cap-tren","quanHe":"Đại Thiên Tôn của Đạo cổ nhất mạch, coi trọng Vương Lâm khiến hoàng tôn phẫn nộ","nguon":"@c1615"},{"ten":"Diệp Đạo","tag":"cap-tren","quanHe":"Hắc bào lão giả thuộc hạ, phụ trách truy tìm nữ tử bí ẩn","nguon":"@c1615"},{"ten":"Quốc sư (Đạo cổ)","tag":"su-mon","quanHe":"Quốc sư của cổ quốc, đưa hạt châu đỏ chứa phân hồn nữ tử và tiên tri hai kết cục cho hoàng tôn","nguon":"@c1615"}],"tuiDo":{}},"nguon":["@c1612","@c1613","@c1614","@c1615"]},{"id":"thac-sam","name":"Thác Sâm","cn":"","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1612","importance":"bridge","mucCt":"gon","text":"Đang dung hợp ký ức Đồ Ti trong Thái cổ Tinh Thần ở giới ngoại, đột nhiên mở mắt đồng tử co rút khi cảm nhận khí tức cổ Mạch Thương Khung Huyết.","anchor":"Nhưng giờ phút này hắn bỗng nhiên mở bừng đôi mắt, đồng tử co rút lại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải, ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ, bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa","chuong":"@c0163"},{"text":"Trao Hỗn Nguyên khu thú quyển và cực phẩm linh thạch cho Vương Lâm, dụ phá phong ấn và ép hấp thu Đồ Ti phách","chuong":"@c0170"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực truy tìm Vương Lâm","chuong":"@c1147"},{"text":"Đại chiến Vương Lâm tại Thái Cổ Tinh Thần, bị chém mất ngón trỏ, cho nổ tinh điểm phá vây","chuong":"@c1239"},{"text":"Quỳ gối nhận truyền thừa Đồ Ti từ Vương Lâm, lần đầu bỏ xưng bổn thần và nói hai chữ đa tạ","chuong":"@c1386"}]},"nguon":["@c1612"],"vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","tinhCach":"Xảo trá, dùng cực phẩm linh thạch và Hỗn Nguyên khu thú quyển làm mồi nhử để mưu cầu phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh của Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần"},{"id":"co-yeu-lao-to-tong","name":"Cổ Yêu","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1612","importance":"bridge","mucCt":"gon","text":"Sống sót sau đại chiến Vân Hải tinh vực, cảm nhận khí tức cổ Mạch Thương Khung Huyết, mơ hồ muốn bái tế.","anchor":"Hắn cảm nhận được khí tức này, mơ hồ khiến hắn muốn bái tế"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lần đầu lộ diện, lập giao kèo với Vương Lâm và kể nguồn gốc chín tồn tại không hoàn chỉnh cùng chiến tranh cửu quận Yêu Lin","chuong":"@c0555"},{"text":"Giáng ý chí cường đại từ Thiên Yêu thành cứu Vương Lâm, mượn máu ngưng huyết ảnh đại chiến tán ma ba ngày","chuong":"@c0565"},{"text":"Đoạt cuốn tranh trong bình bạch ngọc, biến tiên khí thành yêu khí tại Tiên phủ","chuong":"@c0963"},{"text":"Liên thủ cùng Vương Lâm đối đầu Cổ Ma Tháp Già, hóa thất tinh Cổ Yêu thi triển Yêu Linh Biến và tự bạo phân thân cản địch","chuong":"@c0999"},{"text":"Phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, sau đó bị Vương Lâm bắt sống và hiện nguyên hình lục tinh trăm trượng","chuong":"@c1406"},{"text":"Sống sót sau đại chiến Vân Hải tinh vực, cảm nhận khí tức cổ Mạch Thương Khung Huyết và mơ hồ muốn bái tế","chuong":"@c1612"}]},"nguon":["@c1612"],"vaiTro":"Cường giả viễn cổ ẩn trong Yêu Cổ — lão tổ tông Thiên Yêu quận, đồng minh giao kèo của Vương Lâm","tinhCach":"Hành sự qua giao kèo và điều kiện ràng buộc lợi ích, tính toán chặt chẽ; sẵn sàng hao tổn bản thể và tự bạo phân thân để chiến đấu, không né tránh khi cần đối đầu; can thiệp gián tiếp qua trung gian thay vì trực tiếp lộ diện; mỉa mai sắc bén và tự phụ về lai lịch cổ tộc","blurb":"Cổ Yêu là một trong chín tồn tại không hoàn chỉnh từ giới ngoại đến, trú ngụ trong Yêu Cổ với tư cách lão tổ tông của Thiên Yêu quận, thường được gọi là Bối La. Ông lập giao kèo với Vương Lâm từ sớm, nhiều lần giáng ý chí hoặc hiện bản thể cứu viện và tham chiến — từ đại chiến tán ma đến liên thủ đánh Cổ Ma Tháp Già trong Tiên phủ — đồng thời trở thành biến số then chốt trong nhiều bước ngoặt của Vương Lâm. Về sau phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, bị Vương Lâm bắt sống và ép giao nộp bí mật, hiện vẫn tồn tại dưới dạng cổ yêu bị phong ấn trong không gian trữ vật của Vương Lâ"},{"id":"nu-tu-co-than-dong-lam-tinh","name":"Nữ tử Cổ Thần trong Đông Lâm Tinh","gioiTinh":"nu","theLuc":[{"ten":"Cổ Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Cổ Thần vô hình ẩn trong Đông Lâm Tinh sụp đổ, cảm nhận cổ Mạch Thương Khung Huyết","tinhCach":"Hoảng sợ khi cảm nhận khí tức cổ Mạch Thương Khung Huyết","blurb":"Nữ tử Cổ Thần vô hình hiện ra trong Đông Lâm Tinh đã sụp đổ thuộc La Thiên. Run rẩy không khống chế được khi cảm ứng cổ Mạch Thương Khung Huyết, thốt ra tên thần thông này.","tabs":{"diem":[{"text":"Cổ Thần vô hình ẩn trong Đông Lâm Tinh sụp đổ, hoảng sợ run rẩy khi nhận ra cổ Mạch Thương Khung Huyết","chuong":"@c1612"}],"kinhLich":[{"chuong":"@c1612","importance":"normal","mucCt":"gon","tieuDe":"Cảm nhận cổ Mạch Thương Khung Huyết","text":"Hiện hình trong Đông Lâm Tinh đã sụp đổ, mở mắt hoảng sợ, run rẩy không khống chế được, nhận ra khí tức cổ Mạch Thương Khung Huyết.","anchor":"Nữ tử này cũng là Cổ Thần, vào giờ phút này mở bừng đôi mắt, trong mắt hiện lên vẻ hoảng sợ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1612"]},{"id":"cuc-hoang","name":"Cực Hoàng","cn":"极皇","gioiTinh":"nam","theLuc":[{"ten":"Cực đạo tam hoàng","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Một trong Cực đạo tam hoàng, chú ý sự kiện cổ Mạch Thương Khung Huyết","tinhCach":"Chủ động thăm dò, mấy lần dùng thần thức trao đổi với cổ hoàng","blurb":"Một trong Cực đạo tam hoàng của cổ quốc. Rất chú ý sự kiện cổ Mạch Thương Khung Huyết, mấy lần dùng thần thức trao đổi với cổ hoàng. Bị Huyền La cảnh cáo cổ hoàng không nên để ý.","tabs":{"diem":[{"text":"Thuộc Cực đạo tam hoàng, rất chú ý sự kiện cổ Mạch Thương Khung Huyết, mấy lần dùng thần thức trao đổi với cổ hoàng","chuong":"@c1612"}],"kinhLich":[{"chuong":"@c1612","importance":"bridge","mucCt":"gon","text":"Mấy lần dùng thần thức trao đổi với cổ hoàng về sự kiện cổ Mạch Thương Khung Huyết, bị Huyền La cảnh cáo cổ hoàng không nên để ý.","anchor":"Hai người Cực Hoàng và Cực Huyền đối với chuyện ở đây rất chú ý"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Hoàng","tag":"khac","quanHe":"Mấy lần dùng thần thức trao đổi với cổ hoàng về sự kiện cổ Mạch Thương Khung Huyết","gap":"@c1612"}],"tuiDo":{}},"nguon":["@c1612"]},{"id":"cuc-huyen","name":"Cực Huyền","cn":"极玄","gioiTinh":"nam","theLuc":[{"ten":"Cực đạo tam hoàng","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Một trong Cực đạo tam hoàng, cùng Cực Hoàng chú ý sự kiện cổ Mạch Thương Khung Huyết","tinhCach":"Chủ động theo dõi sự kiện","blurb":"Một trong Cực đạo tam hoàng của cổ quốc. Cùng Cực Hoàng chú ý sự kiện cổ Mạch Thương Khung Huyết. Bị Huyền La cảnh cáo cổ hoàng không nên để ý.","tabs":{"diem":[{"text":"Thuộc Cực đạo tam hoàng, cùng Cực Hoàng chú ý sự kiện cổ Mạch Thương Khung Huyết","chuong":"@c1612"}],"kinhLich":[{"chuong":"@c1612","importance":"bridge","mucCt":"gon","text":"Cùng Cực Hoàng chú ý sự kiện cổ Mạch Thương Khung Huyết, bị Huyền La cảnh cáo cổ hoàng không nên để ý.","anchor":"Hai người Cực Hoàng và Cực Huyền đối với chuyện ở đây rất chú ý"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Hoàng","tag":"khac","quanHe":"Cùng Cực Hoàng trao đổi thần thức với cổ hoàng về sự kiện","gap":"@c1612"}],"tuiDo":{}},"nguon":["@c1612"]},{"id":"do-ti","name":"Đồ Ti","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1614","tieuDe":"Được nhắc trong hình ảnh huyễn hóa","text":"Được nhắc qua hình ảnh Vương Lâm huyễn hóa trước cổ tổ: cảnh Vương Lâm đạt được truyền thừa ký ức của Đồ Ti trên Chu Tước Tinh.","anchor":"cuối cùng đạt được truyền thừa ký ức của Đồ Ti"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Phân thân xuất hiện sau mười ba năm thử luyện, công nhận Vương Lâm là người lĩnh ngộ và truyền lại ký ức cùng truyền thừa Cổ Thần vương tộc","chuong":"@c0160"},{"text":"Được La Trần xác nhận đã chết; truyền thừa của lão trong Vương Lâm được nhận ra qua Diệt Thần Mâu","chuong":"@c0882"},{"text":"Đơn độc mở ra không gian Cổ Thần Chi Địa, thân thể khổng lồ tồn tại trong khe không gian","chuong":"@c0996"},{"text":"Tự tế luyện Cổ Thần Đại Đỉnh và luyện chế Tam Xoa Kích mang thần thông thôn phệ vạn vật, song chưa hoàn chỉnh Mặc Lưu Phân Thần Thuật","chuong":"@c1149"},{"text":"Thân thể vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ bị Thác Sâm chiếm đoạt","chuong":"@c1383"},{"text":"Hư ảnh Đồ Ti tan vỡ khi Vương Lâm tuyên bố không còn là truyền thừa của lão, trả lại truyền thừa bát tinh sau hơn ngàn năm","chuong":"@c1385"}]},"nguon":["@c1614"],"vaiTro":"Cổ thần chủ Cấm Sơn — nguồn truyền thừa Cổ Thần vương tộc của Vương Lâm","tinhCach":"Thận trọng, chọn lọc kỹ càng người kế thừa; kiêu hãnh mang khí phách đặc trưng của Cổ Thần; đơn độc khai phá, tự lực cánh sinh","blurb":"Đồ Ti là Cổ thần vương tộc bát tinh đến từ Thái Cổ Tinh Thần — nơi không tồn tại Phong giới trận — và là người đơn độc mở ra không gian Cổ Thần Chi Địa, lấy Cấm Sơn làm nơi đặt truyền thừa. Sau mười ba năm thử luyện, phân thân của lão công nhận Vương Lâm là người lĩnh ngộ, truyền lại ký ức và truyền thừa Cổ Thần mang tính vương tộc, dù phần ký ức ấy chưa trọn vẹn và còn bị phong ấn. Bản thân Đồ Ti đã được La Trần xác nhận là đã chết, thân thể khổng lồ tồn tại bên trong khe không gian và sau đó bị Thác Sâm chiếm đoạt; di sản của lão — từ ký ức, Cổ Thần Đỉnh, Tam Xoa Kích đến Mặc Lưu Phân Thần T"},{"id":"diep-dao","name":"Diệp Đạo","gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hắc bào lão giả, thuộc hạ hoàng tôn Đạo cổ. Phụ trách truy tìm nữ tử có hồn phách trong hạt châu đỏ, thuật lại lời tiên tri của quốc sư về hai kết cục của hoàng tôn.","vaiTro":"Thuộc hạ hoàng tôn Đạo cổ, hắc bào lão giả","tinhCach":"Trung thành; cẩn trọng khi báo cáo","tabs":{"diem":[{"text":"Thuộc hạ hoàng tôn Đạo cổ, tra khắp cổ quốc tìm nữ tử bí ẩn không thấy, đã phái người sang tiên tộc","chuong":"@c1615"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1615","tieuDe":"Báo cáo hoàng tôn về nữ tử bí ẩn và lời tiên tri quốc sư","text":"Được hoàng tôn triệu kiến, báo đã tra khắp cổ quốc không thấy nữ tử có hồn phách trong hạt châu, đang phái người sang tiên tộc tìm. Thuật lại lời quốc sư trước khi bế quan: thấy hai hình ảnh bất động — hoàng tôn thống nhất cổ quốc hoặc tử vong, cả hai đều có thân ảnh người tóc bạc.","anchor":"Hoàng tôn, ti chức đã tra cả cổ quốc, cũng không thấy nữ tử này."}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Hoàng","tag":"cap-tren","quanHe":"Hoàng tôn Đạo cổ, chủ nhân của Diệp Đạo","nguon":"@c1615"},{"ten":"Quốc sư (Đạo cổ)","tag":"khac","quanHe":"Quốc sư cổ quốc, đã giao phó lời tiên tri cho Diệp Đạo thuật lại","nguon":"@c1615"}],"tuiDo":{}},"nguon":["@c1615"]},{"id":"quoc-su-dao-co","name":"Quốc sư (Đạo cổ)","gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Quốc sư của cổ quốc, dung nhập tâm thần vào u minh, mang phân hồn nữ tử bí ẩn từ nơi kỳ dị có tồn tại thiên đạo. Tiên tri hai kết cục cho hoàng tôn, hiện đang bế quan.","vaiTro":"Quốc sư cổ quốc, nhân vật bí ẩn đang bế quan","tinhCach":"Thâm trầm bí ẩn; có năng lực dung nhập u minh; biết tiên tri","tabs":{"diem":[{"text":"Dung nhập tâm thần vào u minh, mang phân hồn nữ tử từ nơi kỳ dị có tồn tại thiên đạo","chuong":"@c1615"},{"text":"Tiên tri hai hình ảnh cho hoàng tôn: thống nhất cổ quốc hoặc tử vong, cả hai có người tóc bạc","chuong":"@c1615"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1615","tieuDe":"Được nhắc — tiên tri hai kết cục và hạt châu đỏ","text":"Qua lời Diệp Đạo: trước khi bế quan, quốc sư đã dung nhập tâm thần vào u minh mang phân hồn nữ tử từ nơi kỳ dị có thiên đạo đặt vào hạt châu đỏ giao cho hoàng tôn. Tiên tri thấy hai hình ảnh bất động — hoàng tôn thống nhất cổ quốc hoặc tử vong, cả hai đều có thân ảnh người tóc bạc mơ hồ.","anchor":"quốc sư cũng không nhìn rõ nhưng chỉ nhớ rõ người này có mái tóc bạc!"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Hoàng","tag":"khac","quanHe":"Hoàng tôn Đạo cổ, người được quốc sư giao hạt châu đỏ và tiên tri","nguon":"@c1615"}],"tuiDo":{}},"nguon":["@c1615"]},{"id":"nu-tu-bi-an-hat-chau-do","name":"Nữ tử bí ẩn (hồn phách trong hạt châu đỏ)","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Chỉ còn phân hồn ngồi khoanh chân trong hạt châu đỏ, tướng mạo bị sương mù che phủ. Quốc sư mang phân hồn nàng từ nơi kỳ dị có tồn tại thiên đạo, tiên tri nàng có thể giúp hoàng tôn Đạo cổ đoạt cả cổ quốc.","vaiTro":"Nữ tử bí ẩn chỉ còn phân hồn, liên quan đến vận mệnh hoàng tôn Đạo cổ","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Chỉ phân hồn trong hạt châu đỏ, bị sương mù che tướng mạo, hoàng tôn chê tầm thường","chuong":"@c1615"},{"text":"Quốc sư tiên tri nàng quyết định vận mệnh hoàng tôn — thống nhất cổ quốc hoặc tử vong","chuong":"@c1615"}],"kinhLich":[{"mucCt":"vua","text":"Phân hồn ngồi khoanh chân bên trong hạt châu đỏ, bị sương mù che phủ tướng mạo. Quốc sư mang phân hồn nàng từ nơi kỳ dị có thiên đạo. Hoàng tôn dự tính tìm thân xác nàng, chê tướng mạo tầm thường. Cuối chương sương mù hé mở nhưng bị ngón tay hoàng tôn che mất.","anchor":"Tướng mạo nữ tử này tầm thường, cũng chẳng vừa mắt ta.","bridge":true,"khoang":"@c1615"},{"mucCt":"gon","text":"Hồn phách nằm trong lòng bàn tay Vương Lâm, bị tuyên bố ân oán xóa bỏ rồi tiễn vào luân hồi, hồn phách tiêu tán.","anchor":"Ân oán giữa ta và ngươi từ nay xóa bỏ, tiễn ngươi vào luân hồi, tự thu xếp nhé","bridge":true,"khoang":"@c1618"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Hoàng","tag":"khac","quanHe":"Hoàng tôn cầm hạt châu chứa phân hồn nàng, dự tính tìm thân xác nàng để lấy làm hậu","nguon":"@c1615"}],"tuiDo":{}},"nguon":["@c1615","@c1618"]},{"id":"co-to","name":"Cổ Tổ","cn":"古祖","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (sinh trước thiên địa)","trangThai":"khong-ro","blurb":"Thủy tổ của cổ tộc, sinh ra trước khi thiên địa xuất hiện. Thề hủy diệt tiên vì tiên muốn nô dịch hắn, giao chín giọt hồn huyết cho ba người con và dặn chờ người kế thừa.","vaiTro":"Thủy tổ cổ tộc, nguồn gốc huyết mạch và ý chí nghịch tiên","tinhCach":"Ngạo nghễ bá đạo; ý chí nghịch thiên bất khuất; không chấp nhận bị nô dịch","tabs":{"diem":[{"text":"Sinh ra trước thiên địa, tuyên bố muốn trời sụp thì trời sụp, muốn đất tan thì đất tan","chuong":"@c1616"},{"text":"Thề hủy diệt tiên vì tiên muốn nô dịch, truyền khẩu quyết nghịch thiên cho hậu nhân","chuong":"@c1616"}],"kinhLich":[{"chuong":"@c1616","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện trong mộng Vương Lâm, lộ nguồn gốc và ý chí","text":"Xuất hiện trong giấc mộng Vương Lâm dưới hình dạng nam tử tướng mạo tầm thường, thân thể khổng lồ, thiên địa dưới chân. Tuyên bố sinh ra trước khi thiên địa xuất hiện, nhưng tiên xuất hiện trước hắn và muốn nô dịch, nên thề hủy diệt tiên. Giao chín giọt hồn huyết cho ba người con, dặn thống lĩnh vạn dân cổ tộc, đời đời chờ luân hồi, chờ người kế thừa. Truyền khẩu quyết: Thuận là phàm, nghịch là tiên, nghịch thiên thành tiên, nghịch tiên thành cổ.","anchor":"Ta là cổ, sinh ra trước khi thiên địa xuất hiện, trong khi vũ trụ còn sơ khai"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người kế thừa huyết mạch và hồn phách","ghiChu":"Vương Lâm nhận truyền thừa chín giọt máu tươi và giọt hồn huyết, tương đương con trai thứ tư Cổ Tổ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1616"]},{"id":"tu-si-dao-nhat-tong","name":"Tu sĩ Đạo Nhất Tông (không rõ tên)","gioiTinh":"nam","theLuc":[{"ten":"Đạo Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ thuộc Đạo Nhất Tông, giao chiến với Huyền La Đại Thiên Tôn trên chín tầng trời tại phạm vi tiên tộc Tiên Cương đại lục.","vaiTro":"Đối thủ của Huyền La Đại Thiên Tôn trên chín tầng trời","tinhCach":"Thận trọng, giỏi suy đoán ý đồ đối phương","tabs":{"diem":[{"text":"Cố ngăn cản Huyền La tiến vào khu vực tiên tộc, suy đoán hắn có chuyện trọng đại","chuong":"@c1620"}],"kinhLich":[{"mucCt":"gon","text":"Giao chiến với Huyền La Đại Thiên Tôn trên chín tầng trời phạm vi tiên tộc, cố ngăn cản hắn. Hỏi Huyền La đã tìm được người bảo vệ chuyển thế hay chưa, đề nghị tặng một người. Suy đoán Huyền La vội vã đến tiên tộc nhất định có chuyện trọng đại.","anchor":"Ngươi vội vã như vậy, lần này tới tiên tộc ta nhất định có chuyện trọng đại rồi","bridge":true,"khoang":"@c1620"}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La Đại Thiên Tôn","tag":"doi-thu","quanHe":"Đối thủ giao chiến trên chín tầng trời","ghiChu":"@c1620"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1620"]},{"id":"chu-dat","name":"Chu Dật","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Nhìn Thanh Sương từ xa với thần sắc phức tạp, bi ai nhưng thỏa mãn. Tới uống rượu cùng Vương Lâm, không nói một câu, cạn hết chén này tới chén khác rồi gật đầu rời đi. Vẫn chọn chờ đợi Thanh Sương tán thành sự tồn tại của mình, dù có thể chờ cả đời.","anchor":"Bóng lưng của hắn hiu quạnh","bridge":true,"khoang":"@c1621"},{"importance":"bridge","mucCt":"gon","chuong":"@c1622","tieuDe":"","text":"Ở phía sau Thanh Sương trên sườn tuyết sơn, thấp giọng nói chuyện với ánh mắt tràn ngập nhu hòa và tình yêu say đắm.","anchor":"ánh mắt nhìn Thanh Sương tràn ngập nhu hòa và tình yêu say đắm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lộ diện tại đáy động tầng 2 với thân phận đại trưởng lão Thi Âm Tông, tiết lộ lai lịch tu sĩ Ngũ Hành Tông từ Chu Tước tinh, mang theo nữ thi tiên nhân Đình Nhi","chuong":"@c0288"},{"text":"Thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm, Nguyên Thần nhập kiếm trở thành Kiếm Tiêu Chi Hồn","chuong":"@c0293"},{"text":"Linh thể bị phong ấn mấy trăm năm trong Luyện Tiên Hóa Ma đại trận, toàn thân hao tổn nghiêm trọng nhưng vẫn không khuất phục, cứu Vương Lâm thoát hiểm","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh Hư Không Tử, dẫn phát thương thế cũ của đối phương khiến tu vi hắn sụt giảm, bản thân linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Bi kịch quên lãng: gặp lại Thanh Sương nhưng bị nàng phủ nhận, thần sắc chua xót bi thương nhưng vẫn lặng lẽ thủ hộ băng sơn nàng ngủ","chuong":"@c1046"},{"text":"Được Vương Lâm thu hồi vận mệnh, cuối cùng đứng phía sau Thanh Sương trên sườn tuyết sơn với ánh mắt tràn ngập nhu hòa và tình yêu sâu kín","chuong":"@c1622"}]},"nguon":["@c1621","@c1622"],"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân giao phó di sản cho Vương Lâm","tinhCach":"Si tình đến cùng cực, nhiều lần thiêu đốt Nguyên Thần vì Đình Nhi và suốt đời lặng lẽ thủ hộ Thanh Sương dù bị phủ nhận quên lãng; trọng nghĩa khí, tận lực trợ chiến và bảo hộ Vương Lâm xuyên suốt không tính toán; kiên nghị bất khuất, chịu phong ấn hàng trăm năm trong Luyện Tiên Hóa Ma đại trận vẫn ","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông trên Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, suốt đời mang theo nữ thi tiên nhân Đình Nhi bên mình. Vì cứu Đình Nhi, y nhiều lần thiêu đốt Nguyên Thần, đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn rồi giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm; Nguyên Thần nhập kiếm trở thành Kiếm Tiêu Chi Hồn, y tiếp tục đồng hành trợ chiến xuyên suốt hành trình Vương Lâm — từ Triều Tịch vực, qua Yêu Linh chi địa đến Vũ Tiên Giới — chịu đựng cả bi kịch bị Thanh Sương phủ nhận và quên lãng mà vẫn lặng lẽ thủ hộ, cuố"},{"id":"chu-nhu","name":"Chu Như","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1621","importance":"bridge","mucCt":"vua","text":"Đã trưởng thành, bên cạnh có con hổ làm bạn, ở bên Vương Lâm như cô con gái, ánh mắt tràn ngập vẻ không muốn rời xa.","anchor":"Chỉ là nhà của đầu to đã mất từ lâu"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn tại Hạnh Hoa Thôn qua tranh sinh tử luân hồi của Vương Lâm, chào đời thành Chu Như","chuong":"@c0314"},{"text":"Hồn phách bị Nguyên Anh Lý Mộ Uyển đẩy ra khỏi nhục thân, được Vương Lâm triệu hồi sống sót rồi bị xóa ký ức, sau đó lang thang cùng Tiểu Bạch tìm thúc thúc khắp Nguyệt tinh","chuong":"@c0381"},{"text":"Được Vương Lâm đưa về nhà đoàn tụ phụ mẫu sau hai mươi năm xa cách, thề tu tiên tìm lại hắn; đã tu tới Ngưng Khí kỳ nhờ khẩu quyết Vương Lâm truyền","chuong":"@c0441"},{"text":"Kết Đan thành công trên con đường tu tiên độc lập, tiếp tục đặt mục tiêu tìm Vương Lâm","chuong":"@c0567"},{"text":"Đạt Anh Biến nhờ Thiết Nham hy sinh tuổi thọ và sức lực, rời Chu Tước Tinh bước vào tinh vực rộng lớn hơn","chuong":"@c0846"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín, kết thúc hành trình tìm kiếm kéo dài cả đời","chuong":"@c1540"}]},"nguon":["@c1621"],"vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — người được Vương Lâm bảo hộ suốt đời","tinhCach":"Dã tính phóng khoáng, ưa cưỡi mãnh thú phiêu bạt thâm sơn; quyến luyến Vương Lâm sâu đậm đến mức bất chấp gian nguy để tìm kiếm; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; có chí khí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích duy nhất","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển đầu thai qua tranh sinh tử luân hồi của Vương Lâm, chào đời tại Hạnh Hoa Thôn và được hắn âm thầm bảo hộ từ thuở sơ sinh. Trải qua kiếp nạn bị cưỡng đoạt lúc nhỏ, tách hồn khỏi Nguyên Anh Lý Mộ Uyển, bị xóa ký ức rồi đoàn tụ phụ mẫu, nàng một mình bước lên con đường tu tiên từ Ngưng Khí qua Kết Đan đến Anh Biến, suốt đời lấy việc tìm lại Vương Lâm làm mục đích duy nhất. Nàng nhiều lần tái ngộ hắn tại Côn Hư cảnh và Tân Vũ Giới, kiên quyết theo Tư Đồ Nam rời Vũ Giới tiếp tục hành trình tìm kiếm, rồi cuối cùng được Vương Lâm tìm thấy, thu hồ"},{"id":"thap-tam","name":"Thập Tam","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Tu luyện bên cạnh Vương Lâm, ý niệm duy nhất là trở thành đệ tử cực mạnh của sư tôn.","anchor":"Thập Tam lại là một người đơn giản."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Trời sinh ngộ tính, tu luyện Luyện Hồn Yêu Thuật ba tháng đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi thành người tàn phế, không cam lòng mà mỗi đêm chịu đau thổ nạp tự phát luyện thể theo pháp Cự Ma Tộc","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu, quỳ đập đầu thề cả đời tôn Vương Lâm làm Lão tổ","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm trên đỉnh núi cao nhất suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu chờ sư tôn","chuong":"@c1018"},{"text":"Sớm nhất rời Vũ Giới, mang pho tượng Vương Lâm dựa cảm ứng mơ hồ tìm kiếm sư tôn khắp tinh vực, gặp lại và nhận hạt giống lôi hỏa bổn nguyên","chuong":"@c1472"},{"text":"Quỳ dập đầu trước tượng Vương Lâm trên Chu Tước Tinh, thề dưới con mắt vạn người công khai danh phận đệ tử","chuong":"@c1494"}]},"nguon":["@c1621"],"vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn tại Thiên Vận Tinh","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, quỳ bái Vương Lâm làm Lão tổ và ngồi canh tượng đá suốt nghìn ngày đêm; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là thanh niên trời sinh ngộ tính với Luyện Hồn Yêu Thuật, chỉ ba tháng đã đạt giai đoạn ba và được Vương Lâm thu nhận làm đại đệ tử. Sau khi bị phế tu vi thành người tàn phế, gã không cam lòng mà mỗi đêm chịu đau thổ nạp luyện thể theo pháp Cự Ma Tộc, dần khôi phục sức mạnh, nhận truyền thừa Cự Linh Cửu Tu rồi quỳ đập đầu tôn Vương Lâm làm Lão tổ, về sau trở thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, được rèn thân thể bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa "},{"id":"dong-tu-dau-to","name":"Đồng tử đầu to","aliases":["Đầu to"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1621","importance":"normal","mucCt":"vua","tieuDe":"Được trả hồn huyết, giải phong ấn","text":"Vương Lâm trả hồn huyết và giải phong ấn, được tự do hoàn toàn. Không chọn rời đi mà ở lại bên Vương Lâm, nhìn bầu trời nhớ nhà dù nhà đã mất từ lâu.","anchor":"Chỉ là nhà của đầu to đã mất từ lâu"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Dẫn quân La Thiên xâm phạm Chu Tước Tinh, bị Vương Lâm đánh bại và phong ấn nguyên thần, chính thức quy phục xưng chủ nhân","chuong":"@c0838"},{"text":"Định tự bạo nguyên thần liều mạng khi bị sáu phân thân Khuy Niết của Vu Phi dồn ép đến tuyệt vọng","chuong":"@c0853"},{"text":"Nhục thân sụp đổ sau trận chiến với phân thân Thiên Vận Tử, nguyên thần trọng thương sắp tan","chuong":"@c1009"},{"text":"Được tái tạo nhục thân mới tại Chu Tước Thánh Tông nhờ trưởng lão Toái Niết trợ giúp","chuong":"@c1016"},{"text":"Tự rời Tân Vũ Giới cùng Lôi Cát đi tìm chủ nhân Vương Lâm","chuong":"@c1440"},{"text":"Được Vương Lâm trả hồn huyết và giải phong ấn, tự do hoàn toàn nhưng chọn ở lại bên chủ nhân","chuong":"@c1621"}]},"nguon":["@c1621"],"vaiTro":"Thiên Cương tiên La Thiên — thuộc hạ trung thành được Vương Lâm thu phục, phó tướng giới nội","tinhCach":"ngoài mặt cười ngây ngô nhưng nội tâm thận trọng toan tính; tuyệt đối trung thành với Vương Lâm, sẵn sàng tự bạo nguyên thần khi chủ nhân lâm nguy; mang quá khứ bị gia tộc ruồng bỏ nên cô độc trầm lặng; am hiểu cấm chế, có tạo nghệ về phá giải trận pháp","blurb":"Đồng tử đầu to là tu sĩ Khuy Niết La Thiên Bắc Vực, thuộc nhóm Thiên Cương tiên hiếm hoi có thể khắc tên lên Phong Tiên thạch. Ban đầu hắn dẫn quân xâm phạm Chu Tước Tinh và khinh miệt tinh cầu này, nhưng bị Vương Lâm đánh bại, phong ấn nguyên thần rồi thu phục — từ đó trở thành thuộc hạ trung thành, theo hộ pháp và chiến đấu xuyên suốt Tiên Di Tộc, Tiên phủ thứ tư, chiến trường liên minh tây bộ cho tới khi nhục thân sụp đổ tại Yêu Linh chi địa và được tái tạo thân mới tại Chu Tước Thánh Tông. Sau đó hắn được an bài về Tân Vũ Giới nhưng tự rời đi tìm chủ nhân, trưởng thành qua chiến đấu tại Ch"},{"id":"thanh-suong","name":"Thanh Sương","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1621","importance":"bridge","mucCt":"gon","text":"Đi sau Thanh Lâm khi nghênh đón Vương Lâm, được Chu Dật nhìn từ xa với thần sắc u buồn.","anchor":"Bóng lưng của hắn hiu quạnh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1622","tieuDe":"","text":"Mặc bạch y ở sườn tuyết sơn phía nam tiên giới, nhìn thiên địa gắng nhớ lại ký ức chưa phục hồi hoàn toàn.","anchor":"sắc mặt hình như đang gắng nhớ lại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thanh âm thì thào khi Vương Lâm đắc kim phù ấn — lần đầu danh tính được hé lộ","chuong":"@c0521"},{"text":"Từng bày kế lợi hại áp chế đối thủ, khiến động phủ Thanh Lâm phát sinh biến cố khi mở ra","chuong":"@c0951"},{"text":"Thân thể bị Cổ Ma Tháp Già chi phối và tranh đoạt trong tầng chín động phủ","chuong":"@c0996"},{"text":"Tạm thời sống lại trong thức hải Thanh Lâm, đau lòng vì Chu Dật rồi dung nhập thể Vương Lâm","chuong":"@c1047"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Trở về tiên giới mặc bạch y nơi sườn tuyết sơn, ký ức chưa phục hồi hoàn toàn","chuong":"@c1622"}]},"nguon":["@c1621","@c1622"],"vaiTro":"Tiên quân bí ẩn của Vũ Tiên Giới — con gái Tiên Đế Thanh Lâm, di thể được Vương Lâm mang theo","tinhCach":"mưu lược sâu xa, giỏi bày kế áp chế đối thủ; nặng tình, đau lòng khi thấy Chu Dật khổ sở; ẩn nhẫn, nén cảm xúc không để lộ","blurb":"Thanh Sương là Tiên quân của Vũ Tiên Giới, con gái Tiên Đế Thanh Lâm — danh tính thần bí mà Vương Lâm lần đầu nghe qua thanh âm thì thào khi đắc kim phù ấn tại Yêu Linh chi địa. Di thể của nàng do Chu Dật gửi gắm, sau đó Vương Lâm mang theo suốt hành trình với hy vọng phục sinh nhờ phụ thân Thanh Lâm; thân thể từng bị Cổ Ma Tháp Già chi phối trong cuộc tranh đoạt tại động phủ, rồi tạm thời sống lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới. Về sau Vương Lâm tìm thấy nàng trong mặt trời thứ chín và thu hồi vận mệnh; nàng trở về tiên giới đi sau Thanh Lâm ngh"},{"id":"lang-thien-hau","name":"Lăng Thiên Hầu","tabs":{"kinhLich":[{"mucCt":"vua","text":"Trong huyễn cảnh quá khứ Vương Lâm thấy qua Mộng Đạo: ngồi khoanh chân hôn mê trên thiên thạch Triệu Hà xưa, đối diện Thiên Vận Tử, bị Thiên Vận Tử há miệng cắn nuốt cực kỳ quỷ dị.","anchor":"cắn nuốt Lăng Thiên Hầu cực kỳ quỷ dị","bridge":true,"khoang":"@c1626"}],"diem":[{"text":"Cưỡi Kỳ Lân tiên thú xông vào mảnh vỡ tiên giới tranh kiếm tiên, bị Tiên chỉ đánh trọng thương nửa người trên vỡ nát","chuong":"@c0299"},{"text":"Dàn mưu mượn hiện tượng thủy triều năm nghìn năm một lần để hút đạo kiếm hồn của nữ quân tiên giới","chuong":"@c0487"},{"text":"Dẫn đệ tử vây Thiên Vận Tông đòi lệnh bài, thử Vương Lâm ba đạo kiếm khí rồi phong làm trưởng lão khách khanh","chuong":"@c0899"},{"text":"Thi triển sáu đạo nguyên thần kiếm công kích phong ấn chữ Ma tại tầng thứ bảy Tiên phủ","chuong":"@c0991"},{"text":"Bị Cổ Ma truy sát trong Tiên phủ, trước ngực mang chưởng ấn đen, phải cầu Vương Lâm liên thủ","chuong":"@c0994"},{"text":"Chứng kiến uy lực Tàn Dạ và Chu Tước chân linh của Vương Lâm, chuyển từ kiêng kị sang sợ hãi thực sự","chuong":"@c1004"}]},"nguon":["@c1626"],"vaiTro":"Phụ — Kiếm Tôn Đại La Kiếm Tông, đại năng Anh Biến kỳ trên Thiên Vận tinh","tinhCach":"Ngạo mạn, không nể mặt ngay cả Thiên Vận Tử; quyết đoán liều lĩnh khi tranh đoạt bảo vật tiên giới; nhiều mưu tính, ấp ủ kế hoạch dài hạn nhắm tới kiếm hồn nữ quân tiên giới; hộ đoản, nổi tiếng bao che đệ tử và dễ nổi giận khi môn nhân bị tổn hại","blurb":"Lăng Thiên Hậu là Kiếm Tôn của Đại La Kiếm Tông, tu vi Anh Biến kỳ, được xem là nhân vật số một số hai trên Thiên Vận tinh, luyện thành kiếm nguyên thần từ tứ tiểu thiên địa và cưỡi Hỏa Hồng Kỳ Lân ra trận. Lão từng xông vào mảnh vỡ tiên giới tranh Vũ Chi Tiên Kiếm, bị Tiên chỉ trọng thương rồi bị Chu Dật hóa kiếm ảnh truy sát; về sau dàn mưu mượn thủy triều năm nghìn năm để thu phục kiếm hồn, vây ép Thiên Vận Tông đòi lệnh bài, phong Vương Lâm làm trưởng lão khách khanh và cùng liên quân thâm nhập Tiên phủ. Trong cuộc khám phá Tiên phủ, lão nhiều lần rơi vào cảnh nguy nan — bị Cổ Ma truy sát,"},{"id":"nguoi-dien","name":"Tu sĩ điên","aliases":["Liên Đạo Phi","Lão quái vật"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1628","tieuDe":"Hé lộ chân tướng quá khứ qua luân hồi Thiên Vận Tử","text":"Chân tướng quá khứ được Vương Lâm ngộ ra trong luân hồi: Liên Đạo Phi vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, có ca ca thân phận cực cao, tính cách kiêu ngạo quỷ dị, thích cướp đoạt mọi thứ. Tới động phủ Thất Thải Tiên Tôn cướp vật nhưng bị thiên đạo cắn nuốt, phải tự bạo thần thức để ngăn cản. Phần tham lam và tính xấu bị tách ra, bị thiên đạo hấp thu, nên trở thành người điên hoàn toàn khác xưa. Vương Lâm thích hắn hiện tại hơn Liên Đạo Phi năm xưa.","anchor":"Phần tham lam và những tính xấu của hắn không ngờ lại bị tách ra cuối cùng bị thiên đạo hấp thu"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị nhốt trong Thất Thải Giới không biết bao nhiêu năm, cô đơn đến phát điên, phát hiện thi thể Vương Lâm rơi tới và dùng máu tươi cực quý cứu sống, biến đổi thể chất Vương Lâm","chuong":"@c1441"},{"text":"Thi triển Dịch Linh Ấn hoàn chỉnh chính tông, truyền thụ ba thần thông độc nhất vô nhị cho Vương Lâm","chuong":"@c1449"},{"text":"Quỳ dập đầu bái Vương Lâm làm sư phụ, thề lấy tiên tổ cả đời không phản bội sư môn, hé lộ bí mật Tiên Chi Cửu Tuyệt","chuong":"@c1450"},{"text":"Liều mình lao vào Thất Thải Thương cứu Vương Lâm, thân phát kim quang nồng đậm, cả hai bị hắc động nuốt vào hư vô","chuong":"@c1493"},{"text":"Thân phận viễn cổ tiên tộc được Vương Lâm xác nhận khi đang hôn mê trong không gian trữ vật","chuong":"@c1545"},{"text":"Chân tướng quá khứ được hé lộ qua luân hồi: Liên Đạo Phi vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, cố hương gọi là Tiên Cương đại lục","chuong":"@c1628"}]},"nguon":["@c1628"],"vaiTro":"Tu sĩ bí ẩn mang huyết mạch tiên tộc viễn cổ, ân nhân và đệ tử của Vương Lâm","tinhCach":"Điên loạn do cô đơn quá lâu, tự tạo nhân vật tưởng tượng để trò chuyện; Tự phụ xưng bổn vương nhưng nhát gan trước nguy hiểm thực sự, luôn cố giữ thể diện; Tình cảm sâu nặng với ca ca và ba nương, nhiều lần nhắc không muốn ca ca tìm mình; Trọng nghĩa khí, sẵn sàng hy sinh máu quý cứu người và liều m","blurb":"Tu sĩ mang huyết mạch tiên tộc viễn cổ, chân danh Liên Đạo Phi, vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, bị nhốt trong Thất Thải Giới bên trong cơ thể U Minh Thú không rõ bao nhiêu năm, cô đơn đến phát điên, tự tạo ra các nhân vật tưởng tượng như Tiểu Hồng, Tiểu Ngân để trò chuyện. Sau khi phát hiện thi thể Vương Lâm rơi vào, hắn liên tục dùng máu tươi cực quý của bản thân cứu sống và biến đổi thể chất Vương Lâm, truyền thụ Dịch Linh Ấn chính tông cùng ba thần thông độc nhất vô nhị, rồi quỳ bái Vương Lâm làm sư phụ, hé lộ bí mật Tiên Chi Cửu Tuyệt. Về sau hắn đồng hành cùng Vương Lâm ra gi"},{"id":"u-minh-thu","name":"U Minh thú","gioiTinh":"khong-ro","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Thu nhỏ còn ngàn trượng, chở Vương Lâm trong tinh không bằng ý niệm. Được Vương Lâm xác nhận là một bộ phận của thiên đạo. Đưa Vương Lâm tới Triệu Hà tinh vực.","anchor":"Không ngờ năm đó thu phục con thú này lại là một bộ phận của thiên đạo","bridge":true,"khoang":"@c1631"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị Vương Lâm phong ấn ba tầng trong cấm địa sương mù La Thiên, thu phục làm bổn mệnh thú, sinh mệnh từ đó gắn liền","chuong":"@c1412"},{"text":"Mở U Minh Hồn Khẩu nuốt trọn cuồng phong chuông vàng, cứu nguy tinh vực Vân Hải","chuong":"@c1419"},{"text":"Bộc lộ bản tính cổ quái: gầm thét uy hiếp tu sĩ bốn phía nhưng sợ hãi vọt về nép vào Vương Lâm khi bị nhìn chằm chằm","chuong":"@c1420"},{"text":"Sinh mệnh tương thông với Vương Lâm, đau đớn truyền vào tâm thần khiến tỉnh dậy và phun ra cuồng phong trợ chiến","chuong":"@c1439"},{"text":"Huyễn hóa hư ảnh khổng lồ bao trùm trận pháp, thôn phệ mãnh thú viễn cổ trong Vô Danh Chuyển Luân trận","chuong":"@c1576"},{"text":"Thu nhỏ còn ngàn trượng chở Vương Lâm trong tinh không, được xác nhận là một bộ phận của Vương Lâm","chuong":"@c1631"}]},"nguon":["@c1631"],"vaiTro":"Bổn mệnh thú của Vương Lâm — linh thú cổ quái sở hữu U Minh Hồn Khẩu","tinhCach":"Hung hãn dữ tợn khi chiến đấu nhưng nhút nhát run rẩy khi bị đám đông chú ý; tính cách cổ quái, nép vào Vương Lâm như hài tử nép cha mẹ; tham ăn, nuốt cuồng phong rồi nhấm nháp thưởng thức","blurb":"Linh thú khổng lồ vốn ngủ trong cấm địa sương mù La Thiên, bị Vương Lâm phong ấn ba tầng thu phục làm bổn mệnh thú, sinh mệnh từ đó gắn liền chủ nhân. Sở hữu U Minh Hồn Khẩu uy lực kinh người đủ nuốt cả tinh không, từng nuốt trọn cuồng phong chuông vàng cứu nguy Vân Hải, phun lại cuồng phong khi cần, và huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ trong Vô Danh Chuyển Luân trận. Dẫu uy mãnh vô song, nó lại run rẩy sợ hãi mỗi khi bị người khác nhìn chằm chằm, bộc lộ bản tính cổ quái vừa dữ tợn vừa ngờ nghệch."},{"id":"tu-dai-chien-tuong","name":"Tứ đại chiến tướng","gioiTinh":"nam","theLuc":[{"ten":"Viễn cổ tiên vực","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Bốn lão già cầm đầu nhóm hơn trăm tiên nhân từ viễn cổ tiên vực, xuất hiện tại Triệu Hà tinh vực dùng hồ lô xanh biếc cổ xưa truy tìm mục tiêu.","vaiTro":"Bốn chiến tướng cấp cao của viễn cổ tiên vực","tinhCach":"Uy nghiêm; có tổ chức, hành động bài bản","tabs":{"diem":[{"text":"Bốn lão già dẫn đầu hơn trăm tiên nhân viễn cổ tiên vực, ngưng tụ thần thức biến ảo ra hồ lô khổng lồ xanh biếc dẫn đường truy tìm mục tiêu.","chuong":"@c1631"}],"kinhLich":[{"mucCt":"vua","text":"Bốn lão già cầm đầu hơn trăm tiên nhân lao đi trong tinh không Triệu Hà tinh vực. Ngưng tụ thần thức biến ảo ra hồ lô khổng lồ xanh biếc cổ xưa trên đỉnh đầu, miệng hồ lô có thanh khí bị hút về phương xa, mỗi khoảng dừng vái hồ lô và dùng thần niệm giao tiếp.","anchor":"Bốn lão già này không ngờ chính là tứ đại chiến tướng đến từ viễn cổ tiên vực","bridge":true,"khoang":"@c1631"}],"tuViMoc":[],"nhanMach":[{"ten":"Chiến lão quỷ","tag":"khac","quanHe":"Chiến lão quỷ đi theo phía sau nhóm tiên nhân nhưng hai bên lờ nhau"}],"tuiDo":{"phapBao":[{"ten":"Hồ lô xanh biếc cổ xưa","loai":"pháp bảo dẫn lộ","trangThai":"dang-co","moTa":"Ngưng tụ thần thức mà biến ảo ra, miệng hồ lô có thanh khí hút về phương xa, dùng thần niệm giao tiếp để dẫn đường","nguon":"@c1631"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1631"]},{"id":"thanh-long","name":"Thanh Long","gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"vua","text":"Đi đầu nhóm cầu vồng, kinh hãi khi thấy U Minh thú mà thần thức không phát hiện nổi. Chặn đường Vương Lâm, mắt lộ vẻ tham lam nhìn U Minh thú, đòi biết nguồn gốc hoặc cho mượn, uy hiếp sẽ chấm dứt hợp tác và nhắc cung Lý Quảng còn ít mũi tên.","anchor":"Thanh Long chiến tướng nhìn chằm chằm vào u Minh thú, đôi mắt lộ vẻ tham lam","bridge":true,"khoang":"@c1632"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được nhắc là một trong tứ đại chiến tướng bị phong ấn tại Viễn cổ Tinh Vực","chuong":"@c1458"},{"text":"Dung hợp hư ảnh Thanh Long đánh lén Vương Lâm, bị Cổ Tộc Bất Diệt chỉ bức lùi","chuong":"@c1549"},{"text":"Phân tích điểm yếu cung pháp Lý Quảng và tiết lộ cơ chế phòng thủ trăm năm","chuong":"@c1550"},{"text":"Từng bị lão tổ Chu Tước trẻ tuổi đoạt thuật đại thần thông","chuong":"@c1311"},{"text":"Đi đầu nhóm cầu vồng, kinh hãi khi thần thức không phát hiện nổi U Minh thú; chặn đường Vương Lâm","chuong":"@c1632"}]},"nguon":["@c1632"],"vaiTro":"Tứ đại chiến tướng Viễn cổ Tinh Vực — danh vị Thanh Long trong Tứ Thánh","tinhCach":"hành sự quỷ quyệt, thiên về đánh lén; phân tích chiến cục lạnh lùng, thấu đáo; thận trọng trước hiểm nguy chưa lường được","blurb":"Thanh Long là một trong Tứ Thánh, gắn liền với Thanh Long Thánh Tông, đồng thời thuộc hàng tứ đại chiến tướng từng bị phong ấn tại Viễn cổ Tinh Vực. Sau khi thoát phong ấn, Thanh Long dung hợp hư ảnh Thanh Long đánh lén Vương Lâm nhưng bị Cổ Tộc Bất Diệt chỉ bức lùi, rồi thể hiện kiến thức sâu rộng khi phân tích điểm yếu cung pháp Lý Quảng cùng cơ chế phòng thủ trăm năm. Trong mạch thuật truyền thừa, Thanh Long từng bị lão tổ Chu Tước trẻ tuổi đoạt đại thần thông, và về sau dẫn đầu nhóm cầu vồng truy kích Vương Lâm nhưng kinh hãi khi thần thức không thể phát hiện U Minh thú."},{"id":"bach-ho","name":"Bạch Hổ","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1632","importance":"bridge","mucCt":"vua","text":"Đứng bên phải Vương Lâm phong tỏa, tâm thần chấn động khi thấy U Minh thú thoát khỏi thần thức, hỏi Vương Lâm con thú từ đâu có được.","anchor":"Con thú này không biết đạo hữu từ đâu mà có được?"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được nhắc trong hệ thống Tứ Thánh khi Vương Lâm suy đoán nguồn gốc mảnh vỡ thanh long","chuong":"@c0923"},{"text":"Các bí thuật của Bạch Hổ bị Chu Tước tộc đoạt, được nhắc cùng Thanh Long và Huyền Vũ","chuong":"@c1311"},{"text":"Bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực cùng ba chiến tướng khác","chuong":"@c1458"},{"text":"Chất vấn Vương Lâm về nguồn gốc cung Lý Quảng, bị cự tuyệt trả lời thì nghệt mặt không nói thêm","chuong":"@c1550"},{"text":"Đứng bên phải Vương Lâm phong tỏa, tâm thần chấn động khi chứng kiến U Minh thú thoát khỏi thần thức","chuong":"@c1632"}]},"nguon":["@c1632"],"vaiTro":"Một trong Tứ Thánh Tông — chiến tướng bị phong ấn tại Viễn cổ Tinh Vực","tinhCach":"tò mò, trực tính khi chất vấn; dễ dàng chấp nhận bị cự tuyệt; dễ bị chấn động trước sự kiện bất ngờ","blurb":"Bạch Hổ là một trong bốn danh vị thuộc Tứ Thánh Tông, được nhắc cùng Thanh Long, Chu Tước và Huyền Vũ. Hắn từng bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực cùng ba chiến tướng khác, sau khi thoát phong ấn đã đi theo Vương Lâm, từng chất vấn về nguồn gốc cung Lý Quảng và chứng kiến U Minh thú thoát khỏi thần thức của Vương Lâm."},{"id":"chu-tuoc","name":"Chu Tước","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1632","importance":"bridge","mucCt":"gon","text":"Do dự một chút rồi chọn phong kín đường lui của Vương Lâm.","anchor":"Chu Tước chiến tướng do dự một chút, cuối cùng lựa chọn phong kín đường lui của Vương Lâm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1632"]}]};
